{
  "name": "زاد المسلم - رفيق رمضان",
  "description": "تطبيق متكامل لمتابعة العبادات، الأذكار، ختم القرآن، وأعمال الخير خلال شهر رمضان المبارك مع نظام نقاط تحفيزي وتصميم إسلامي فاخر."
}

export interface DailyLog {
  date: string; // YYYY-MM-DD
  prayers: string[]; // List of completed prayer IDs
  azkar: string[]; // List of completed azkar IDs
  goodDeeds: string[]; // List of completed deed IDs
  mujahada: string[]; // List of COMMITTED sins (negatives)
  quranStart: number;
  quranEnd: number;
  notes: string[];
}

export interface Quote {
  text: string;
  source: string;
}

export interface TaskItem {
  id: string;
  label: string;
  verse?: string;
  hadith?: string;
}

export enum SectionType {
  PRAYER = 'PRAYER',
  AZKAR = 'AZKAR',
  QURAN = 'QURAN',
  GOOD_DEEDS = 'GOOD_DEEDS',
  MUJAHADA = 'MUJAHADA'
}

import { DailyLog } from '../types';

const STORAGE_KEY = 'zad_almuslim_logs';

export const getLogs = (): Record<string, DailyLog> => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : {};
};

export const saveLog = (log: DailyLog) => {
  const logs = getLogs();
  logs[log.date] = log;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(logs));
};

export const getLogForDate = (date: string): DailyLog => {
  const logs = getLogs();
  if (logs[date]) return logs[date];

  return {
    date,
    prayers: [],
    azkar: [],
    goodDeeds: [],
    mujahada: [],
    quranStart: 0,
    quranEnd: 0,
    notes: []
  };
};

export const formatDate = (date: Date): string => {
  return date.toISOString().split('T')[0];
};

import React, { useState } from 'react';

