        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-[#222] flex items-center justify-center text-[#d4af37]">
            <i className={`fas ${icon} text-lg`}></i>
          </div>
          <h3 className="text-lg font-bold text-gray-100">{title}</h3>
        </div>
        {info && (
          <button 
            onClick={() => setShowInfo(!showInfo)}
            className={`text-sm transition-colors ${showInfo ? 'text-yellow-500' : 'text-gray-500 hover:text-yellow-500'}`}
            title="معلومة إيمانية"
