import React, { useState, useEffect, useMemo } from 'react';
import { 
  PRAYER_TASKS, 
  AZKAR_TASKS, 
  GOOD_DEED_TASKS, 
  MUJAHADA_TASKS, 
  MOTIVATIONAL_QUOTES 
} from '../constants';
import { getLogForDate, saveLog, formatDate } from '../services/storageService';
import SectionCard from '../components/SectionCard';
import { DailyLog } from '../types';

const Dashboard: React.FC = () => {
  const [currentDate] = useState(formatDate(new Date()));
  const [log, setLog] = useState<DailyLog>(getLogForDate(currentDate));
  const [newNote, setNewNote] = useState("");

  const quote = useMemo(() => {
    const day = new Date().getDate();
    return MOTIVATIONAL_QUOTES[day % MOTIVATIONAL_QUOTES.length];
  }, []);

  useEffect(() => {
    saveLog(log);
  }, [log]);

  const toggleTask = (section: keyof DailyLog, id: string) => {
    setLog(prev => {
      const currentList = prev[section] as string[];
      const newList = currentList.includes(id) 
        ? currentList.filter(item => item !== id)
        : [...currentList, id];
      return { ...prev, [section]: newList };
    });
  };

  const handleQuranChange = (field: 'quranStart' | 'quranEnd', value: string) => {
    const num = Math.min(604, Math.max(0, parseInt(value) || 0));
    setLog(prev => ({ ...prev, [field]: num }));
  };

  const addNote = () => {
    if (!newNote.trim()) return;
    setLog(prev => ({ ...prev, notes: [...prev.notes, newNote] }));
    setNewNote("");
  };

  const deleteNote = (index: number) => {
    setLog(prev => ({ ...prev, notes: prev.notes.filter((_, i) => i !== index) }));
  };

  const score = useMemo(() => {
    const positiveCount = log.prayers.length + log.azkar.length + log.goodDeeds.length;
    const negativeCount = log.mujahada.length;
    // Every Fardh prayer missed? Let's say we have 5 Fardh.
    // Logic: (Checked Positives * 10) - (Checked Negatives * 10)
    return (positiveCount * 10) - (negativeCount * 10);
  }, [log]);

  const quranProgress = useMemo(() => {
    const pagesRead = Math.max(0, log.quranEnd - log.quranStart);
    const totalRemaining = 604 - log.quranEnd;
    const percentage = (log.quranEnd / 604) * 100;
    return { pagesRead, totalRemaining, percentage };
  }, [log.quranStart, log.quranEnd]);

  return (
    <div className="space-y-6 pb-12 animate-fade-in">
      {/* Motivational Quote */}
      <div className="bg-[#1a1a1a] border border-yellow-900/30 p-6 rounded-2xl relative overflow-hidden group">
        <div className="absolute top-0 right-0 w-32 h-32 bg-yellow-500/5 rounded-full -mr-16 -mt-16 blur-3xl"></div>
        <div className="relative z-10 text-center">
          <i className="fas fa-quote-right text-[#d4af37] text-2xl mb-4 opacity-50"></i>
          <p className="text-xl md:text-2xl font-bold text-gray-100 leading-snug">
            {quote.text}
          </p>
          <div className="mt-4 flex items-center justify-center gap-2">
            <span className="h-[1px] w-8 bg-gray-700"></span>
            <span className="text-sm text-yellow-600 font-medium">{quote.source}</span>
            <span className="h-[1px] w-8 bg-gray-700"></span>
          </div>
        </div>
      </div>

      {/* Daily Score Summary */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <div className="bg-[#151515] p-4 rounded-xl border border-gray-800 flex flex-col items-center justify-center">
          <span className="text-gray-500 text-xs mb-1 uppercase font-bold tracking-wider">نقاط اليوم</span>
          <span className="text-3xl font-black text-[#d4af37]">{score}</span>
        </div>
        <div className="bg-[#151515] p-4 rounded-xl border border-gray-800 flex flex-col items-center justify-center">
          <span className="text-gray-500 text-xs mb-1 uppercase font-bold tracking-wider">ختمة القرآن</span>
          <span className="text-xl font-bold text-gray-200">{Math.round(quranProgress.percentage)}%</span>
        </div>
        <div className="bg-[#151515] p-4 rounded-xl border border-gray-800 flex flex-col items-center justify-center">
          <span className="text-gray-500 text-xs mb-1 uppercase font-bold tracking-wider">عبادات منجزة</span>
          <span className="text-xl font-bold text-gray-200">{log.prayers.length + log.azkar.length}</span>
        </div>
        <div className="bg-[#151515] p-4 rounded-xl border border-gray-800 flex flex-col items-center justify-center">
          <span className="text-gray-500 text-xs mb-1 uppercase font-bold tracking-wider">أعمال خير</span>
          <span className="text-xl font-bold text-gray-200">{log.goodDeeds.length}</span>
        </div>
      </div>

      {/* Sections Grid */}
      <div className="grid md:grid-cols-2 gap-6">

        {/* Prayers */}
        <SectionCard title="قسم الصلاة" icon="fa-mosque">
          <div className="grid grid-cols-2 gap-3">
            {PRAYER_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-3 rounded-lg bg-[#1a1a1a] cursor-pointer hover:bg-[#222] transition-colors group">
                <input 
                  type="checkbox" 
                  checked={log.prayers.includes(task.id)}
                  onChange={() => toggleTask('prayers', task.id)}
                  className="w-5 h-5 rounded border-gray-700 text-[#d4af37] bg-gray-900 focus:ring-[#d4af37]"
                />
                <span className={`text-sm font-medium ${log.prayers.includes(task.id) ? 'text-yellow-500 line-through' : 'text-gray-300'}`}>
                  {task.label}
                </span>
              </label>
            ))}
          </div>
        </SectionCard>

        {/* Azkar */}
        <SectionCard title="قسم الأذكار" icon="fa-hands-praying">
          <div className="grid grid-cols-2 gap-3">
            {AZKAR_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-3 rounded-lg bg-[#1a1a1a] cursor-pointer hover:bg-[#222] transition-colors">
                <input 
                  type="checkbox" 
                  checked={log.azkar.includes(task.id)}
                  onChange={() => toggleTask('azkar', task.id)}
                  className="w-5 h-5 rounded border-gray-700 text-[#d4af37] bg-gray-900 focus:ring-[#d4af37]"
                />
                <span className={`text-sm font-medium ${log.azkar.includes(task.id) ? 'text-yellow-500 line-through' : 'text-gray-300'}`}>
                  {task.label}
                </span>
              </label>
            ))}
          </div>
        </SectionCard>

        {/* Quran */}
        <SectionCard title="ختمة القرآن" icon="fa-book-quran">
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-xs text-gray-500 block">من صفحة</label>
                <input 
                  type="number" 
                  value={log.quranStart || ""}
                  onChange={(e) => handleQuranChange('quranStart', e.target.value)}
                  className="w-full bg-[#1a1a1a] border border-gray-800 rounded-lg p-3 text-center text-yellow-500 font-bold focus:outline-none focus:border-yellow-600"
                  placeholder="0"
                />
              </div>
              <div className="space-y-1">
                <label className="text-xs text-gray-500 block">إلى صفحة</label>
                <input 
                  type="number" 
                  value={log.quranEnd || ""}
                  onChange={(e) => handleQuranChange('quranEnd', e.target.value)}
                  className="w-full bg-[#1a1a1a] border border-gray-800 rounded-lg p-3 text-center text-yellow-500 font-bold focus:outline-none focus:border-yellow-600"
                  placeholder="0"
                />
              </div>
            </div>

            <div className="bg-[#1a1a1a] p-4 rounded-xl border border-gray-800 flex justify-between items-center">
              <div className="text-center flex-1 border-l border-gray-800">
                <p className="text-xl font-black text-gray-200">{quranProgress.pagesRead}</p>
                <p className="text-xs text-gray-500">صفحات اليوم</p>
              </div>
              <div className="text-center flex-1">
                <p className="text-xl font-black text-yellow-600">{quranProgress.totalRemaining}</p>
                <p className="text-xs text-gray-500">متبقي للختمة</p>
              </div>
            </div>

            <div className="space-y-2">
              <div className="flex justify-between text-xs text-gray-500">
                <span>التقدم الإجمالي</span>
                <span>{Math.round(quranProgress.percentage)}%</span>
              </div>
              <div className="w-full h-3 bg-gray-900 rounded-full overflow-hidden border border-gray-800">
                <div 
                  className="h-full bg-gradient-to-r from-yellow-700 to-yellow-400 rounded-full transition-all duration-500"
                  style={{ width: `${quranProgress.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>
        </SectionCard>

        {/* Mujahada */}
        <SectionCard title="مجاهدة النفس" icon="fa-shield-halved">
          <p className="text-xs text-red-500/80 mb-3 text-center bg-red-900/10 py-1 rounded">اختر ما وقعت فيه اليوم (يخصم 10 نقاط)</p>
          <div className="space-y-2">
            {MUJAHADA_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-3 rounded-lg bg-[#1a1a1a] cursor-pointer hover:bg-red-900/10 border border-transparent hover:border-red-900/30 transition-all">
                <input 
                  type="checkbox" 
                  checked={log.mujahada.includes(task.id)}
                  onChange={() => toggleTask('mujahada', task.id)}
                  className="w-5 h-5 rounded border-gray-700 text-red-600 bg-gray-900 focus:ring-red-600"
                />
                <span className={`text-sm font-medium ${log.mujahada.includes(task.id) ? 'text-red-500 font-bold' : 'text-gray-300'}`}>
                  {task.label}
                </span>
              </label>
            ))}
          </div>
        </SectionCard>

        {/* Good Deeds */}
        <SectionCard title="أعمال الخير" icon="fa-heart">
          <div className="space-y-3">
             <div className="grid grid-cols-2 gap-2">
              {GOOD_DEED_TASKS.map(task => (
                <label key={task.id} className="flex items-center gap-2 p-2 rounded-lg bg-[#1a1a1a] cursor-pointer hover:bg-[#222]">
                  <input 
                    type="checkbox" 
                    checked={log.goodDeeds.includes(task.id)}
                    onChange={() => toggleTask('goodDeeds', task.id)}
                    className="w-4 h-4 rounded border-gray-700 text-emerald-500 bg-gray-900"
                  />
                  <span className="text-xs font-medium text-gray-300">
                    {task.label}
                  </span>
                </label>
              ))}
            </div>

            <div className="pt-2 border-t border-gray-800">
              <div className="flex gap-2 mb-2">
                <input 
                  type="text" 
                  value={newNote}
                  onChange={(e) => setNewNote(e.target.value)}
                  placeholder="أضف عمل خير آخر..."
                  className="flex-grow bg-[#222] border border-gray-800 rounded-lg px-3 py-2 text-sm focus:outline-none focus:border-yellow-600"
                />
                <button 
                  onClick={addNote}
                  className="bg-yellow-600 hover:bg-yellow-700 text-white px-3 py-2 rounded-lg transition-colors"
                >
                  <i className="fas fa-plus"></i>
                </button>
              </div>
              <ul className="space-y-1">
                {log.notes.map((note, idx) => (
                  <li key={idx} className="flex items-center justify-between text-xs bg-[#1a1a1a] p-2 rounded border border-gray-800">
                    <span className="text-gray-400">{note}</span>
                    <button onClick={() => deleteNote(idx)} className="text-red-800 hover:text-red-500">
                      <i className="fas fa-trash-can"></i>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </SectionCard>

      </div>
    </div>
  );
};

export default Dashboard;

import React, { useMemo } from 'react';
import { getLogs } from '../services/storageService';

const History: React.FC = () => {
  const logs = useMemo(() => getLogs(), []);
  const sortedDates = Object.keys(logs).sort((a, b) => b.localeCompare(a));

  const calculateScore = (log: any) => {
    const positiveCount = (log.prayers?.length || 0) + (log.azkar?.length || 0) + (log.goodDeeds?.length || 0);
    const negativeCount = log.mujahada?.length || 0;
    return (positiveCount * 10) - (negativeCount * 10);
  };

  const totalPoints = useMemo(() => {
    return Object.values(logs).reduce((acc, log) => acc + calculateScore(log), 0);
  }, [logs]);

  return (
    <div className="animate-fade-in space-y-6 pb-12">
      <div className="bg-[#1a1a1a] border border-gray-800 rounded-2xl p-6 text-center">
        <h2 className="text-gray-400 text-sm mb-2 font-bold tracking-widest uppercase">رصيدك الكلي من الحسنات</h2>
        <div className="text-5xl font-black gold-gradient">{totalPoints}</div>
        <div className="mt-4 flex items-center justify-center gap-4 text-xs">
          <div className="flex items-center gap-1 text-gray-500">
            <span className="w-2 h-2 rounded-full bg-emerald-500"></span>
            <span>كل عمل +10</span>
          </div>
          <div className="flex items-center gap-1 text-gray-500">
            <span className="w-2 h-2 rounded-full bg-red-500"></span>
            <span>كل ذنب -10</span>
          </div>
        </div>
      </div>

      <div className="bg-[#151515] border border-gray-800 rounded-2xl overflow-hidden">
        <div className="p-4 border-b border-gray-800 bg-[#1a1a1a] flex items-center justify-between">
          <h3 className="font-bold text-gray-100">سجل المتابعة اليومي</h3>
          <span className="text-xs text-gray-500">{sortedDates.length} أيام مسجلة</span>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-right">
            <thead>
              <tr className="bg-[#222] text-xs text-gray-500 uppercase">
                <th className="px-4 py-3 font-bold">التاريخ</th>
                <th className="px-4 py-3 font-bold">الصلوات</th>
                <th className="px-4 py-3 font-bold">الأذكار</th>
                <th className="px-4 py-3 font-bold">القرآن</th>
                <th className="px-4 py-3 font-bold">المجموع</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-800">
              {sortedDates.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-4 py-12 text-center text-gray-500">لا توجد بيانات مسجلة بعد</td>
                </tr>
              ) : (
                sortedDates.map(date => {
                  const log = logs[date];
                  const score = calculateScore(log);
                  return (
                    <tr key={date} className="hover:bg-[#1a1a1a] transition-colors">
                      <td className="px-4 py-4 text-sm font-bold text-gray-300">{date}</td>
                      <td className="px-4 py-4 text-sm text-gray-400">{log.prayers.length}/10</td>
                      <td className="px-4 py-4 text-sm text-gray-400">{log.azkar.length}/6</td>
                      <td className="px-4 py-4 text-sm text-gray-400">{log.quranEnd - log.quranStart} ص</td>
                      <td className="px-4 py-4">
                        <span className={`px-2 py-1 rounded text-xs font-bold ${score >= 0 ? 'bg-emerald-900/20 text-emerald-500' : 'bg-red-900/20 text-red-500'}`}>
                          {score > 0 ? `+${score}` : score}
                        </span>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="p-6 text-center text-gray-500 text-sm">
        <p>ملاحظة: البيانات تُحفظ في متصفحك فقط (أوفلاين).</p>
      </div>
    </div>
  );
};

export default History;

