const History: React.FC = () => {
  const logs = useMemo(() => getLogs(), []);
  const sortedDates = Object.keys(logs).sort((a, b) => b.localeCompare(a));

  // Fix: Explicitly type the parameter as DailyLog
  const calculateScore = (log: DailyLog) => {
    const positiveCount = (log.prayers?.length || 0) + (log.azkar?.length || 0) + (log.goodDeeds?.length || 0);
    const negativeCount = log.mujahada?.length || 0;
    return (positiveCount * 10) - (negativeCount * 10);
  };

  const totalPoints = useMemo(() => {
    // Fix: Explicitly type 'log' as DailyLog in the reduce callback to resolve the 'unknown' type error on line 19/20
    return Object.values(logs).reduce((acc: number, log: DailyLog) => acc + calculateScore(log), 0);
  }, [logs]);

  return (
    <div className="animate-fade-in space-y-6 pb-12">
      <div className="bg-[#1a1a1a] border border-gray-800 rounded-2xl p-6 text-center">
