import { DailyLog } from '../types';

const STORAGE_KEY = 'zad_almuslim_logs';

export const getLogs = (): Record<string, DailyLog> => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : {};
};

export const saveLog = (log: DailyLog) => {
  const logs = getLogs();
  logs[log.date] = log;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(logs));
};

export const getLogForDate = (date: string): DailyLog => {
  const logs = getLogs();
  if (logs[date]) {
    const log = logs[date];
    // Migration for older logs
    if (!log.mujahadaNotes) log.mujahadaNotes = [];
    return log;
  }

  return {
    date,
    prayers: [],
    azkar: [],
    goodDeeds: [],
    mujahada: [],
    quranStart: 0,
    quranEnd: 0,
    notes: [],
    mujahadaNotes: []
  };
};

export const formatDate = (date: Date): string => {
  return date.toISOString().split('T')[0];
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  PRAYER_TASKS, 
  AZKAR_TASKS, 
  GOOD_DEED_TASKS, 
  MUJAHADA_TASKS, 
  MOTIVATIONAL_QUOTES,
  SECTION_INFO
} from '../constants';
