        <div className="absolute top-0 right-0 w-48 h-48 bg-yellow-500/5 rounded-full -mr-24 -mt-24 blur-3xl"></div>
        <div className="relative z-10 text-center">
          <i className="fas fa-hands-praying text-[#d4af37] text-3xl mb-4 opacity-40"></i>
          <p className="text-2xl md:text-3xl font-bold text-gray-100 leading-snug quran-font">
            "{quote.text}"
          </p>
          <div className="mt-6 flex items-center justify-center gap-3">
            <span className="h-[1px] w-12 bg-gray-800"></span>
            <span className="text-sm text-yellow-600 font-bold uppercase tracking-wider">{quote.source}</span>
            <span className="h-[1px] w-12 bg-gray-800"></span>
          </div>
        </div>
      </div>

      {/* Daily Score Summary */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <div className="bg-[#151515] p-5 rounded-2xl border border-gray-800 flex flex-col items-center justify-center shadow-inner">
          <span className="text-gray-500 text-xs mb-1 font-bold tracking-widest uppercase">نقاط اليوم</span>
          <span className="text-4xl font-black text-[#d4af37]">{score}</span>
        </div>
        <div className="bg-[#151515] p-5 rounded-2xl border border-gray-800 flex flex-col items-center justify-center shadow-inner">
          <span className="text-gray-500 text-xs mb-1 font-bold tracking-widest uppercase">ختمة القرآن</span>
          <span className="text-2xl font-bold text-gray-200">{Math.round(quranProgress.percentage)}%</span>
        </div>
        <div className="bg-[#151515] p-5 rounded-2xl border border-gray-800 flex flex-col items-center justify-center shadow-inner">
          <span className="text-gray-500 text-xs mb-1 font-bold tracking-widest uppercase">العبادات</span>
          <span className="text-2xl font-bold text-gray-200">{log.prayers.length + log.azkar.length}</span>
        </div>
        <div className="bg-[#151515] p-5 rounded-2xl border border-gray-800 flex flex-col items-center justify-center shadow-inner">
          <span className="text-gray-500 text-xs mb-1 font-bold tracking-widest uppercase">أعمال خير</span>
          <span className="text-2xl font-bold text-gray-200">{log.goodDeeds.length + log.notes.length}</span>
        </div>
