                    <span className={`text-sm font-bold ${log.goodDeeds.includes(task.id) ? 'text-emerald-500' : 'text-gray-300'}`}>
                      {task.label}
                    </span>
                    <span className="text-[10px] text-gray-500 leading-tight mt-0.5">{task.description}</span>
                  </div>
                </label>
              ))}
            </div>

            <div className="pt-3 border-t border-gray-800">
              <div className="flex gap-2 mb-3">
                <input 
                  type="text" 
                  value={newNote}
                  onChange={(e) => setNewNote(e.target.value)}
                  placeholder="أضف عمل خير آخر..."
                  className="flex-grow bg-[#222] border border-gray-800 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-yellow-600 transition-colors"
                />
                <button 
                  onClick={addNote}
                  className="bg-yellow-600 hover:bg-yellow-700 text-white w-10 h-10 rounded-xl transition-all shadow-lg active:scale-95 flex items-center justify-center"
                >
                  <i className="fas fa-plus"></i>
                </button>
              </div>
              <ul className="space-y-2">
                {log.notes.map((note, idx) => (
                  <li key={idx} className="flex items-center justify-between text-xs bg-[#1a1a1a] p-3 rounded-xl border border-gray-800 animate-slide-in">
                    <span className="text-gray-300 font-medium">{note}</span>
                    <button onClick={() => deleteNote(idx)} className="text-gray-600 hover:text-red-500 transition-colors">
                      <i className="fas fa-trash-can"></i>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </SectionCard>

      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  PRAYER_TASKS, 
  AZKAR_TASKS, 
  GOOD_DEED_TASKS, 
  MUJAHADA_TASKS, 
  MOTIVATIONAL_QUOTES,
  SECTION_INFO
} from '../constants';
import { getLogForDate, saveLog, formatDate } from '../services/storageService';
import SectionCard from '../components/SectionCard';
import { DailyLog } from '../types';

const Dashboard: React.FC = () => {
  const [currentDate] = useState(formatDate(new Date()));
  const [log, setLog] = useState<DailyLog>(getLogForDate(currentDate));
  const [newNote, setNewNote] = useState("");
  const [newMujahadaNote, setNewMujahadaNote] = useState("");

  // Select quote and info based on day of month for daily rotation
  const dailyRotationIndex = useMemo(() => {
    const d = new Date();
    return d.getDate();
  }, []);

  const quote = useMemo(() => {
    return MOTIVATIONAL_QUOTES[dailyRotationIndex % MOTIVATIONAL_QUOTES.length];
  }, [dailyRotationIndex]);

  // Helper to get daily info for a section
  const getDailyInfo = (section: keyof typeof SECTION_INFO) => {
    const list = SECTION_INFO[section];
    return [list[dailyRotationIndex % list.length]];
  };

  useEffect(() => {
    saveLog(log);
  }, [log]);

  const toggleTask = (section: keyof DailyLog, id: string) => {
    setLog(prev => {
      const currentList = prev[section] as string[];
      const newList = currentList.includes(id) 
        ? currentList.filter(item => item !== id)
        : [...currentList, id];
      return { ...prev, [section]: newList };
    });
  };

  const handleQuranChange = (field: 'quranStart' | 'quranEnd', value: string) => {
    const num = Math.min(604, Math.max(0, parseInt(value) || 0));
    setLog(prev => ({ ...prev, [field]: num }));
  };

  const addNote = () => {
    if (!newNote.trim()) return;
    setLog(prev => ({ ...prev, notes: [...prev.notes, newNote] }));
    setNewNote("");
  };

  const addMujahadaNote = () => {
    if (!newMujahadaNote.trim()) return;
    setLog(prev => ({ ...prev, mujahadaNotes: [...prev.mujahadaNotes, newMujahadaNote] }));
    setNewMujahadaNote("");
  };

  const deleteNote = (index: number) => {
    setLog(prev => ({ ...prev, notes: prev.notes.filter((_, i) => i !== index) }));
  };

  const deleteMujahadaNote = (index: number) => {
    setLog(prev => ({ ...prev, mujahadaNotes: prev.mujahadaNotes.filter((_, i) => i !== index) }));
  };

  const score = useMemo(() => {
    const positiveCount = log.prayers.length + log.azkar.length + log.goodDeeds.length + log.notes.length;
    const negativeCount = log.mujahada.length + log.mujahadaNotes.length;
    return (positiveCount * 10) - (negativeCount * 10);
  }, [log]);

  const quranProgress = useMemo(() => {
    const pagesRead = Math.max(0, log.quranEnd - log.quranStart);
    const totalRemaining = 604 - log.quranEnd;
    const percentage = (log.quranEnd / 604) * 100;
    return { pagesRead, totalRemaining, percentage };
  }, [log.quranStart, log.quranEnd]);

  return (
    <div className="space-y-6 pb-12 animate-fade-in">
      {/* Motivational Quote */}
      <div className="bg-[#1a1a1a] border border-yellow-900/30 p-8 rounded-3xl relative overflow-hidden group shadow-2xl">
        <div className="absolute top-0 right-0 w-48 h-48 bg-yellow-500/5 rounded-full -mr-24 -mt-24 blur-3xl"></div>
        <div className="relative z-10 text-center">
          <i className="fas fa-hands-praying text-[#d4af37] text-3xl mb-4 opacity-40"></i>
          <p className="text-2xl md:text-3xl font-bold text-gray-100 leading-snug quran-font">
            "{quote.text}"
          </p>
          <div className="mt-6 flex items-center justify-center gap-3">
            <span className="h-[1px] w-12 bg-gray-800"></span>
            <span className="text-sm text-yellow-600 font-bold uppercase tracking-wider">{quote.source}</span>
            <span className="h-[1px] w-12 bg-gray-800"></span>
          </div>
        </div>
      </div>

      {/* Daily Score Summary */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <div className="bg-[#151515] p-5 rounded-2xl border border-gray-800 flex flex-col items-center justify-center shadow-inner">
          <span className="text-gray-500 text-xs mb-1 font-bold tracking-widest uppercase">نقاط اليوم</span>
          <span className="text-4xl font-black text-[#d4af37]">{score}</span>
        </div>
        <div className="bg-[#151515] p-5 rounded-2xl border border-gray-800 flex flex-col items-center justify-center shadow-inner">
          <span className="text-gray-500 text-xs mb-1 font-bold tracking-widest uppercase">ختمة القرآن</span>
          <span className="text-2xl font-bold text-gray-200">{Math.round(quranProgress.percentage)}%</span>
        </div>
        <div className="bg-[#151515] p-5 rounded-2xl border border-gray-800 flex flex-col items-center justify-center shadow-inner">
          <span className="text-gray-500 text-xs mb-1 font-bold tracking-widest uppercase">العبادات</span>
          <span className="text-2xl font-bold text-gray-200">{log.prayers.length + log.azkar.length}</span>
        </div>
        <div className="bg-[#151515] p-5 rounded-2xl border border-gray-800 flex flex-col items-center justify-center shadow-inner">
          <span className="text-gray-500 text-xs mb-1 font-bold tracking-widest uppercase">أعمال خير</span>
          <span className="text-2xl font-bold text-gray-200">{log.goodDeeds.length + log.notes.length}</span>
        </div>
      </div>

      {/* Sections Grid */}
      <div className="grid md:grid-cols-2 gap-6">

        {/* Prayers */}
        <SectionCard title="قسم الصلاة" icon="fa-mosque" infoItems={getDailyInfo('PRAYER')}>
          <div className="grid grid-cols-2 gap-3">
            {PRAYER_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-3 rounded-xl bg-[#1a1a1a] cursor-pointer hover:bg-[#222] transition-all border border-transparent hover:border-gray-800">
                <input 
                  type="checkbox" 
                  checked={log.prayers.includes(task.id)}
                  onChange={() => toggleTask('prayers', task.id)}
                  className="w-5 h-5 rounded border-gray-700 text-[#d4af37] bg-gray-900 focus:ring-[#d4af37]"
                />
                <span className={`text-sm font-medium ${log.prayers.includes(task.id) ? 'text-yellow-500 line-through' : 'text-gray-300'}`}>
                  {task.label}
                </span>
              </label>
            ))}
          </div>
        </SectionCard>

        {/* Azkar */}
        <SectionCard title="قسم الأذكار" icon="fa-hands-praying" infoItems={getDailyInfo('AZKAR')}>
          <div className="grid grid-cols-2 gap-3">
            {AZKAR_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-3 rounded-xl bg-[#1a1a1a] cursor-pointer hover:bg-[#222] transition-all border border-transparent hover:border-gray-800">
                <input 
                  type="checkbox" 
                  checked={log.azkar.includes(task.id)}
                  onChange={() => toggleTask('azkar', task.id)}
                  className="w-5 h-5 rounded border-gray-700 text-[#d4af37] bg-gray-900 focus:ring-[#d4af37]"
                />
                <span className={`text-sm font-medium ${log.azkar.includes(task.id) ? 'text-yellow-500 line-through' : 'text-gray-300'}`}>
                  {task.label}
                </span>
              </label>
            ))}
          </div>
        </SectionCard>

        {/* Quran */}
        <SectionCard title="ختمة القرآن" icon="fa-book-quran" infoItems={getDailyInfo('QURAN')}>
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-xs text-gray-500 block font-bold">من صفحة</label>
                <input 
                  type="number" 
                  value={log.quranStart || ""}
                  onChange={(e) => handleQuranChange('quranStart', e.target.value)}
                  className="w-full bg-[#1a1a1a] border border-gray-800 rounded-xl p-3 text-center text-yellow-500 font-bold focus:outline-none focus:border-yellow-600 transition-colors"
                  placeholder="0"
                />
              </div>
              <div className="space-y-1">
                <label className="text-xs text-gray-500 block font-bold">إلى صفحة</label>
                <input 
                  type="number" 
                  value={log.quranEnd || ""}
                  onChange={(e) => handleQuranChange('quranEnd', e.target.value)}
                  className="w-full bg-[#1a1a1a] border border-gray-800 rounded-xl p-3 text-center text-yellow-500 font-bold focus:outline-none focus:border-yellow-600 transition-colors"
                  placeholder="0"
                />
              </div>
            </div>

            <div className="bg-[#1a1a1a] p-4 rounded-2xl border border-gray-800 flex justify-between items-center">
              <div className="text-center flex-1 border-l border-gray-800">
                <p className="text-2xl font-black text-gray-200">{quranProgress.pagesRead}</p>
                <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">صفحات اليوم</p>
              </div>
              <div className="text-center flex-1">
                <p className="text-2xl font-black text-yellow-600">{quranProgress.totalRemaining}</p>
                <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">متبقي للختمة</p>
              </div>
            </div>

            <div className="space-y-2">
              <div className="flex justify-between text-[10px] text-gray-500 font-bold uppercase">
                <span>التقدم الإجمالي</span>
                <span>{Math.round(quranProgress.percentage)}%</span>
              </div>
              <div className="w-full h-3 bg-gray-900 rounded-full overflow-hidden border border-gray-800">
                <div 
                  className="h-full bg-gradient-to-r from-yellow-700 to-yellow-400 rounded-full transition-all duration-700 ease-out"
                  style={{ width: `${quranProgress.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>
        </SectionCard>

        {/* Mujahada */}
        <SectionCard title="مجاهدة النفس" icon="fa-shield-halved" infoItems={getDailyInfo('MUJAHADA')} defaultOpen={false}>
          <p className="text-[10px] text-red-500/80 mb-3 text-center bg-red-900/10 py-1.5 rounded-lg font-bold border border-red-900/20 uppercase tracking-widest">اختر ما وقعت فيه اليوم (يخصم 10 نقاط)</p>
          <div className="space-y-3 mb-4">
            {MUJAHADA_TASKS.map(task => (
              <label key={task.id} className="flex items-start gap-3 p-3 rounded-xl bg-[#1a1a1a] cursor-pointer hover:bg-red-900/5 border border-transparent hover:border-red-900/30 transition-all">
                <input 
                  type="checkbox" 
                  checked={log.mujahada.includes(task.id)}
                  onChange={() => toggleTask('mujahada', task.id)}
                  className="w-5 h-5 mt-0.5 rounded border-gray-700 text-red-600 bg-gray-900 focus:ring-red-600"
                />
                <div className="flex flex-col">
                  <span className={`text-sm font-bold ${log.mujahada.includes(task.id) ? 'text-red-500' : 'text-gray-300'}`}>
                    {task.label}
                  </span>
                  <span className="text-[10px] text-gray-500 leading-tight mt-0.5">{task.description}</span>
                </div>
              </label>
            ))}
          </div>

          <div className="pt-3 border-t border-gray-800">
              <div className="flex gap-2 mb-3">
                <input 
                  type="text" 
                  value={newMujahadaNote}
                  onChange={(e) => setNewMujahadaNote(e.target.value)}
                  placeholder="أضف زلة أخرى لم تُذكر..."
                  className="flex-grow bg-[#222] border border-gray-800 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-red-900 transition-colors"
                />
                <button 
                  onClick={addMujahadaNote}
                  className="bg-red-900/40 hover:bg-red-900/60 text-red-500 w-10 h-10 rounded-xl transition-all shadow-lg active:scale-95 flex items-center justify-center border border-red-900/50"
                >
                  <i className="fas fa-plus"></i>
                </button>
              </div>
              <ul className="space-y-2">
                {log.mujahadaNotes.map((note, idx) => (
                  <li key={idx} className="flex items-center justify-between text-xs bg-red-900/5 p-3 rounded-xl border border-red-900/20 animate-slide-in">
                    <span className="text-red-400 font-medium">{note}</span>
                    <button onClick={() => deleteMujahadaNote(idx)} className="text-gray-600 hover:text-red-500 transition-colors">
                      <i className="fas fa-trash-can"></i>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
        </SectionCard>

        {/* Good Deeds */}
        <SectionCard title="أعمال الخير" icon="fa-heart" infoItems={getDailyInfo('GOOD_DEEDS')} defaultOpen={false}>
          <div className="space-y-3">
             <div className="grid grid-cols-1 gap-2">
              {GOOD_DEED_TASKS.map(task => (
                <label key={task.id} className="flex items-start gap-3 p-3 rounded-xl bg-[#1a1a1a] cursor-pointer hover:bg-[#222] border border-transparent hover:border-gray-800 transition-all">
                  <input 
                    type="checkbox" 
                    checked={log.goodDeeds.includes(task.id)}
                    onChange={() => toggleTask('goodDeeds', task.id)}
                    className="w-5 h-5 mt-0.5 rounded border-gray-700 text-emerald-500 bg-gray-900"
                  />
                  <div className="flex flex-col">
                    <span className={`text-sm font-bold ${log.goodDeeds.includes(task.id) ? 'text-emerald-500' : 'text-gray-300'}`}>
                      {task.label}
                    </span>
                    <span className="text-[10px] text-gray-500 leading-tight mt-0.5">{task.description}</span>
                  </div>
                </label>
              ))}
            </div>

            <div className="pt-3 border-t border-gray-800">
              <div className="flex gap-2 mb-3">
                <input 
                  type="text" 
                  value={newNote}
                  onChange={(e) => setNewNote(e.target.value)}
                  placeholder="أضف عمل خير آخر..."
                  className="flex-grow bg-[#222] border border-gray-800 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:border-yellow-600 transition-colors"
                />
                <button 
                  onClick={addNote}
                  className="bg-yellow-600 hover:bg-yellow-700 text-white w-10 h-10 rounded-xl transition-all shadow-lg active:scale-95 flex items-center justify-center"
                >
                  <i className="fas fa-plus"></i>
                </button>
              </div>
              <ul className="space-y-2">
                {log.notes.map((note, idx) => (
                  <li key={idx} className="flex items-center justify-between text-xs bg-[#1a1a1a] p-3 rounded-xl border border-gray-800 animate-slide-in">
                    <span className="text-gray-300 font-medium">{note}</span>
                    <button onClick={() => deleteNote(idx)} className="text-gray-600 hover:text-red-500 transition-colors">
                      <i className="fas fa-trash-can"></i>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </SectionCard>

      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';

interface InfoItem {
  type: string;
  text: string;
}

interface SectionCardProps {
  title: string;
  icon: string;
  children: React.ReactNode;
  infoItems?: InfoItem[];
  defaultOpen?: boolean;
}

const SectionCard: React.FC<SectionCardProps> = ({ title, icon, children, infoItems, defaultOpen = true }) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);

  return (
    <div className="bg-[#151515] border border-gray-800 rounded-2xl overflow-hidden transition-all hover:border-yellow-700/30 group shadow-lg">
      <div 
        className="p-4 flex items-center justify-between border-b border-gray-800 bg-[#1a1a1a] cursor-pointer"
        onClick={() => setIsOpen(!isOpen)}
      >
        <div className="flex items-center gap-3 flex-grow">
          <div className="w-10 h-10 rounded-full bg-[#222] flex items-center justify-center text-[#d4af37] border border-gray-800 group-hover:border-yellow-600/50 transition-colors">
            <i className={`fas ${icon} text-lg`}></i>
          </div>
          <div className="flex flex-col">
             <h3 className="text-lg font-bold text-gray-100">{title}</h3>
             <span className="text-[10px] text-gray-500 font-medium tracking-tight">
               {isOpen ? 'انقر لإغلاق القسم' : 'انقر للتفاصيل والمهام'}
             </span>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full flex items-center justify-center text-gray-500 group-hover:text-yellow-500 bg-[#222] transition-colors">
            <i className={`fas fa-chevron-${isOpen ? 'up' : 'down'} text-xs transition-transform duration-300`}></i>
          </div>
        </div>
      </div>

      <div className={`transition-all duration-300 ease-in-out ${isOpen ? 'max-h-[3000px] opacity-100 overflow-visible' : 'max-h-0 opacity-0 overflow-hidden'}`}>
        {/* Religious Info - Automatically visible when section is open */}
        {infoItems && infoItems.length > 0 && (
          <div className="bg-[#1a1a1a] border-b border-gray-800/50">
            {infoItems.map((info, idx) => (
              <div key={idx} className="p-5 bg-gradient-to-l from-yellow-900/10 via-transparent to-transparent">
                <div className="flex items-center gap-2 mb-2">
                  <div className="w-1.5 h-1.5 rounded-full bg-yellow-600"></div>
                  <span className="text-[10px] font-bold px-2 py-0.5 rounded bg-yellow-900/30 text-yellow-500 uppercase tracking-tighter">
                    {info.type} اليوم
                  </span>
                </div>
                <p className="quran-font text-gray-200 text-xl leading-relaxed text-right pr-4 border-r-2 border-yellow-800/30 italic">
                  {info.text}
                </p>
              </div>
            ))}
          </div>
        )}

        <div className="p-5">
          {children}
        </div>
      </div>
    </div>
  );
};

export default SectionCard;

