  const [isOpen, setIsOpen] = useState(defaultOpen);

  return (
    <div className="bg-white dark:bg-[#151515] border border-gray-200 dark:border-gray-800 rounded-2xl overflow-hidden transition-all hover:border-yellow-700/30 group shadow-md dark:shadow-lg">
      <div 
        className="p-4 flex items-center justify-between border-b border-gray-100 dark:border-gray-800 bg-gray-50/50 dark:bg-[#1a1a1a] cursor-pointer"
        onClick={() => setIsOpen(!isOpen)}
      >
        <div className="flex items-center gap-3 flex-grow">
          <div className="w-10 h-10 rounded-full bg-white dark:bg-[#222] flex items-center justify-center text-[#d4af37] border border-gray-200 dark:border-gray-800 group-hover:border-yellow-600/50 transition-colors shadow-sm">
            <i className={`fas ${icon} text-lg`}></i>
          </div>
          <div className="flex flex-col">
             <h3 className="text-lg font-bold text-slate-800 dark:text-gray-100">{title}</h3>
             <span className="text-[10px] text-gray-500 dark:text-gray-500 font-bold tracking-tight">
               {isOpen ? 'انقر لإغلاق القسم' : 'انقر للتفاصيل والمهام'}
             </span>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full flex items-center justify-center text-gray-400 dark:text-gray-500 group-hover:text-yellow-600 bg-gray-100 dark:bg-[#222] transition-colors">
            <i className={`fas fa-chevron-${isOpen ? 'up' : 'down'} text-xs transition-transform duration-300`}></i>
          </div>
        </div>
      </div>

      <div className={`transition-all duration-500 ease-in-out ${isOpen ? 'max-h-[3000px] opacity-100' : 'max-h-0 opacity-0 overflow-hidden'}`}>
        {/* Religious Info */}
        {infoItems && infoItems.length > 0 && (
          <div className="bg-yellow-50/30 dark:bg-[#1a1a1a] border-b border-gray-100 dark:border-gray-800/50">
            {infoItems.map((info, idx) => (
              <div key={idx} className="p-5">
                <div className="flex items-center gap-2 mb-2">
                  <div className="w-1.5 h-1.5 rounded-full bg-yellow-600"></div>
                  <span className="text-[10px] font-bold px-2 py-0.5 rounded bg-yellow-600/10 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-500 uppercase tracking-tighter">
                    {info.type} اليوم
                  </span>
                </div>
                <p className="quran-font text-slate-700 dark:text-gray-200 text-xl leading-relaxed text-right pr-4 border-r-2 border-yellow-600/30 dark:border-yellow-800/30 italic">
                  {info.text}
                </p>
              </div>
            ))}
          </div>
        )}

        <div className="p-5 dark:text-gray-300">
          {children}
        </div>
      </div>
    </div>
  );
};

export default SectionCard;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  PRAYER_TASKS, 
  AZKAR_TASKS, 
  GOOD_DEED_TASKS, 
  MUJAHADA_TASKS, 
  MOTIVATIONAL_QUOTES,
  SECTION_INFO
} from '../constants';
import { getLogForDate, saveLog, formatDate } from '../services/storageService';
import SectionCard from '../components/SectionCard';
import { DailyLog } from '../types';

const Dashboard: React.FC = () => {
  const [currentDate] = useState(formatDate(new Date()));
  const [log, setLog] = useState<DailyLog>(getLogForDate(currentDate));
  const [newNote, setNewNote] = useState("");
  const [newMujahadaNote, setNewMujahadaNote] = useState("");

  const dailyRotationIndex = useMemo(() => {
    const d = new Date();
    return d.getDate();
  }, []);

  const quote = useMemo(() => {
    return MOTIVATIONAL_QUOTES[dailyRotationIndex % MOTIVATIONAL_QUOTES.length];
  }, [dailyRotationIndex]);

  const getDailyInfo = (section: keyof typeof SECTION_INFO) => {
    const list = SECTION_INFO[section];
    return [list[dailyRotationIndex % list.length]];
  };

  useEffect(() => {
    saveLog(log);
  }, [log]);

  const toggleTask = (section: keyof DailyLog, id: string) => {
    setLog(prev => {
      const currentList = prev[section] as string[];
      const newList = currentList.includes(id) 
        ? currentList.filter(item => item !== id)
        : [...currentList, id];
      return { ...prev, [section]: newList };
    });
  };

  const handleQuranChange = (field: 'quranStart' | 'quranEnd', value: string) => {
    const num = Math.min(604, Math.max(0, parseInt(value) || 0));
    setLog(prev => ({ ...prev, [field]: num }));
  };

  const addNote = () => {
    if (!newNote.trim()) return;
    setLog(prev => ({ ...prev, notes: [...prev.notes, newNote] }));
    setNewNote("");
  };

  const addMujahadaNote = () => {
    if (!newMujahadaNote.trim()) return;
    setLog(prev => ({ ...prev, mujahadaNotes: [...prev.mujahadaNotes, newMujahadaNote] }));
    setNewMujahadaNote("");
  };

  const deleteNote = (index: number) => {
    setLog(prev => ({ ...prev, notes: prev.notes.filter((_, i) => i !== index) }));
  };

  const deleteMujahadaNote = (index: number) => {
    setLog(prev => ({ ...prev, mujahadaNotes: prev.mujahadaNotes.filter((_, i) => i !== index) }));
  };

  const score = useMemo(() => {
    const positiveCount = log.prayers.length + log.azkar.length + log.goodDeeds.length + log.notes.length;
    const negativeCount = log.mujahada.length + log.mujahadaNotes.length;
    return (positiveCount * 10) - (negativeCount * 10);
  }, [log]);

  const quranProgress = useMemo(() => {
    const pagesRead = Math.max(0, log.quranEnd - log.quranStart);
    const totalRemaining = 604 - log.quranEnd;
    const percentage = (log.quranEnd / 604) * 100;
    return { pagesRead, totalRemaining, percentage };
  }, [log.quranStart, log.quranEnd]);

  return (
    <div className="space-y-6 pb-12 animate-fade-in">
      {/* Motivational Quote */}
      <div className="bg-white dark:bg-[#1a1a1a] border border-yellow-600/20 dark:border-yellow-900/30 p-8 rounded-3xl relative overflow-hidden group shadow-xl">
        <div className="absolute top-0 right-0 w-48 h-48 bg-yellow-500/5 rounded-full -mr-24 -mt-24 blur-3xl"></div>
        <div className="relative z-10 text-center">
          <i className="fas fa-hands-praying text-[#d4af37] text-3xl mb-4 opacity-40"></i>
          <p className="text-2xl md:text-3xl font-bold text-slate-800 dark:text-gray-100 leading-snug quran-font">
            "{quote.text}"
          </p>
          <div className="mt-6 flex items-center justify-center gap-3">
            <span className="h-[1px] w-12 bg-gray-200 dark:bg-gray-800"></span>
            <span className="text-sm text-yellow-700 dark:text-yellow-600 font-black uppercase tracking-wider">{quote.source}</span>
            <span className="h-[1px] w-12 bg-gray-200 dark:bg-gray-800"></span>
          </div>
        </div>
      </div>

      {/* Daily Score Summary */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'نقاط اليوم', value: score, highlight: true },
          { label: 'ختمة القرآن', value: `${Math.round(quranProgress.percentage)}%`, highlight: false },
          { label: 'العبادات', value: log.prayers.length + log.azkar.length, highlight: false },
          { label: 'أعمال خير', value: log.goodDeeds.length + log.notes.length, highlight: false },
        ].map((stat, idx) => (
          <div key={idx} className="bg-white dark:bg-[#151515] p-5 rounded-2xl border border-gray-100 dark:border-gray-800 flex flex-col items-center justify-center shadow-sm dark:shadow-inner">
            <span className="text-gray-400 dark:text-gray-500 text-[10px] mb-1 font-black tracking-widest uppercase">{stat.label}</span>
            <span className={`text-3xl font-black ${stat.highlight ? 'text-yellow-600 dark:text-[#d4af37]' : 'text-slate-800 dark:text-gray-200'}`}>{stat.value}</span>
          </div>
        ))}
      </div>

      {/* Sections Grid */}
      <div className="grid md:grid-cols-2 gap-6">

        {/* Prayers */}
        <SectionCard title="قسم الصلاة" icon="fa-mosque" infoItems={getDailyInfo('PRAYER')}>
          <div className="grid grid-cols-2 gap-3">
            {PRAYER_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-3 rounded-xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-yellow-50 dark:hover:bg-[#222] transition-all border border-transparent hover:border-yellow-200 dark:hover:border-gray-800">
                <input 
                  type="checkbox" 
                  checked={log.prayers.includes(task.id)}
                  onChange={() => toggleTask('prayers', task.id)}
                  className="w-5 h-5 rounded border-gray-300 dark:border-gray-700 text-yellow-600 bg-white dark:bg-gray-900 focus:ring-yellow-500"
                />
                <span className={`text-sm font-bold ${log.prayers.includes(task.id) ? 'text-yellow-600 line-through opacity-70' : 'text-slate-700 dark:text-gray-300'}`}>
                  {task.label}
                </span>
              </label>
            ))}
          </div>
        </SectionCard>

        {/* Azkar */}
        <SectionCard title="قسم الأذكار" icon="fa-hands-praying" infoItems={getDailyInfo('AZKAR')}>
          <div className="grid grid-cols-2 gap-3">
            {AZKAR_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-3 rounded-xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-yellow-50 dark:hover:bg-[#222] transition-all border border-transparent hover:border-yellow-200 dark:hover:border-gray-800">
                <input 
                  type="checkbox" 
                  checked={log.azkar.includes(task.id)}
                  onChange={() => toggleTask('azkar', task.id)}
                  className="w-5 h-5 rounded border-gray-300 dark:border-gray-700 text-yellow-600 bg-white dark:bg-gray-900 focus:ring-yellow-500"
                />
                <span className={`text-sm font-bold ${log.azkar.includes(task.id) ? 'text-yellow-600 line-through opacity-70' : 'text-slate-700 dark:text-gray-300'}`}>
                  {task.label}
                </span>
              </label>
            ))}
          </div>
        </SectionCard>

        {/* Quran */}
        <SectionCard title="ختمة القرآن" icon="fa-book-quran" infoItems={getDailyInfo('QURAN')}>
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] text-gray-500 block font-black uppercase">من صفحة</label>
                <input 
                  type="number" 
                  value={log.quranStart || ""}
                  onChange={(e) => handleQuranChange('quranStart', e.target.value)}
                  className="w-full bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-xl p-3 text-center text-yellow-600 font-black focus:outline-none focus:ring-2 focus:ring-yellow-500/20"
                  placeholder="0"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] text-gray-500 block font-black uppercase">إلى صفحة</label>
                <input 
                  type="number" 
                  value={log.quranEnd || ""}
                  onChange={(e) => handleQuranChange('quranEnd', e.target.value)}
                  className="w-full bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-xl p-3 text-center text-yellow-600 font-black focus:outline-none focus:ring-2 focus:ring-yellow-500/20"
                  placeholder="0"
                />
              </div>
            </div>

            <div className="bg-gray-50 dark:bg-[#1a1a1a] p-4 rounded-2xl border border-gray-100 dark:border-gray-800 flex justify-between items-center">
              <div className="text-center flex-1 border-l border-gray-200 dark:border-gray-800">
                <p className="text-2xl font-black text-slate-800 dark:text-gray-200">{quranProgress.pagesRead}</p>
                <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest">صفحات اليوم</p>
              </div>
              <div className="text-center flex-1">
                <p className="text-2xl font-black text-yellow-600">{quranProgress.totalRemaining}</p>
                <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest">متبقي للختمة</p>
              </div>
            </div>

            <div className="space-y-2">
              <div className="flex justify-between text-[10px] text-gray-500 font-black uppercase">
                <span>التقدم الإجمالي</span>
                <span>{Math.round(quranProgress.percentage)}%</span>
              </div>
              <div className="w-full h-3 bg-gray-200 dark:bg-gray-900 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-gradient-to-r from-yellow-600 to-yellow-400 rounded-full transition-all duration-1000 ease-out"
                  style={{ width: `${quranProgress.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>
        </SectionCard>

        {/* Mujahada */}
        <SectionCard title="مجاهدة النفس" icon="fa-shield-halved" infoItems={getDailyInfo('MUJAHADA')} defaultOpen={false}>
          <p className="text-[10px] text-red-600/80 mb-3 text-center bg-red-50 dark:bg-red-900/10 py-2 rounded-lg font-black border border-red-100 dark:border-red-900/20 uppercase tracking-widest">اختر ما وقعت فيه اليوم (يخصم 10 نقاط)</p>
          <div className="space-y-3 mb-4">
            {MUJAHADA_TASKS.map(task => (
              <label key={task.id} className="flex items-start gap-3 p-3 rounded-xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-red-50 dark:hover:bg-red-900/5 border border-transparent hover:border-red-200 dark:hover:border-red-900/30 transition-all">
                <input 
                  type="checkbox" 
                  checked={log.mujahada.includes(task.id)}
                  onChange={() => toggleTask('mujahada', task.id)}
                  className="w-5 h-5 mt-0.5 rounded border-gray-300 dark:border-gray-700 text-red-600 bg-white dark:bg-gray-900"
                />
                <div className="flex flex-col">
                  <span className={`text-sm font-bold ${log.mujahada.includes(task.id) ? 'text-red-600' : 'text-slate-700 dark:text-gray-300'}`}>
                    {task.label}
                  </span>
                  <span className="text-[10px] text-gray-500 leading-tight mt-0.5">{task.description}</span>
                </div>
              </label>
            ))}
          </div>

          <div className="pt-3 border-t border-gray-100 dark:border-gray-800">
              <div className="flex gap-2 mb-3">
                <input 
                  type="text" 
                  value={newMujahadaNote}
                  onChange={(e) => setNewMujahadaNote(e.target.value)}
                  placeholder="أضف زلة أخرى..."
                  className="flex-grow bg-white dark:bg-[#222] border border-gray-200 dark:border-gray-800 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-1 focus:ring-red-500"
                />
                <button 
                  onClick={addMujahadaNote}
                  className="bg-red-600 dark:bg-red-900/40 hover:bg-red-700 dark:hover:bg-red-900/60 text-white dark:text-red-500 w-10 h-10 rounded-xl transition-all shadow-md flex items-center justify-center border border-red-200 dark:border-red-900/50"
                >
                  <i className="fas fa-plus"></i>
                </button>
              </div>
              <ul className="space-y-2">
                {log.mujahadaNotes.map((note, idx) => (
                  <li key={idx} className="flex items-center justify-between text-xs bg-red-50 dark:bg-red-900/5 p-3 rounded-xl border border-red-100 dark:border-red-900/20 animate-slide-in">
                    <span className="text-red-700 dark:text-red-400 font-bold">{note}</span>
                    <button onClick={() => deleteMujahadaNote(idx)} className="text-gray-400 hover:text-red-600 transition-colors">
                      <i className="fas fa-trash-can"></i>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
        </SectionCard>

        {/* Good Deeds */}
        <SectionCard title="أعمال الخير" icon="fa-heart" infoItems={getDailyInfo('GOOD_DEEDS')} defaultOpen={false}>
          <div className="space-y-3">
             <div className="grid grid-cols-1 gap-2">
              {GOOD_DEED_TASKS.map(task => (
                <label key={task.id} className="flex items-start gap-3 p-3 rounded-xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-emerald-50 dark:hover:bg-[#222] border border-transparent hover:border-emerald-200 dark:hover:border-gray-800 transition-all">
                  <input 
                    type="checkbox" 
                    checked={log.goodDeeds.includes(task.id)}
                    onChange={() => toggleTask('goodDeeds', task.id)}
                    className="w-5 h-5 mt-0.5 rounded border-gray-300 dark:border-gray-700 text-emerald-600 bg-white dark:bg-gray-900"
                  />
                  <div className="flex flex-col">
                    <span className={`text-sm font-bold ${log.goodDeeds.includes(task.id) ? 'text-emerald-600' : 'text-slate-700 dark:text-gray-300'}`}>
                      {task.label}
                    </span>
                    <span className="text-[10px] text-gray-500 leading-tight mt-0.5">{task.description}</span>
                  </div>
                </label>
              ))}
            </div>

            <div className="pt-3 border-t border-gray-100 dark:border-gray-800">
              <div className="flex gap-2 mb-3">
                <input 
                  type="text" 
                  value={newNote}
                  onChange={(e) => setNewNote(e.target.value)}
                  placeholder="أضف عمل خير آخر..."
                  className="flex-grow bg-white dark:bg-[#222] border border-gray-200 dark:border-gray-800 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-1 focus:ring-yellow-500"
                />
                <button 
                  onClick={addNote}
                  className="bg-yellow-600 hover:bg-yellow-700 text-white w-10 h-10 rounded-xl transition-all shadow-md flex items-center justify-center"
                >
                  <i className="fas fa-plus"></i>
                </button>
              </div>
              <ul className="space-y-2">
                {log.notes.map((note, idx) => (
                  <li key={idx} className="flex items-center justify-between text-xs bg-emerald-50 dark:bg-[#1a1a1a] p-3 rounded-xl border border-emerald-100 dark:border-gray-800 animate-slide-in">
                    <span className="text-emerald-700 dark:text-gray-300 font-bold">{note}</span>
                    <button onClick={() => deleteNote(idx)} className="text-gray-400 hover:text-red-500 transition-colors">
                      <i className="fas fa-trash-can"></i>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </SectionCard>

      </div>
    </div>
  );
};

export default Dashboard;

import React, { useMemo } from 'react';
import { getLogs } from '../services/storageService';
import { DailyLog } from '../types';

const History: React.FC = () => {
  const logs = useMemo(() => getLogs(), []);
  const sortedDates = Object.keys(logs).sort((a, b) => b.localeCompare(a));

  const calculateScore = (log: DailyLog) => {
    const positiveCount = (log.prayers?.length || 0) + (log.azkar?.length || 0) + (log.goodDeeds?.length || 0) + (log.notes?.length || 0);
    const negativeCount = (log.mujahada?.length || 0) + (log.mujahadaNotes?.length || 0);
    return (positiveCount * 10) - (negativeCount * 10);
  };

  const totalPoints = useMemo(() => {
    return Object.values(logs).reduce((acc: number, log: DailyLog) => acc + calculateScore(log), 0);
  }, [logs]);

  return (
    <div className="animate-fade-in space-y-6 pb-12">
      <div className="bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-2xl p-8 text-center shadow-xl">
        <h2 className="text-gray-500 text-[10px] mb-2 font-black tracking-widest uppercase">رصيدك الكلي من الحسنات</h2>
        <div className="text-6xl font-black gold-gradient drop-shadow-sm">{totalPoints}</div>
        <div className="mt-6 flex items-center justify-center gap-6 text-[10px] font-black uppercase tracking-tighter">
          <div className="flex items-center gap-1.5 text-emerald-600">
            <span className="w-2.5 h-2.5 rounded-full bg-emerald-500 shadow-sm shadow-emerald-500/50"></span>
            <span>كل عمل +10</span>
          </div>
          <div className="flex items-center gap-1.5 text-red-600">
            <span className="w-2.5 h-2.5 rounded-full bg-red-500 shadow-sm shadow-red-500/50"></span>
            <span>كل ذنب -10</span>
          </div>
        </div>
      </div>

      <div className="bg-white dark:bg-[#151515] border border-gray-200 dark:border-gray-800 rounded-2xl overflow-hidden shadow-lg">
        <div className="p-5 border-b border-gray-100 dark:border-gray-800 bg-gray-50 dark:bg-[#1a1a1a] flex items-center justify-between">
          <h3 className="font-black text-slate-800 dark:text-gray-100">سجل المتابعة اليومي</h3>
          <span className="text-[10px] font-black text-gray-500 bg-gray-200 dark:bg-gray-800 px-2 py-1 rounded">{sortedDates.length} أيام مسجلة</span>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-right">
            <thead>
              <tr className="bg-gray-50 dark:bg-[#222] text-[10px] text-gray-500 uppercase font-black">
                <th className="px-5 py-4">التاريخ</th>
                <th className="px-5 py-4">الصلوات</th>
                <th className="px-5 py-4">الأذكار</th>
                <th className="px-5 py-4">القرآن</th>
                <th className="px-5 py-4">المجموع</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
              {sortedDates.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-5 py-16 text-center text-gray-400 font-bold italic">لا توجد بيانات مسجلة بعد</td>
                </tr>
              ) : (
                sortedDates.map(date => {
                  const log = logs[date];
                  const score = calculateScore(log);
                  return (
                    <tr key={date} className="hover:bg-gray-50/50 dark:hover:bg-[#1a1a1a] transition-colors group">
                      <td className="px-5 py-5 text-sm font-black text-slate-700 dark:text-gray-300">{date}</td>
                      <td className="px-5 py-5 text-sm text-gray-600 dark:text-gray-400 font-bold">{log.prayers.length}/10</td>
                      <td className="px-5 py-5 text-sm text-gray-600 dark:text-gray-400 font-bold">{log.azkar.length}/6</td>
                      <td className="px-5 py-5 text-sm text-gray-600 dark:text-gray-400 font-bold">{log.quranEnd - log.quranStart} ص</td>
                      <td className="px-5 py-5">
                        <span className={`px-3 py-1.5 rounded-lg text-xs font-black shadow-sm ${score >= 0 ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-500 border border-emerald-100 dark:border-emerald-900/30' : 'bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-500 border border-red-100 dark:border-red-900/30'}`}>
                          {score > 0 ? `+${score}` : score}
                        </span>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="p-6 text-center text-gray-500 text-xs font-bold bg-white/50 dark:bg-transparent rounded-2xl border border-dashed border-gray-200 dark:border-gray-800">
        <i className="fas fa-shield-halved mb-2 block text-xl opacity-20"></i>
        <p>جميع بياناتك مخزنة محلياً في جهازك وبأمان تام.</p>
      </div>
    </div>
  );
};

export default History;

import React, { useMemo, useState } from 'react';
import { getLogs } from '../services/storageService';
import { DailyLog } from '../types';
import { PRAYER_TASKS, AZKAR_TASKS } from '../constants';

const History: React.FC = () => {
  const [startDate, setStartDate] = useState(() => {
    const d = new Date();
    d.setDate(d.getDate() - 7);
    return d.toISOString().split('T')[0];
  });
  const [endDate, setEndDate] = useState(() => new Date().toISOString().split('T')[0]);

  const logs = useMemo(() => getLogs(), []);

  const filteredDates = useMemo(() => {
    return Object.keys(logs)
      .filter(date => date >= startDate && date <= endDate)
      .sort((a, b) => b.localeCompare(a));
  }, [logs, startDate, endDate]);

  const calculateScore = (log: DailyLog) => {
    const positiveCount = (log.prayers?.length || 0) + (log.azkar?.length || 0) + (log.goodDeeds?.length || 0) + (log.notes?.length || 0);
    const negativeCount = (log.mujahada?.length || 0) + (log.mujahadaNotes?.length || 0);
    return (positiveCount * 10) - (negativeCount * 10);
  };

  const totalPoints = useMemo(() => {
    return filteredDates.reduce((acc: number, date: string) => acc + calculateScore(logs[date]), 0);
  }, [logs, filteredDates]);

  const toHijri = (dateStr: string) => {
    try {
      const date = new Date(dateStr);
      return new Intl.DateTimeFormat('ar-SA-u-ca-islamic-uma-nu-latn', {
        day: 'numeric',
        month: 'long',
        year: 'numeric'
      }).format(date);
    } catch (e) {
      return '';
    }
  };

  const getTaskLabel = (id: string, type: 'prayer' | 'azkar') => {
    const source = type === 'prayer' ? PRAYER_TASKS : AZKAR_TASKS;
    return source.find(t => t.id === id)?.label.split(' ')[1] || source.find(t => t.id === id)?.label || id;
  };

  return (
    <div className="animate-fade-in space-y-6 pb-12">
      {/* Summary Header */}
      <div className="bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-2xl p-6 md:p-8 text-center shadow-xl relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-yellow-500 to-transparent opacity-30"></div>
        <h2 className="text-gray-500 dark:text-gray-400 text-[10px] mb-2 font-black tracking-widest uppercase">رصيد الفترة المحددة</h2>
        <div className="text-6xl font-black gold-gradient drop-shadow-sm">{totalPoints}</div>
        <p className="text-[10px] text-gray-400 mt-2 font-bold">من {toHijri(startDate)} إلى {toHijri(endDate)}</p>
      </div>

      {/* Advanced Filter */}
      <div className="bg-white dark:bg-[#151515] border border-gray-200 dark:border-gray-800 rounded-2xl p-4 shadow-md">
        <div className="flex flex-col md:flex-row gap-4 items-end">
          <div className="flex-1 w-full space-y-1">
            <label className="text-[10px] font-black text-gray-500 uppercase pr-2">من تاريخ</label>
            <input 
              type="date" 
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              className="w-full bg-gray-50 dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-xl p-3 text-sm font-bold focus:ring-2 focus:ring-yellow-500/20 outline-none dark:text-gray-200"
            />
          </div>
          <div className="flex-1 w-full space-y-1">
            <label className="text-[10px] font-black text-gray-500 uppercase pr-2">إلى تاريخ</label>
            <input 
              type="date" 
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              className="w-full bg-gray-50 dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-xl p-3 text-sm font-bold focus:ring-2 focus:ring-yellow-500/20 outline-none dark:text-gray-200"
            />
          </div>
        </div>
      </div>

      {/* Responsive Detailed Table */}
      <div className="bg-white dark:bg-[#151515] border border-gray-200 dark:border-gray-800 rounded-2xl overflow-hidden shadow-lg">
        <div className="p-5 border-b border-gray-100 dark:border-gray-800 bg-gray-50 dark:bg-[#1a1a1a] flex items-center justify-between">
          <h3 className="font-black text-slate-800 dark:text-gray-100">تفاصيل العبادات اليومية</h3>
          <span className="text-[10px] font-black text-yellow-700 bg-yellow-100 dark:bg-yellow-900/30 px-3 py-1 rounded-full uppercase">
            {filteredDates.length} أيام في العرض
          </span>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-right min-w-[900px]">
            <thead>
              <tr className="bg-gray-50 dark:bg-[#1a1a1a] text-[10px] text-gray-500 uppercase font-black border-b border-gray-100 dark:border-gray-800">
                <th className="px-5 py-4 w-40">التاريخ</th>
                <th className="px-5 py-4">الصلوات</th>
                <th className="px-5 py-4">الأذكار</th>
                <th className="px-5 py-4">القرآن</th>
                <th className="px-5 py-4 text-center">أعمال البر</th>
                <th className="px-5 py-4 text-center">المجاهدة</th>
                <th className="px-5 py-4 text-center">النتيجة</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
              {filteredDates.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-5 py-16 text-center text-gray-400 font-bold italic">لا توجد سجلات لهذه الفترة</td>
                </tr>
              ) : (
                filteredDates.map(date => {
                  const log = logs[date];
                  const score = calculateScore(log);
                  return (
                    <tr key={date} className="hover:bg-gray-50/50 dark:hover:bg-[#1a1a1a] transition-colors group">
                      {/* Date Column */}
                      <td className="px-5 py-5">
                        <div className="flex flex-col">
                          <span className="text-xs font-black text-slate-800 dark:text-gray-200">{date}</span>
                          <span className="text-[9px] text-gray-500 font-bold mt-1">{toHijri(date)}</span>
                        </div>
                      </td>

                      {/* Prayers Details */}
                      <td className="px-5 py-5">
                        <div className="flex flex-wrap gap-1 max-w-[150px]">
                          {log.prayers.length > 0 ? log.prayers.map(p => (
                            <span key={p} className="text-[9px] px-1.5 py-0.5 rounded bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 font-black border border-blue-100 dark:border-blue-900/30">
                              {getTaskLabel(p, 'prayer')}
                            </span>
                          )) : <span className="text-[10px] text-gray-400 italic">لم تسجل</span>}
                        </div>
                      </td>

                      {/* Azkar Details */}
                      <td className="px-5 py-5">
                        <div className="flex flex-wrap gap-1 max-w-[150px]">
                          {log.azkar.length > 0 ? log.azkar.map(a => (
                            <span key={a} className="text-[9px] px-1.5 py-0.5 rounded bg-purple-50 dark:bg-purple-900/20 text-purple-600 dark:text-purple-400 font-black border border-purple-100 dark:border-purple-900/30">
                              {getTaskLabel(a, 'azkar')}
                            </span>
                          )) : <span className="text-[10px] text-gray-400 italic">لم تسجل</span>}
                        </div>
                      </td>

                      {/* Quran Progress */}
                      <td className="px-5 py-5 text-center">
                        <div className="inline-flex flex-col items-center bg-gray-50 dark:bg-[#222] px-3 py-1.5 rounded-xl border border-gray-100 dark:border-gray-800">
                          <span className="text-xs font-black text-yellow-700 dark:text-yellow-500">
                            {log.quranStart} ↔ {log.quranEnd}
                          </span>
                          <span className="text-[8px] text-gray-400 font-bold">صفحة</span>
                        </div>
                      </td>

                      {/* Good Deeds Count */}
                      <td className="px-5 py-5 text-center">
                         <div className="inline-flex flex-col items-center">
                            <span className="text-lg font-black text-emerald-600">
                              {log.goodDeeds.length + log.notes.length}
                            </span>
                            <span className="text-[8px] text-emerald-500/70 font-bold uppercase tracking-widest">عمل صالح</span>
                         </div>
                      </td>

                      {/* Mujahada Count */}
                      <td className="px-5 py-5 text-center">
                        <div className="inline-flex flex-col items-center">
                            <span className="text-lg font-black text-red-600">
                              {log.mujahada.length + log.mujahadaNotes.length}
                            </span>
                            <span className="text-[8px] text-red-500/70 font-bold uppercase tracking-widest">زلات نفس</span>
                         </div>
                      </td>

                      {/* Daily Total */}
                      <td className="px-5 py-5 text-center">
                        <span className={`inline-block px-3 py-1.5 rounded-lg text-xs font-black shadow-sm border ${score >= 0 ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-500 border-emerald-100 dark:border-emerald-900/30' : 'bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-500 border-red-100 dark:border-red-900/30'}`}>
                          {score > 0 ? `+${score}` : score}
                        </span>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="p-6 text-center text-gray-500 text-xs font-bold bg-white/50 dark:bg-transparent rounded-2xl border border-dashed border-gray-200 dark:border-gray-800">
        <i className="fas fa-calendar-check mb-2 block text-xl opacity-20"></i>
        <p>يتم احتساب الرصيد بناءً على الفلترة المختارة أعلاه.</p>
      </div>
    </div>
  );
};

export default History;

import React, { useMemo, useState } from 'react';
import { getLogs } from '../services/storageService';
import { DailyLog } from '../types';
import { PRAYER_TASKS, AZKAR_TASKS } from '../constants';

const History: React.FC = () => {
  const [startDate, setStartDate] = useState(() => {
    const d = new Date();
    d.setDate(d.getDate() - 7);
    return d.toISOString().split('T')[0];
  });
  const [endDate, setEndDate] = useState(() => new Date().toISOString().split('T')[0]);
  const [isHijriMode, setIsHijriMode] = useState(true);

  const logs = useMemo(() => getLogs(), []);

  const filteredDates = useMemo(() => {
    return Object.keys(logs)
      .filter(date => date >= startDate && date <= endDate)
      .sort((a, b) => b.localeCompare(a));
  }, [logs, startDate, endDate]);

  const calculateScore = (log: DailyLog) => {
    const positiveCount = (log.prayers?.length || 0) + (log.azkar?.length || 0) + (log.goodDeeds?.length || 0) + (log.notes?.length || 0);
    const negativeCount = (log.mujahada?.length || 0) + (log.mujahadaNotes?.length || 0);
    return (positiveCount * 10) - (negativeCount * 10);
  };

  const totalPoints = useMemo(() => {
    return filteredDates.reduce((acc: number, date: string) => acc + calculateScore(logs[date]), 0);
  }, [logs, filteredDates]);

  // دالة تحويل التاريخ إلى نص عربي (هجري أو ميلادي)
  const formatArabicDate = (dateStr: string, forceHijri?: boolean) => {
    try {
      const date = new Date(dateStr);
      const calendar = (forceHijri ?? isHijriMode) ? 'islamic-uma' : 'gregory';
      return new Intl.DateTimeFormat(`ar-SA-u-ca-${calendar}-nu-latn`, {
        day: 'numeric',
        month: 'long',
        year: 'numeric'
      }).format(date);
    } catch (e) {
      return dateStr;
    }
  };

  const getTaskLabel = (id: string, type: 'prayer' | 'azkar') => {
    const source = type === 'prayer' ? PRAYER_TASKS : AZKAR_TASKS;
    const task = source.find(t => t.id === id);
    if (!task) return id;
    // استخراج اسم الصلاة أو الذكر فقط بدون كلمة "صلاة" لتقليل الزحام
    return task.label.replace('صلاة ', '').replace('أذكار ', '');
  };

  return (
    <div className="animate-fade-in space-y-6 pb-12">
      {/* Summary Header */}
      <div className="bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-3xl p-8 text-center shadow-xl relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-yellow-500 to-transparent opacity-40"></div>
        <h2 className="text-gray-500 dark:text-gray-400 text-[10px] mb-2 font-black tracking-widest uppercase">رصيد النقاط للفترة المختارة</h2>
        <div className="text-6xl font-black gold-gradient drop-shadow-sm mb-2">{totalPoints}</div>
        <div className="flex items-center justify-center gap-2 text-[11px] text-yellow-700 dark:text-yellow-600 font-bold bg-yellow-50 dark:bg-yellow-900/10 px-4 py-1.5 rounded-full inline-flex mx-auto border border-yellow-100 dark:border-yellow-900/20">
          <i className="fas fa-calendar-alt"></i>
          <span>من {formatArabicDate(startDate)} إلى {formatArabicDate(endDate)}</span>
        </div>
      </div>

      {/* Advanced Filter with Toggle */}
      <div className="bg-white dark:bg-[#151515] border border-gray-200 dark:border-gray-800 rounded-2xl p-4 shadow-md">
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="grid grid-cols-2 gap-3 flex-grow w-full">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-gray-400 uppercase pr-2">من</label>
              <input 
                type="date" 
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="w-full bg-gray-50 dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-xl p-3 text-xs font-bold focus:ring-2 focus:ring-yellow-500/20 outline-none dark:text-gray-200"
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-gray-400 uppercase pr-2">إلى</label>
              <input 
                type="date" 
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                className="w-full bg-gray-50 dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-xl p-3 text-xs font-bold focus:ring-2 focus:ring-yellow-500/20 outline-none dark:text-gray-200"
              />
            </div>
          </div>

          <button 
            onClick={() => setIsHijriMode(!isHijriMode)}
            className="flex items-center gap-2 px-6 py-3 bg-slate-800 dark:bg-yellow-600 text-white rounded-xl shadow-lg hover:opacity-90 transition-all font-bold text-sm w-full md:w-auto mt-2 md:mt-4 group"
          >
            <i className={`fas ${isHijriMode ? 'fa-moon' : 'fa-calendar-day'} group-hover:rotate-12 transition-transform`}></i>
            <span>التقويم {isHijriMode ? 'الهجري' : 'الميلادي'}</span>
          </button>
        </div>
      </div>

      {/* Detailed Table */}
      <div className="bg-white dark:bg-[#151515] border border-gray-200 dark:border-gray-800 rounded-2xl overflow-hidden shadow-lg">
        <div className="p-5 border-b border-gray-100 dark:border-gray-800 bg-gray-50 dark:bg-[#1a1a1a] flex items-center justify-between">
          <h3 className="font-black text-slate-800 dark:text-gray-100 flex items-center gap-2">
            <i className="fas fa-list-check text-yellow-600"></i>
            سجل المتابعة التفصيلي
          </h3>
          <span className="text-[10px] font-black text-gray-500 bg-white dark:bg-gray-800 px-3 py-1 rounded border border-gray-200 dark:border-gray-700">
            {filteredDates.length} أيام
          </span>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-right min-w-[950px]">
            <thead>
              <tr className="bg-gray-50 dark:bg-[#1a1a1a] text-[10px] text-gray-500 uppercase font-black border-b border-gray-100 dark:border-gray-800">
                <th className="px-5 py-4 w-44">اليوم والتاريخ</th>
                <th className="px-5 py-4">الصلوات</th>
                <th className="px-5 py-4">الأذكار</th>
                <th className="px-5 py-4">القرآن</th>
                <th className="px-5 py-4 text-center">أعمال البر</th>
                <th className="px-5 py-4 text-center">المجاهدة</th>
                <th className="px-5 py-4 text-center">النتيجة</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
              {filteredDates.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-5 py-20 text-center text-gray-400 font-bold italic">لا توجد بيانات مسجلة في هذه الفترة</td>
                </tr>
              ) : (
                filteredDates.map(date => {
                  const log = logs[date];
                  const score = calculateScore(log);
                  return (
                    <tr key={date} className="hover:bg-gray-50/50 dark:hover:bg-[#1a1a1a] transition-colors group">
                      {/* Date Info */}
                      <td className="px-5 py-5">
                        <div className="flex flex-col">
                          <span className="text-xs font-black text-slate-800 dark:text-gray-200">
                            {formatArabicDate(date)}
                          </span>
                          <span className="text-[9px] text-gray-400 font-bold mt-1">
                            {formatArabicDate(date, !isHijriMode)}
                          </span>
                        </div>
                      </td>

                      {/* Prayer Icons/Mini-labels */}
                      <td className="px-5 py-5">
                        <div className="flex flex-wrap gap-1 max-w-[160px]">
                          {log.prayers.length > 0 ? log.prayers.map(p => (
                            <span key={p} className="text-[9px] px-2 py-0.5 rounded bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 font-black border border-blue-100 dark:border-blue-900/30">
                              {getTaskLabel(p, 'prayer')}
                            </span>
                          )) : <i className="fas fa-minus text-gray-200 dark:text-gray-800"></i>}
                        </div>
                      </td>

                      {/* Azkar Mini-labels */}
                      <td className="px-5 py-5">
                        <div className="flex flex-wrap gap-1 max-w-[160px]">
                          {log.azkar.length > 0 ? log.azkar.map(a => (
                            <span key={a} className="text-[9px] px-2 py-0.5 rounded bg-purple-50 dark:bg-purple-900/20 text-purple-600 dark:text-purple-400 font-black border border-purple-100 dark:border-purple-900/30">
                              {getTaskLabel(a, 'azkar')}
                            </span>
                          )) : <i className="fas fa-minus text-gray-200 dark:text-gray-800"></i>}
                        </div>
                      </td>

                      {/* Quran Range */}
                      <td className="px-5 py-5">
                        <div className="flex flex-col items-center bg-gray-50 dark:bg-[#222] px-3 py-1.5 rounded-xl border border-gray-100 dark:border-gray-800 w-fit">
                          <span className="text-xs font-black text-yellow-700 dark:text-yellow-500">
                             {log.quranEnd > 0 ? `${log.quranStart} ↩ ${log.quranEnd}` : 'لم يبدأ'}
                          </span>
                          {log.quranEnd > 0 && <span className="text-[8px] text-gray-400 font-bold uppercase">صفحة</span>}
                        </div>
                      </td>

                      {/* Good Deeds - Count Only */}
                      <td className="px-5 py-5 text-center">
                         <div className="inline-flex flex-col items-center justify-center w-12 h-12 rounded-full bg-emerald-50 dark:bg-emerald-900/10 border border-emerald-100 dark:border-emerald-900/20">
                            <span className="text-lg font-black text-emerald-600 leading-none">
                              {log.goodDeeds.length + log.notes.length}
                            </span>
                            <span className="text-[7px] text-emerald-500 font-bold uppercase mt-1">عمل</span>
                         </div>
                      </td>

                      {/* Mujahada - Count Only */}
                      <td className="px-5 py-5 text-center">
                        <div className="inline-flex flex-col items-center justify-center w-12 h-12 rounded-full bg-red-50 dark:bg-red-900/10 border border-red-100 dark:border-red-900/20">
                            <span className="text-lg font-black text-red-600 leading-none">
                              {log.mujahada.length + log.mujahadaNotes.length}
                            </span>
                            <span className="text-[7px] text-red-500 font-bold uppercase mt-1">زلة</span>
                         </div>
                      </td>

                      {/* Score Result */}
                      <td className="px-5 py-5 text-center">
                        <span className={`inline-block px-4 py-2 rounded-xl text-xs font-black shadow-sm border transition-transform group-hover:scale-105 ${score >= 0 ? 'bg-emerald-500 text-white border-emerald-400' : 'bg-red-500 text-white border-red-400'}`}>
                          {score > 0 ? `+${score}` : score}
                        </span>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="bg-yellow-600/5 dark:bg-yellow-900/5 p-6 text-center text-gray-500 dark:text-gray-400 text-xs font-bold rounded-2xl border border-dashed border-yellow-200 dark:border-yellow-900/30">
        <p>يتم تحويل التاريخ وعرضه حسب نظام التقويم المختار في الأعلى.</p>
        <p className="mt-1 opacity-60">جميع الحسابات تعتمد على توقيت جهازك المحلي.</p>
      </div>
    </div>
  );
};

export default History;

