const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('theme');
    return saved ? saved === 'dark' : true;
  });

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  return (
    <HashRouter>
      <div className="min-h-screen flex flex-col pb-24 md:pb-0 md:pt-20 theme-transition">
        <Header />
        <main className="flex-grow max-w-4xl mx-auto w-full px-4">
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/history" element={<History />} />
          </Routes>
        </main>
        <Navigation isDarkMode={isDarkMode} toggleTheme={toggleTheme} />
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  PRAYER_TASKS, 
  AZKAR_TASKS, 
  GOOD_DEED_TASKS, 
  MUJAHADA_TASKS, 
  MOTIVATIONAL_QUOTES,
  SECTION_INFO
} from '../constants';
import { getLogForDate, saveLog, formatDate } from '../services/storageService';
import SectionCard from '../components/SectionCard';
import { DailyLog } from '../types';

const Dashboard: React.FC = () => {
  const [currentDate] = useState(formatDate(new Date()));
  const [log, setLog] = useState<DailyLog>(getLogForDate(currentDate));
  const [newNote, setNewNote] = useState("");
  const [newMujahadaNote, setNewMujahadaNote] = useState("");

  // Quran Goal State
  const [dailyGoal, setDailyGoal] = useState(() => {
    return parseInt(localStorage.getItem('quran_daily_goal') || "20");
  });

  const dailyRotationIndex = useMemo(() => {
    const d = new Date();
    return d.getDate();
  }, []);

  const quote = useMemo(() => {
    return MOTIVATIONAL_QUOTES[dailyRotationIndex % MOTIVATIONAL_QUOTES.length];
  }, [dailyRotationIndex]);

  const getDailyInfo = (section: keyof typeof SECTION_INFO) => {
    const list = SECTION_INFO[section];
    return [list[dailyRotationIndex % list.length]];
  };

  useEffect(() => {
    saveLog(log);
  }, [log]);

  useEffect(() => {
    localStorage.setItem('quran_daily_goal', dailyGoal.toString());
  }, [dailyGoal]);

  const toggleTask = (section: keyof DailyLog, id: string) => {
    setLog(prev => {
      const currentList = prev[section] as string[];
      const newList = currentList.includes(id) 
        ? currentList.filter(item => item !== id)
        : [...currentList, id];
      return { ...prev, [section]: newList };
    });
  };

  const handleQuranChange = (field: 'quranStart' | 'quranEnd', value: string) => {
    const num = Math.min(604, Math.max(0, parseInt(value) || 0));
    setLog(prev => ({ ...prev, [field]: num }));
  };

  const addNote = () => {
    if (!newNote.trim()) return;
    setLog(prev => ({ ...prev, notes: [...prev.notes, newNote] }));
    setNewNote("");
  };

  const addMujahadaNote = () => {
    if (!newMujahadaNote.trim()) return;
    setLog(prev => ({ ...prev, mujahadaNotes: [...prev.mujahadaNotes, newMujahadaNote] }));
    setNewMujahadaNote("");
  };

  const deleteNote = (index: number) => {
    setLog(prev => ({ ...prev, notes: prev.notes.filter((_, i) => i !== index) }));
  };

  const deleteMujahadaNote = (index: number) => {
    setLog(prev => ({ ...prev, mujahadaNotes: prev.mujahadaNotes.filter((_, i) => i !== index) }));
  };

  const score = useMemo(() => {
    const positiveCount = log.prayers.length + log.azkar.length + log.goodDeeds.length + log.notes.length;
    const negativeCount = log.mujahada.length + log.mujahadaNotes.length;
    return (positiveCount * 10) - (negativeCount * 10);
  }, [log]);

  const quranProgress = useMemo(() => {
    const pagesReadToday = Math.max(0, log.quranEnd - log.quranStart);
    const totalRemaining = 604 - log.quranEnd;
    const percentage = (log.quranEnd / 604) * 100;

    // Prediction Logic
    const daysLeft = dailyGoal > 0 ? Math.ceil(totalRemaining / dailyGoal) : 0;
    const completionDate = new Date();
    completionDate.setDate(completionDate.getDate() + daysLeft);

    const formattedCompletion = new Intl.DateTimeFormat('ar-SA-u-ca-islamic-uma-nu-latn', {
      day: 'numeric',
      month: 'long'
    }).format(completionDate);

    return { pagesReadToday, totalRemaining, percentage, daysLeft, formattedCompletion };
  }, [log.quranStart, log.quranEnd, dailyGoal]);

  return (
    <div className="space-y-6 pb-12 animate-fade-in relative">

      {/* Visual Decor */}
      <div className="hidden md:block absolute -left-20 top-40 opacity-10 dark:opacity-5 animate-swing pointer-events-none">
        <i className="fas fa-mosque text-9xl text-yellow-600"></i>
      </div>

      {/* Motivational Quote */}
      <div className="bg-white dark:bg-[#1a1a1a] border border-yellow-600/20 dark:border-yellow-900/30 p-8 rounded-3xl relative overflow-hidden group shadow-xl">
        <div className="absolute top-0 right-0 w-48 h-48 bg-yellow-500/5 rounded-full -mr-24 -mt-24 blur-3xl"></div>
        <div className="relative z-10 text-center">
          <i className="fas fa-hands-praying text-[#d4af37] text-3xl mb-4 opacity-40"></i>
          <p className="text-2xl md:text-3xl font-bold text-slate-800 dark:text-gray-100 leading-snug quran-font">
            "{quote.text}"
          </p>
          <div className="mt-6 flex items-center justify-center gap-3">
            <span className="h-[1px] w-12 bg-gray-200 dark:bg-gray-800"></span>
            <span className="text-sm text-yellow-700 dark:text-yellow-600 font-black uppercase tracking-wider">{quote.source}</span>
            <span className="h-[1px] w-12 bg-gray-200 dark:bg-gray-800"></span>
          </div>
        </div>
      </div>

      {/* Daily Score Summary */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'نقاط اليوم', value: score, highlight: true, icon: 'fa-star' },
          { label: 'ختمة القرآن', value: `${Math.round(quranProgress.percentage)}%`, highlight: false, icon: 'fa-book-open' },
          { label: 'العبادات', value: log.prayers.length + log.azkar.length, highlight: false, icon: 'fa-pray' },
          { label: 'أعمال خير', value: log.goodDeeds.length + log.notes.length, highlight: false, icon: 'fa-heart' },
        ].map((stat, idx) => (
          <div key={idx} className="bg-white dark:bg-[#151515] p-5 rounded-2xl border border-gray-100 dark:border-gray-800 flex flex-col items-center justify-center shadow-sm dark:shadow-inner hover:scale-105 transition-transform">
            <i className={`fas ${stat.icon} text-[10px] text-yellow-600/40 mb-1`}></i>
            <span className="text-gray-400 dark:text-gray-500 text-[9px] mb-1 font-black tracking-widest uppercase">{stat.label}</span>
            <span className={`text-3xl font-black ${stat.highlight ? 'text-yellow-600 dark:text-[#d4af37]' : 'text-slate-800 dark:text-gray-200'}`}>{stat.value}</span>
          </div>
        ))}
      </div>

      {/* Sections Grid */}
      <div className="grid md:grid-cols-2 gap-6">

        {/* Prayers */}
        <SectionCard title="قسم الصلاة" icon="fa-mosque" infoItems={getDailyInfo('PRAYER')}>
          <div className="grid grid-cols-2 gap-3">
            {PRAYER_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-3 rounded-xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-yellow-50 dark:hover:bg-[#222] transition-all border border-transparent hover:border-yellow-200 dark:hover:border-gray-800">
                <input 
                  type="checkbox" 
                  checked={log.prayers.includes(task.id)}
                  onChange={() => toggleTask('prayers', task.id)}
                  className="w-5 h-5 rounded border-gray-300 dark:border-gray-700 text-yellow-600 bg-white dark:bg-gray-900 focus:ring-yellow-500"
                />
                <span className={`text-sm font-bold ${log.prayers.includes(task.id) ? 'text-yellow-600 line-through opacity-70' : 'text-slate-700 dark:text-gray-300'}`}>
                  {task.label}
                </span>
              </label>
            ))}
          </div>
        </SectionCard>

        {/* Azkar */}
        <SectionCard title="قسم الأذكار" icon="fa-hands-praying" infoItems={getDailyInfo('AZKAR')}>
          <div className="grid grid-cols-2 gap-3">
            {AZKAR_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-3 rounded-xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-yellow-50 dark:hover:bg-[#222] transition-all border border-transparent hover:border-yellow-200 dark:hover:border-gray-800">
                <input 
                  type="checkbox" 
                  checked={log.azkar.includes(task.id)}
                  onChange={() => toggleTask('azkar', task.id)}
                  className="w-5 h-5 rounded border-gray-300 dark:border-gray-700 text-yellow-600 bg-white dark:bg-gray-900 focus:ring-yellow-500"
                />
                <span className={`text-sm font-bold ${log.azkar.includes(task.id) ? 'text-yellow-600 line-through opacity-70' : 'text-slate-700 dark:text-gray-300'}`}>
                  {task.label}
                </span>
              </label>
            ))}
          </div>
        </SectionCard>

        {/* Quran with Prediction */}
        <SectionCard title="ختمة القرآن" icon="fa-book-quran" infoItems={getDailyInfo('QURAN')}>
          <div className="space-y-6">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] text-gray-500 block font-black uppercase">من صفحة</label>
                <input 
                  type="number" 
                  value={log.quranStart || ""}
                  onChange={(e) => handleQuranChange('quranStart', e.target.value)}
                  className="w-full bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-xl p-3 text-center text-yellow-600 font-black focus:outline-none focus:ring-2 focus:ring-yellow-500/20"
                  placeholder="0"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] text-gray-500 block font-black uppercase">إلى صفحة</label>
                <input 
                  type="number" 
                  value={log.quranEnd || ""}
                  onChange={(e) => handleQuranChange('quranEnd', e.target.value)}
                  className="w-full bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-xl p-3 text-center text-yellow-600 font-black focus:outline-none focus:ring-2 focus:ring-yellow-500/20"
                  placeholder="0"
                />
              </div>
            </div>

            {/* Daily Goal & Prediction */}
            <div className="bg-gradient-to-br from-yellow-50 to-white dark:from-[#1a1a1a] dark:to-[#111] p-5 rounded-2xl border border-yellow-100 dark:border-yellow-900/20 shadow-inner">
               <div className="flex items-center justify-between mb-4">
                  <div className="flex flex-col">
                    <span className="text-xs font-black text-slate-800 dark:text-gray-200">الورد اليومي المستهدف</span>
                    <span className="text-[10px] text-gray-400">كم صفحة تنوي قراءتها يومياً؟</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <input 
                      type="number"
                      value={dailyGoal}
                      onChange={(e) => setDailyGoal(Math.max(1, parseInt(e.target.value) || 0))}
                      className="w-16 bg-white dark:bg-[#222] border border-gray-200 dark:border-gray-800 rounded-lg p-1 text-center font-black text-yellow-600 focus:ring-1 focus:ring-yellow-500 outline-none"
                    />
                    <span className="text-[10px] font-bold text-gray-500">صفحة</span>
                  </div>
               </div>

               {dailyGoal > 0 && (
                 <div className="flex items-center gap-4 pt-4 border-t border-yellow-200/30 dark:border-yellow-900/10">
                    <div className="flex-1 text-center p-2 bg-white/50 dark:bg-black/20 rounded-xl">
                      <p className="text-lg font-black text-yellow-600">{quranProgress.daysLeft}</p>
                      <p className="text-[9px] text-gray-400 font-bold uppercase">أيام متبقية</p>
                    </div>
                    <div className="flex-[2] text-center p-2 bg-yellow-600 text-white rounded-xl shadow-md">
                      <p className="text-sm font-black">{quranProgress.formattedCompletion}</p>
                      <p className="text-[9px] opacity-80 font-bold uppercase">التاريخ المتوقع للختم</p>
                    </div>
                 </div>
               )}
            </div>

            <div className="bg-gray-50 dark:bg-[#1a1a1a] p-4 rounded-2xl border border-gray-100 dark:border-gray-800 flex justify-between items-center">
              <div className="text-center flex-1 border-l border-gray-200 dark:border-gray-800">
                <p className="text-2xl font-black text-slate-800 dark:text-gray-200">{quranProgress.pagesReadToday}</p>
                <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest">صفحات اليوم</p>
              </div>
              <div className="text-center flex-1">
                <p className="text-2xl font-black text-yellow-600">{quranProgress.totalRemaining}</p>
                <p className="text-[10px] text-gray-500 font-black uppercase tracking-widest">متبقي للختمة</p>
              </div>
            </div>

            <div className="space-y-2">
              <div className="flex justify-between text-[10px] text-gray-500 font-black uppercase px-1">
                <span>التقدم الإجمالي</span>
                <span>{Math.round(quranProgress.percentage)}%</span>
              </div>
              <div className="w-full h-3 bg-gray-200 dark:bg-gray-900 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-gradient-to-r from-yellow-600 to-yellow-400 rounded-full transition-all duration-1000 ease-out shadow-[0_0_10px_rgba(212,175,55,0.4)]"
                  style={{ width: `${quranProgress.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>
        </SectionCard>

        {/* Mujahada */}
        <SectionCard title="مجاهدة النفس" icon="fa-shield-halved" infoItems={getDailyInfo('MUJAHADA')} defaultOpen={false}>
          <p className="text-[10px] text-red-600/80 mb-3 text-center bg-red-50 dark:bg-red-900/10 py-2 rounded-lg font-black border border-red-100 dark:border-red-900/20 uppercase tracking-widest">اختر ما وقعت فيه اليوم (يخصم 10 نقاط)</p>
          <div className="space-y-3 mb-4">
            {MUJAHADA_TASKS.map(task => (
              <label key={task.id} className="flex items-start gap-3 p-3 rounded-xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-red-50 dark:hover:bg-red-900/5 border border-transparent hover:border-red-200 dark:hover:border-red-900/30 transition-all">
                <input 
                  type="checkbox" 
                  checked={log.mujahada.includes(task.id)}
                  onChange={() => toggleTask('mujahada', task.id)}
                  className="w-5 h-5 mt-0.5 rounded border-gray-300 dark:border-gray-700 text-red-600 bg-white dark:bg-gray-900"
                />
                <div className="flex flex-col">
                  <span className={`text-sm font-bold ${log.mujahada.includes(task.id) ? 'text-red-600' : 'text-slate-700 dark:text-gray-300'}`}>
                    {task.label}
                  </span>
                  <span className="text-[10px] text-gray-500 leading-tight mt-0.5">{task.description}</span>
                </div>
              </label>
            ))}
          </div>

          <div className="pt-3 border-t border-gray-100 dark:border-gray-800">
              <div className="flex gap-2 mb-3">
                <input 
                  type="text" 
                  value={newMujahadaNote}
                  onChange={(e) => setNewMujahadaNote(e.target.value)}
                  placeholder="أضف زلة أخرى..."
                  className="flex-grow bg-white dark:bg-[#222] border border-gray-200 dark:border-gray-800 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-1 focus:ring-red-500"
                />
                <button 
                  onClick={addMujahadaNote}
                  className="bg-red-600 dark:bg-red-900/40 hover:bg-red-700 dark:hover:bg-red-900/60 text-white dark:text-red-500 w-10 h-10 rounded-xl transition-all shadow-md flex items-center justify-center border border-red-200 dark:border-red-900/50"
                >
                  <i className="fas fa-plus"></i>
                </button>
              </div>
              <ul className="space-y-2">
                {log.mujahadaNotes.map((note, idx) => (
                  <li key={idx} className="flex items-center justify-between text-xs bg-red-50 dark:bg-red-900/5 p-3 rounded-xl border border-red-100 dark:border-red-900/20 animate-slide-in">
                    <span className="text-red-700 dark:text-red-400 font-bold">{note}</span>
                    <button onClick={() => deleteMujahadaNote(idx)} className="text-gray-400 hover:text-red-600 transition-colors">
                      <i className="fas fa-trash-can"></i>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
        </SectionCard>

        {/* Good Deeds */}
        <SectionCard title="أعمال الخير" icon="fa-heart" infoItems={getDailyInfo('GOOD_DEEDS')} defaultOpen={false}>
          <div className="space-y-3">
             <div className="grid grid-cols-1 gap-2">
