                  </div>
                </label>
              ))}
            </div>

            <div className="pt-3 border-t border-gray-100 dark:border-gray-800">
              <div className="flex gap-2 mb-3">
                <input 
                  type="text" 
                  value={newNote}
                  onChange={(e) => setNewNote(e.target.value)}
                  placeholder="أضف عمل خير آخر..."
                  className="flex-grow bg-white dark:bg-[#222] border border-gray-200 dark:border-gray-800 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-1 focus:ring-yellow-500"
                />
                <button 
                  onClick={addNote}
                  className="bg-yellow-600 hover:bg-yellow-700 text-white w-10 h-10 rounded-xl transition-all shadow-md flex items-center justify-center"
                >
                  <i className="fas fa-plus"></i>
                </button>
              </div>
              <ul className="space-y-2">
                {log.notes.map((note, idx) => (
                  <li key={idx} className="flex items-center justify-between text-xs bg-emerald-50 dark:bg-[#1a1a1a] p-3 rounded-xl border border-emerald-100 dark:border-gray-800 animate-slide-in">
                    <span className="text-emerald-700 dark:text-gray-300 font-bold">{note}</span>
                    <button onClick={() => deleteNote(idx)} className="text-gray-400 hover:text-red-500 transition-colors">
                      <i className="fas fa-trash-can"></i>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </SectionCard>

      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';

interface InfoItem {
  type: string;
  text: string;
}

interface SectionCardProps {
  title: string;
  icon: string;
  children: React.ReactNode;
  infoItems?: InfoItem[];
  defaultOpen?: boolean;
}

const SectionCard: React.FC<SectionCardProps> = ({ title, icon, children, infoItems, defaultOpen = false }) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);

  return (
    <div className="bg-white dark:bg-[#151515] border border-gray-200 dark:border-gray-800 rounded-2xl overflow-hidden transition-all hover:border-yellow-700/30 group shadow-md dark:shadow-lg">
      <div 
        className="p-4 flex items-center justify-between border-b border-gray-100 dark:border-gray-800 bg-gray-50/50 dark:bg-[#1a1a1a] cursor-pointer"
        onClick={() => setIsOpen(!isOpen)}
      >
        <div className="flex items-center gap-3 flex-grow">
          <div className="w-10 h-10 rounded-full bg-white dark:bg-[#222] flex items-center justify-center text-[#d4af37] border border-gray-200 dark:border-gray-800 group-hover:border-yellow-600/50 transition-colors shadow-sm">
            <i className={`fas ${icon} text-lg ${isOpen ? 'animate-pulse' : ''}`}></i>
          </div>
          <div className="flex flex-col">
             <h3 className="text-lg font-bold text-slate-800 dark:text-gray-100">{title}</h3>
             <span className="text-[10px] text-gray-500 dark:text-gray-500 font-bold tracking-tight">
               {isOpen ? 'انقر لإغلاق القسم' : 'انقر للتفاصيل والمهام'}
             </span>
          </div>
        </div>

        <div className="flex items-center gap-2">
          <div className={`w-8 h-8 rounded-full flex items-center justify-center text-gray-400 dark:text-gray-500 group-hover:text-yellow-600 bg-gray-100 dark:bg-[#222] transition-all ${isOpen ? 'rotate-180' : ''}`}>
            <i className={`fas fa-chevron-down text-xs`}></i>
          </div>
        </div>
      </div>

      <div className={`transition-all duration-500 ease-in-out ${isOpen ? 'max-h-[3000px] opacity-100' : 'max-h-0 opacity-0 overflow-hidden'}`}>
        {/* Religious Info */}
        {infoItems && infoItems.length > 0 && (
          <div className="bg-yellow-50/30 dark:bg-[#1a1a1a] border-b border-gray-100 dark:border-gray-800/50">
            {infoItems.map((info, idx) => (
              <div key={idx} className="p-5">
                <div className="flex items-center gap-2 mb-2">
                  <div className="w-1.5 h-1.5 rounded-full bg-yellow-600"></div>
                  <span className="text-[10px] font-bold px-2 py-0.5 rounded bg-yellow-600/10 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-500 uppercase tracking-tighter">
                    {info.type} اليوم
                  </span>
                </div>
                <p className="quran-font text-slate-700 dark:text-gray-200 text-xl leading-relaxed text-right pr-4 border-r-2 border-yellow-600/30 dark:border-yellow-800/30 italic">
                  {info.text}
                </p>
              </div>
            ))}
          </div>
        )}

        <div className="p-5 dark:text-gray-300">
          {children}
        </div>
      </div>
    </div>
  );
};

export default SectionCard;

