const App: React.FC = () => {
  const [isDarkMode, setIsDarkMode] = useState(() => {
    const saved = localStorage.getItem('theme');
    return saved ? saved === 'dark' : true;
  });

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  return (
    <HashRouter>
      <div className="min-h-screen flex flex-col pb-24 md:pb-12 md:pt-20 theme-transition overflow-x-hidden">
        <Header />
        <main className="flex-grow max-w-4xl mx-auto w-full px-4 relative">
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/history" element={<History />} />
          </Routes>
        </main>
        <Navigation isDarkMode={isDarkMode} toggleTheme={toggleTheme} />
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  PRAYER_TASKS, 
  AZKAR_TASKS, 
  GOOD_DEED_TASKS, 
  MUJAHADA_TASKS, 
  MOTIVATIONAL_QUOTES,
  SECTION_INFO
} from '../constants';
import { getLogForDate, saveLog, formatDate } from '../services/storageService';
import SectionCard from '../components/SectionCard';
import { DailyLog } from '../types';

const Dashboard: React.FC = () => {
  const [currentDate] = useState(formatDate(new Date()));
  const [log, setLog] = useState<DailyLog>(getLogForDate(currentDate));
  const [newNote, setNewNote] = useState("");
  const [newMujahadaNote, setNewMujahadaNote] = useState("");

  // Quran Goal State
  const [dailyGoal, setDailyGoal] = useState(() => {
    return parseInt(localStorage.getItem('quran_daily_goal') || "20");
  });

  const dailyRotationIndex = useMemo(() => {
    const d = new Date();
    return d.getDate();
  }, []);

  const quote = useMemo(() => {
    return MOTIVATIONAL_QUOTES[dailyRotationIndex % MOTIVATIONAL_QUOTES.length];
  }, [dailyRotationIndex]);

  const getDailyInfo = (section: keyof typeof SECTION_INFO) => {
    const list = SECTION_INFO[section];
    return [list[dailyRotationIndex % list.length]];
  };

  useEffect(() => {
    saveLog(log);
  }, [log]);

  useEffect(() => {
    localStorage.setItem('quran_daily_goal', dailyGoal.toString());
  }, [dailyGoal]);

  const toggleTask = (section: keyof DailyLog, id: string) => {
    setLog(prev => {
      const currentList = prev[section] as string[];
      const newList = currentList.includes(id) 
        ? currentList.filter(item => item !== id)
        : [...currentList, id];
      return { ...prev, [section]: newList };
    });
  };

  const handleQuranChange = (field: 'quranStart' | 'quranEnd', value: string) => {
    const num = Math.min(604, Math.max(0, parseInt(value) || 0));
    setLog(prev => ({ ...prev, [field]: num }));
  };

  const addNote = () => {
    if (!newNote.trim()) return;
    setLog(prev => ({ ...prev, notes: [...prev.notes, newNote] }));
    setNewNote("");
  };

  const addMujahadaNote = () => {
    if (!newMujahadaNote.trim()) return;
    setLog(prev => ({ ...prev, mujahadaNotes: [...prev.mujahadaNotes, newMujahadaNote] }));
    setNewMujahadaNote("");
  };

  const deleteNote = (index: number) => {
    setLog(prev => ({ ...prev, notes: prev.notes.filter((_, i) => i !== index) }));
  };

  const deleteMujahadaNote = (index: number) => {
    setLog(prev => ({ ...prev, mujahadaNotes: prev.mujahadaNotes.filter((_, i) => i !== index) }));
  };

  const score = useMemo(() => {
    const positiveCount = log.prayers.length + log.azkar.length + log.goodDeeds.length + log.notes.length;
    const negativeCount = log.mujahada.length + log.mujahadaNotes.length;
    return (positiveCount * 10) - (negativeCount * 10);
  }, [log]);

  const quranProgress = useMemo(() => {
    const pagesReadToday = Math.max(0, log.quranEnd - log.quranStart);
    const totalRemaining = 604 - log.quranEnd;
    const percentage = (log.quranEnd / 604) * 100;

    // Prediction Logic
    const daysLeft = dailyGoal > 0 ? Math.ceil(totalRemaining / dailyGoal) : 0;
    const completionDate = new Date();
    completionDate.setDate(completionDate.getDate() + daysLeft);

    let formattedCompletion = "غير محدد";
    try {
      formattedCompletion = new Intl.DateTimeFormat('ar-SA-u-ca-islamic-uma-nu-latn', {
        day: 'numeric',
        month: 'long',
        year: 'numeric'
      }).format(completionDate);
    } catch (e) {
      formattedCompletion = completionDate.toLocaleDateString('ar-EG');
    }

    return { pagesReadToday, totalRemaining, percentage, daysLeft, formattedCompletion };
  }, [log.quranStart, log.quranEnd, dailyGoal]);

  return (
    <div className="space-y-6 pb-12 animate-fade-in relative">

      {/* Visual Decor Background Element */}
      <div className="hidden lg:block absolute -right-32 top-1/4 opacity-10 dark:opacity-5 animate-float pointer-events-none">
        <i className="fas fa-mosque text-[15rem] text-yellow-600"></i>
      </div>

      {/* Motivational Quote Card */}
      <div className="bg-white dark:bg-[#1a1a1a] border border-yellow-600/30 dark:border-yellow-900/40 p-10 rounded-[2.5rem] relative overflow-hidden group shadow-2xl">
        <div className="absolute top-0 right-0 w-64 h-64 bg-yellow-500/10 rounded-full -mr-32 -mt-32 blur-[100px]"></div>
        <div className="relative z-10 text-center">
          <i className="fas fa-quote-right text-[#d4af37] text-4xl mb-6 opacity-30"></i>
          <p className="text-2xl md:text-4xl font-bold text-slate-800 dark:text-gray-100 leading-relaxed quran-font">
            {quote.text}
          </p>
          <div className="mt-8 flex items-center justify-center gap-4">
            <div className="h-[2px] w-16 bg-gradient-to-l from-transparent to-yellow-500/40"></div>
            <span className="text-sm text-yellow-700 dark:text-yellow-500 font-black uppercase tracking-widest">{quote.source}</span>
            <div className="h-[2px] w-16 bg-gradient-to-r from-transparent to-yellow-500/40"></div>
          </div>
        </div>
      </div>

      {/* Stats Quick View */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {[
          { label: 'نقاط اليوم', value: score, highlight: true, icon: 'fa-star' },
          { label: 'تقدم الختمة', value: `${Math.round(quranProgress.percentage)}%`, highlight: false, icon: 'fa-book-quran' },
          { label: 'إجمالي الطاعات', value: log.prayers.length + log.azkar.length, highlight: false, icon: 'fa-pray' },
          { label: 'أعمال البر', value: log.goodDeeds.length + log.notes.length, highlight: false, icon: 'fa-heart' },
        ].map((stat, idx) => (
          <div key={idx} className="bg-white dark:bg-[#151515] p-6 rounded-3xl border border-gray-100 dark:border-gray-800 flex flex-col items-center justify-center shadow-lg hover:shadow-yellow-500/10 hover:-translate-y-1 transition-all duration-300">
            <i className={`fas ${stat.icon} text-xs text-yellow-600/50 mb-2`}></i>
            <span className="text-gray-400 dark:text-gray-500 text-[10px] mb-1 font-black tracking-widest uppercase">{stat.label}</span>
            <span className={`text-4xl font-black ${stat.highlight ? 'gold-gradient' : 'text-slate-800 dark:text-gray-100'}`}>{stat.value}</span>
          </div>
        ))}
      </div>

      {/* Sections Grid - All Folded by Default */}
      <div className="grid md:grid-cols-2 gap-6">

        {/* Quran with Detailed Prediction and Ward Option */}
        <SectionCard title="ورد القرآن الكريم" icon="fa-book-open-reader" infoItems={getDailyInfo('QURAN')} defaultOpen={false}>
          <div className="space-y-6">
            <div className="bg-yellow-50/50 dark:bg-yellow-900/10 p-4 rounded-2xl border border-yellow-100 dark:border-yellow-900/20 mb-4">
               <div className="flex flex-col gap-3">
                  <div className="flex items-center justify-between">
                    <span className="text-xs font-black text-yellow-800 dark:text-yellow-400">الورد اليومي المستهدف (بالصفحات)</span>
                    <div className="flex items-center gap-2">
                      <button onClick={() => setDailyGoal(Math.max(1, dailyGoal - 1))} className="w-8 h-8 rounded-lg bg-white dark:bg-[#222] border border-gray-200 dark:border-gray-800 text-yellow-600">-</button>
                      <input 
                        type="number"
                        value={dailyGoal}
                        onChange={(e) => setDailyGoal(Math.max(1, parseInt(e.target.value) || 1))}
                        className="w-14 bg-white dark:bg-[#222] border border-gray-200 dark:border-gray-800 rounded-lg p-1 text-center font-black text-yellow-600 outline-none"
                      />
                      <button onClick={() => setDailyGoal(dailyGoal + 1)} className="w-8 h-8 rounded-lg bg-white dark:bg-[#222] border border-gray-200 dark:border-gray-800 text-yellow-600">+</button>
                    </div>
                  </div>
               </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] text-gray-500 block font-black uppercase pr-2">من صفحة</label>
                <input 
                  type="number" 
                  value={log.quranStart || ""}
                  onChange={(e) => handleQuranChange('quranStart', e.target.value)}
                  className="w-full bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-xl p-4 text-center text-yellow-600 font-black focus:ring-2 focus:ring-yellow-500/20"
                  placeholder="0"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] text-gray-500 block font-black uppercase pr-2">إلى صفحة</label>
                <input 
                  type="number" 
                  value={log.quranEnd || ""}
                  onChange={(e) => handleQuranChange('quranEnd', e.target.value)}
                  className="w-full bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-xl p-4 text-center text-yellow-600 font-black focus:ring-2 focus:ring-yellow-500/20"
                  placeholder="0"
                />
              </div>
            </div>

            {dailyGoal > 0 && (
              <div className="bg-gradient-to-r from-yellow-600 to-yellow-700 p-5 rounded-2xl text-white shadow-lg relative overflow-hidden">
                <div className="absolute top-0 right-0 opacity-10 -mr-4 -mt-4">
                   <i className="fas fa-calendar-check text-7xl"></i>
                </div>
                <div className="relative z-10 flex flex-col items-center">
                  <span className="text-[10px] font-black uppercase tracking-widest opacity-80 mb-1">الموعد المتوقع للختمة</span>
                  <p className="text-xl font-black">{quranProgress.formattedCompletion}</p>
                  <div className="mt-3 text-[11px] bg-white/20 px-4 py-1 rounded-full font-bold">
                    متبقي {quranProgress.daysLeft} يوماً بمعدل وردك الحالي
                  </div>
                </div>
              </div>
            )}

            <div className="space-y-2 pt-2">
              <div className="flex justify-between text-[10px] text-gray-500 font-black uppercase px-1">
                <span>التقدم في المصحف</span>
                <span>{Math.round(quranProgress.percentage)}%</span>
              </div>
              <div className="w-full h-4 bg-gray-100 dark:bg-black/30 rounded-full overflow-hidden p-0.5 border border-gray-200 dark:border-gray-800">
                <div 
                  className="h-full bg-gradient-to-r from-yellow-600 via-yellow-400 to-yellow-600 rounded-full transition-all duration-1000 ease-out shadow-[0_0_15px_rgba(212,175,55,0.5)]"
                  style={{ width: `${quranProgress.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>
        </SectionCard>

        {/* Prayers */}
        <SectionCard title="قسم الصلاة" icon="fa-mosque" infoItems={getDailyInfo('PRAYER')} defaultOpen={false}>
          <div className="grid grid-cols-2 gap-3">
            {PRAYER_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-4 rounded-2xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-yellow-50 dark:hover:bg-[#222] transition-all border border-transparent hover:border-yellow-200 dark:hover:border-gray-800">
                <input 
                  type="checkbox" 
                  checked={log.prayers.includes(task.id)}
                  onChange={() => toggleTask('prayers', task.id)}
                  className="w-5 h-5 rounded-lg border-gray-300 dark:border-gray-700 text-yellow-600 focus:ring-yellow-500"
                />
                <span className={`text-sm font-bold ${log.prayers.includes(task.id) ? 'text-yellow-600 line-through opacity-60' : 'text-slate-700 dark:text-gray-200'}`}>
                  {task.label}
                </span>
              </label>
            ))}
          </div>
        </SectionCard>

        {/* Azkar */}
        <SectionCard title="قسم الأذكار" icon="fa-hands-praying" infoItems={getDailyInfo('AZKAR')} defaultOpen={false}>
          <div className="grid grid-cols-2 gap-3">
            {AZKAR_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-4 rounded-2xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-purple-50 dark:hover:bg-[#222] transition-all border border-transparent hover:border-purple-200 dark:hover:border-gray-800">
                <input 
                  type="checkbox" 
                  checked={log.azkar.includes(task.id)}
                  onChange={() => toggleTask('azkar', task.id)}
                  className="w-5 h-5 rounded-lg border-gray-300 dark:border-gray-700 text-purple-600 focus:ring-purple-500"
                />
                <span className={`text-sm font-bold ${log.azkar.includes(task.id) ? 'text-purple-600 line-through opacity-60' : 'text-slate-700 dark:text-gray-200'}`}>
                  {task.label}
                </span>
              </label>
            ))}
          </div>
        </SectionCard>

        {/* Good Deeds */}
        <SectionCard title="أعمال البر والخير" icon="fa-heart-pulse" infoItems={getDailyInfo('GOOD_DEEDS')} defaultOpen={false}>
           <div className="space-y-4">
              <div className="grid gap-2">
                {GOOD_DEED_TASKS.slice(0, 8).map(task => (
                  <label key={task.id} className="flex items-start gap-4 p-4 rounded-2xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-emerald-50 dark:hover:bg-[#222] transition-all border border-transparent hover:border-emerald-200 dark:hover:border-gray-800">
                    <input 
                      type="checkbox" 
                      checked={log.goodDeeds.includes(task.id)}
                      onChange={() => toggleTask('goodDeeds', task.id)}
                      className="w-6 h-6 mt-0.5 rounded-lg border-gray-300 dark:border-gray-700 text-emerald-600"
                    />
                    <div className="flex flex-col">
                      <span className={`text-sm font-bold ${log.goodDeeds.includes(task.id) ? 'text-emerald-600' : 'text-slate-700 dark:text-gray-200'}`}>
                        {task.label}
                      </span>
                      <span className="text-[10px] text-gray-500 leading-tight mt-1">{task.description}</span>
                    </div>
                  </label>
                ))}
              </div>
              <div className="pt-4 border-t border-gray-100 dark:border-gray-800">
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    value={newNote}
                    onChange={(e) => setNewNote(e.target.value)}
                    placeholder="أضف عمل خير آخر قمت به..."
                    className="flex-grow bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-2xl px-5 py-3 text-sm focus:ring-2 focus:ring-yellow-500/20 outline-none"
                  />
                  <button onClick={addNote} className="bg-yellow-600 hover:bg-yellow-700 text-white w-12 h-12 rounded-2xl shadow-lg transition-all flex items-center justify-center">
                    <i className="fas fa-plus"></i>
                  </button>
                </div>
              </div>
           </div>
        </SectionCard>

        {/* Mujahada */}
        <SectionCard title="مجاهدة النفس" icon="fa-shield-halved" infoItems={getDailyInfo('MUJAHADA')} defaultOpen={false}>
          <div className="space-y-4">
