      <div className="mt-12 text-center p-8 bg-gradient-to-b from-transparent to-yellow-600/5 dark:to-yellow-900/10 rounded-t-[3rem] border-t border-yellow-200/20 dark:border-yellow-900/20">
         <i className="fas fa-mosque text-yellow-600/20 text-5xl mb-4 block"></i>
         <p className="text-gray-500 dark:text-gray-400 font-bold tracking-widest text-xs uppercase italic">"وَمَن يُعَظِّمْ شَعَائِرَ اللَّهِ فَإِنَّهَا مِن تَقْوَى الْقُلُوبِ"</p>
      </div>
    </div>
  );
};

export default Dashboard;

