        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-right min-w-[1100px]">
            <thead>
              <tr className="bg-gray-50 dark:bg-[#1a1a1a] text-[10px] text-gray-500 uppercase font-black border-b border-gray-100 dark:border-gray-800">
                <th className="px-5 py-4 w-44">اليوم والتاريخ</th>
                <th className="px-5 py-4">الصلوات</th>
                <th className="px-5 py-4">الأذكار</th>
                <th className="px-5 py-4">القرآن</th>
                <th className="px-5 py-4">أعمال البر (تفاصيل)</th>
                <th className="px-5 py-4">المجاهدة (تفاصيل)</th>
                <th className="px-5 py-4 text-center">النتيجة</th>
