            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
              {filteredDates.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-5 py-20 text-center text-gray-400 font-bold italic">لا توجد بيانات مسجلة في هذه الفترة</td>
                </tr>
              ) : (
                filteredDates.map(date => {
                  const log = logs[date];
                  const score = calculateScore(log);
                  return (
                    <tr key={date} className="hover:bg-gray-50/50 dark:hover:bg-[#1a1a1a] transition-colors group">
                      {/* Date Info */}
                      <td className="px-5 py-5">
                        <div className="flex flex-col">
                          <span className="text-xs font-black text-slate-800 dark:text-gray-200">
                            {formatArabicDate(date)}
                          </span>
                          <span className="text-[9px] text-gray-400 font-bold mt-1">
                            {formatArabicDate(date, !isHijriMode)}
                          </span>
                        </div>
                      </td>

                      {/* Prayer Icons/Mini-labels */}
                      <td className="px-5 py-5">
                        <div className="flex flex-wrap gap-1 max-w-[160px]">
                          {log.prayers.length > 0 ? log.prayers.map(p => (
                            <span key={p} className="text-[9px] px-2 py-0.5 rounded bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 font-black border border-blue-100 dark:border-blue-900/30">
                              {getTaskLabel(p, 'prayer')}
                            </span>
                          )) : <i className="fas fa-minus text-gray-200 dark:text-gray-800"></i>}
                        </div>
                      </td>

                      {/* Azkar Mini-labels */}
                      <td className="px-5 py-5">
                        <div className="flex flex-wrap gap-1 max-w-[160px]">
                          {log.azkar.length > 0 ? log.azkar.map(a => (
                            <span key={a} className="text-[9px] px-2 py-0.5 rounded bg-purple-50 dark:bg-purple-900/20 text-purple-600 dark:text-purple-400 font-black border border-purple-100 dark:border-purple-900/30">
                              {getTaskLabel(a, 'azkar')}
                            </span>
                          )) : <i className="fas fa-minus text-gray-200 dark:text-gray-800"></i>}
                        </div>
                      </td>

                      {/* Quran Range */}
                      <td className="px-5 py-5">
                        <div className="flex flex-col items-center bg-gray-50 dark:bg-[#222] px-3 py-1.5 rounded-xl border border-gray-100 dark:border-gray-800 w-fit">
                          <span className="text-xs font-black text-yellow-700 dark:text-yellow-500">
                             {log.quranEnd > 0 ? `${log.quranStart} ↩ ${log.quranEnd}` : 'لم يبدأ'}
                          </span>
                          {log.quranEnd > 0 && <span className="text-[8px] text-gray-400 font-bold uppercase">صفحة</span>}
                        </div>
                      </td>

                      {/* Good Deeds - DETAILED */}
                      <td className="px-5 py-5">
                        <div className="flex flex-wrap gap-1 max-w-[220px]">
                          {log.goodDeeds.length > 0 || log.notes.length > 0 ? (
                            <>
                              {log.goodDeeds.map(d => (
                                <span key={d} className="text-[9px] px-2 py-0.5 rounded bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 font-black border border-emerald-100 dark:border-emerald-900/30">
                                  {getTaskLabel(d, 'deed')}
                                </span>
                              ))}
                              {log.notes.map((n, i) => (
                                <span key={i} className="text-[9px] px-2 py-0.5 rounded bg-emerald-100/50 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-300 font-bold border border-emerald-200 dark:border-emerald-800">
                                  {n}
                                </span>
                              ))}
                            </>
                          ) : <i className="fas fa-minus text-gray-200 dark:text-gray-800"></i>}
                        </div>
                      </td>

                      {/* Mujahada - DETAILED */}
                      <td className="px-5 py-5">
                        <div className="flex flex-wrap gap-1 max-w-[220px]">
                          {log.mujahada.length > 0 || log.mujahadaNotes.length > 0 ? (
                            <>
                              {log.mujahada.map(m => (
                                <span key={m} className="text-[9px] px-2 py-0.5 rounded bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 font-black border border-red-100 dark:border-red-900/30">
                                  {getTaskLabel(m, 'mujahada')}
                                </span>
                              ))}
                              {log.mujahadaNotes.map((mn, i) => (
                                <span key={i} className="text-[9px] px-2 py-0.5 rounded bg-red-100/50 dark:bg-red-900/40 text-red-700 dark:text-red-300 font-bold border border-red-200 dark:border-red-800">
                                  {mn}
                                </span>
                              ))}
                            </>
                          ) : <i className="fas fa-minus text-gray-200 dark:text-gray-800"></i>}
                        </div>
                      </td>

                      {/* Score Result */}
                      <td className="px-5 py-5 text-center">
                        <span className={`inline-block px-4 py-2 rounded-xl text-xs font-black shadow-sm border transition-transform group-hover:scale-105 ${score >= 0 ? 'bg-emerald-500 text-white border-emerald-400' : 'bg-red-500 text-white border-red-400'}`}>
                          {score > 0 ? `+${score}` : score}
                        </span>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="bg-yellow-600/5 dark:bg-yellow-900/5 p-6 text-center text-gray-500 dark:text-gray-400 text-xs font-bold rounded-2xl border border-dashed border-yellow-200 dark:border-yellow-900/30">
        <p>يتم تحويل التاريخ وعرضه حسب نظام التقويم المختار في الأعلى.</p>
        <p className="mt-1 opacity-60">جميع الحسابات تعتمد على توقيت جهازك المحلي.</p>
      </div>
    </div>
  );
};

