        <div className="p-5 border-b border-gray-100 dark:border-gray-800 bg-gray-50 dark:bg-[#1a1a1a] flex items-center justify-between">
          <h3 className="font-black text-slate-800 dark:text-gray-100 flex items-center gap-2">
            <i className="fas fa-list-check text-yellow-600"></i>
            سجل المتابعة التفصيلي
          </h3>
          <span className="text-[10px] font-black text-gray-500 bg-white dark:bg-gray-800 px-3 py-1 rounded border border-gray-200 dark:border-gray-700">
            {filteredDates.length} أيام
          </span>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-right min-w-[1100px]">
            <thead>
              <tr className="bg-gray-50 dark:bg-[#1a1a1a] text-[10px] text-gray-500 uppercase font-black border-b border-gray-100 dark:border-gray-800">
                <th className="px-5 py-4 w-44">اليوم والتاريخ</th>
                <th className="px-5 py-4">الصلوات</th>
                <th className="px-5 py-4">الأذكار</th>
                <th className="px-5 py-4">القرآن</th>
                <th className="px-5 py-4">أعمال البر</th>
                <th className="px-5 py-4">المجاهدة</th>
                <th className="px-5 py-4 text-center">النتيجة</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
              {filteredDates.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-5 py-20 text-center text-gray-400 font-bold italic">لا توجد بيانات مسجلة في هذه الفترة</td>
                </tr>
              ) : (
                filteredDates.map(date => {
                  const log = logs[date];
                  const score = calculateScore(log);
                  const deedsCount = (log.goodDeeds?.length || 0) + (log.notes?.length || 0);
                  const mujahadaCount = (log.mujahada?.length || 0) + (log.mujahadaNotes?.length || 0);

                  const deedsEval = getDeedsEvaluation(deedsCount);
                  const mujahadaEval = getMujahadaEvaluation(mujahadaCount);

                  return (
                    <tr key={date} className="hover:bg-gray-50/50 dark:hover:bg-[#1a1a1a] transition-colors group">
                      <td className="px-5 py-5">
                        <div className="flex flex-col">
                          <span className="text-xs font-black text-slate-800 dark:text-gray-200">
                            {formatArabicDate(date)}
                          </span>
                          <span className="text-[9px] text-gray-400 font-bold mt-1">
                            {formatArabicDate(date, !isHijriMode)}
                          </span>
                        </div>
                      </td>

                      <td className="px-5 py-5">
                        <div className="flex flex-wrap gap-1 max-w-[160px]">
                          {log.prayers.length > 0 ? log.prayers.map(p => (
                            <span key={p} className="text-[9px] px-2 py-0.5 rounded bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 font-black border border-blue-100 dark:border-blue-900/30">
                              {getTaskLabel(p, 'prayer')}
                            </span>
                          )) : <i className="fas fa-minus text-gray-200 dark:text-gray-800"></i>}
                        </div>
                      </td>

                      <td className="px-5 py-5">
                        <div className="flex flex-wrap gap-1 max-w-[160px]">
                          {log.azkar.length > 0 ? log.azkar.map(a => (
                            <span key={a} className="text-[9px] px-2 py-0.5 rounded bg-purple-50 dark:bg-purple-900/20 text-purple-600 dark:text-purple-400 font-black border border-purple-100 dark:border-purple-900/30">
                              {getTaskLabel(a, 'azkar')}
                            </span>
                          )) : <i className="fas fa-minus text-gray-200 dark:text-gray-800"></i>}
                        </div>
                      </td>

                      <td className="px-5 py-5">
                        <div className="flex flex-col items-center bg-gray-50 dark:bg-[#222] px-3 py-1.5 rounded-xl border border-gray-100 dark:border-gray-800 w-fit">
                          <span className="text-xs font-black text-yellow-700 dark:text-yellow-500">
                             {log.quranEnd > 0 ? `${log.quranStart} ↩ ${log.quranEnd}` : 'لم يبدأ'}
                          </span>
                          {log.quranEnd > 0 && <span className="text-[8px] text-gray-400 font-bold uppercase">صفحة</span>}
                        </div>
                      </td>

                      {/* Good Deeds - Evaluation with Eye Icon */}
                      <td className="px-5 py-5">
                        <div className="flex flex-col gap-2">
                          <div className="flex items-center justify-between gap-3">
                            <span className={`text-[11px] font-bold ${deedsEval.color}`}>
                              {deedsEval.text}
                            </span>
                            <button 
                              onClick={() => toggleDetails(`${date}-deed`)}
                              className={`w-7 h-7 rounded-full flex items-center justify-center transition-all ${visibleDetails[`${date}-deed`] ? 'bg-emerald-600 text-white shadow-lg' : 'bg-gray-100 dark:bg-gray-800 text-gray-400 hover:text-emerald-600'}`}
                            >
                              <i className={`fas ${visibleDetails[`${date}-deed`] ? 'fa-eye-slash' : 'fa-eye'} text-[10px]`}></i>
                            </button>
                          </div>

                          {visibleDetails[`${date}-deed`] && (
                            <div className="flex flex-wrap gap-1 max-w-[220px] mt-1 animate-fade-in">
                                {log.goodDeeds.map(d => (
                                  <span key={d} className="text-[9px] px-2 py-0.5 rounded bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 font-black border border-emerald-100 dark:border-emerald-900/30">
                                    {getTaskLabel(d, 'deed')}
                                  </span>
                                ))}
                                {log.notes.map((n, i) => (
                                  <span key={i} className="text-[9px] px-2 py-0.5 rounded bg-emerald-100/50 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-300 font-bold border border-emerald-200 dark:border-emerald-800">
                                    {n}
                                  </span>
                                ))}
                            </div>
                          )}
                        </div>
                      </td>

                      {/* Mujahada - Evaluation with Eye Icon */}
                      <td className="px-5 py-5">
                        <div className="flex flex-col gap-2">
                           <div className="flex items-center justify-between gap-3">
                            <span className={`text-[11px] font-bold ${mujahadaEval.color}`}>
                              {mujahadaEval.text}
                            </span>
                            <button 
                              onClick={() => toggleDetails(`${date}-mujahada`)}
                              className={`w-7 h-7 rounded-full flex items-center justify-center transition-all ${visibleDetails[`${date}-mujahada`] ? 'bg-red-600 text-white shadow-lg' : 'bg-gray-100 dark:bg-gray-800 text-gray-400 hover:text-red-600'}`}
                            >
                              <i className={`fas ${visibleDetails[`${date}-mujahada`] ? 'fa-eye-slash' : 'fa-eye'} text-[10px]`}></i>
                            </button>
                          </div>

                          {visibleDetails[`${date}-mujahada`] && (
                            <div className="flex flex-wrap gap-1 max-w-[220px] mt-1 animate-fade-in">
                                {log.mujahada.map(m => (
                                  <span key={m} className="text-[9px] px-2 py-0.5 rounded bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 font-black border border-red-100 dark:border-red-900/30">
                                    {getTaskLabel(m, 'mujahada')}
                                  </span>
                                ))}
                                {log.mujahadaNotes.map((mn, i) => (
                                  <span key={i} className="text-[9px] px-2 py-0.5 rounded bg-red-100/50 dark:bg-red-900/40 text-red-700 dark:text-red-300 font-bold border border-red-200 dark:border-red-800">
                                    {mn}
                                  </span>
                                ))}
                            </div>
                          )}
                        </div>
                      </td>

                      <td className="px-5 py-5 text-center">
                        <span className={`inline-block px-4 py-2 rounded-xl text-xs font-black shadow-sm border transition-transform group-hover:scale-105 ${score >= 0 ? 'bg-emerald-500 text-white border-emerald-400' : 'bg-red-500 text-white border-red-400'}`}>
                          {score > 0 ? `+${score}` : score}
                        </span>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="bg-yellow-600/5 dark:bg-yellow-900/5 p-6 text-center text-gray-500 dark:text-gray-400 text-xs font-bold rounded-2xl border border-dashed border-yellow-200 dark:border-yellow-900/30">
        <p>يتم تحويل التاريخ وعرضه حسب نظام التقويم المختار في الأعلى.</p>
        <p className="mt-1 opacity-60">جميع الحسابات تعتمد على توقيت جهازك المحلي.</p>
      </div>
    </div>
  );
};

export default History;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  PRAYER_TASKS, 
  AZKAR_TASKS, 
  GOOD_DEED_TASKS, 
  MUJAHADA_TASKS, 
  MOTIVATIONAL_QUOTES,
  SECTION_INFO
} from '../constants';
import { getLogForDate, saveLog, formatDate } from '../services/storageService';
import SectionCard from '../components/SectionCard';
import { DailyLog } from '../types';

const Dashboard: React.FC = () => {
  const [currentDate] = useState(formatDate(new Date()));
  const [log, setLog] = useState<DailyLog>(getLogForDate(currentDate));
  const [newNote, setNewNote] = useState("");
  const [newMujahadaNote, setNewMujahadaNote] = useState("");

  // Quran Goal State
  const [dailyGoal, setDailyGoal] = useState(() => {
    return parseInt(localStorage.getItem('quran_daily_goal') || "20");
  });

  const dailyRotationIndex = useMemo(() => {
    const d = new Date();
    return d.getDate();
  }, []);

  const quote = useMemo(() => {
    return MOTIVATIONAL_QUOTES[dailyRotationIndex % MOTIVATIONAL_QUOTES.length];
  }, [dailyRotationIndex]);

  const getDailyInfo = (section: keyof typeof SECTION_INFO) => {
    const list = SECTION_INFO[section];
    return [list[dailyRotationIndex % list.length]];
  };

  useEffect(() => {
    saveLog(log);
  }, [log]);

  useEffect(() => {
    localStorage.setItem('quran_daily_goal', dailyGoal.toString());
  }, [dailyGoal]);

  const toggleTask = (section: keyof DailyLog, id: string) => {
    setLog(prev => {
      const currentList = prev[section] as string[];
      const newList = currentList.includes(id) 
        ? currentList.filter(item => item !== id)
        : [...currentList, id];
      return { ...prev, [section]: newList };
    });
  };

  const handleQuranChange = (field: 'quranStart' | 'quranEnd', value: string) => {
    const num = Math.min(604, Math.max(0, parseInt(value) || 0));
    setLog(prev => ({ ...prev, [field]: num }));
  };

  const addNote = () => {
    if (!newNote.trim()) return;
    setLog(prev => ({ ...prev, notes: [...prev.notes, newNote] }));
    setNewNote("");
  };

  const addMujahadaNote = () => {
    if (!newMujahadaNote.trim()) return;
    setLog(prev => ({ ...prev, mujahadaNotes: [...prev.mujahadaNotes, newMujahadaNote] }));
    setNewMujahadaNote("");
  };

  const score = useMemo(() => {
    let currentScore = 0;

    // الصلوات المفروضة
    const fardIds = ['fajr', 'dhuhr', 'asr', 'maghrib', 'isha'];
    fardIds.forEach(id => {
      if (log.prayers.includes(id)) {
        currentScore += 10;
      } else {
        currentScore -= 10; // خصم في حالة عدم الأداء
      }
    });

    // بقية الصلوات (نوافل)
    const otherPrayersCount = log.prayers.filter(id => !fardIds.includes(id)).length;
    currentScore += otherPrayersCount * 10;

    // الأذكار وأعمال البر
    currentScore += (log.azkar.length + log.goodDeeds.length + log.notes.length) * 10;

    // الزلات والناقص
    currentScore -= (log.mujahada.length + log.mujahadaNotes.length) * 10;

    return currentScore;
  }, [log]);

  const quranProgress = useMemo(() => {
    const pagesReadToday = Math.max(0, log.quranEnd - log.quranStart);
    const totalRemaining = 604 - log.quranEnd;
    const percentage = (log.quranEnd / 604) * 100;

    const daysLeft = dailyGoal > 0 ? Math.ceil(totalRemaining / dailyGoal) : 0;
    const completionDate = new Date();
    completionDate.setDate(completionDate.getDate() + daysLeft);

    let formattedCompletion = "غير محدد";
    try {
      formattedCompletion = new Intl.DateTimeFormat('ar-SA-u-ca-islamic-uma-nu-latn', {
        day: 'numeric',
        month: 'long',
        year: 'numeric'
      }).format(completionDate);
    } catch (e) {
      formattedCompletion = completionDate.toLocaleDateString('ar-EG');
    }

    return { pagesReadToday, totalRemaining, percentage, daysLeft, formattedCompletion };
  }, [log.quranStart, log.quranEnd, dailyGoal]);

  return (
    <div className="space-y-6 pb-12 animate-fade-in relative">
      <div className="hidden lg:block absolute -right-32 top-1/4 opacity-10 dark:opacity-5 animate-float pointer-events-none">
        <i className="fas fa-mosque text-[15rem] text-yellow-600"></i>
      </div>

      <div className="bg-white dark:bg-[#1a1a1a] border border-yellow-600/30 dark:border-yellow-900/40 p-10 rounded-[2.5rem] relative overflow-hidden group shadow-2xl">
        <div className="absolute top-0 right-0 w-64 h-64 bg-yellow-500/10 rounded-full -mr-32 -mt-32 blur-[100px]"></div>
        <div className="relative z-10 text-center">
          <i className="fas fa-quote-right text-[#d4af37] text-4xl mb-6 opacity-30"></i>
          <p className="text-2xl md:text-4xl font-bold text-slate-800 dark:text-gray-100 leading-relaxed quran-font">
            {quote.text}
          </p>
          <div className="mt-8 flex items-center justify-center gap-4">
            <div className="h-[2px] w-16 bg-gradient-to-l from-transparent to-yellow-500/40"></div>
            <span className="text-sm text-yellow-700 dark:text-yellow-500 font-black uppercase tracking-widest">{quote.source}</span>
            <div className="h-[2px] w-16 bg-gradient-to-r from-transparent to-yellow-500/40"></div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
        {[
          { label: 'نقاط اليوم', value: score, highlight: true, icon: 'fa-star', theme: 'gold' },
          { label: 'تقدم الختمة', value: `${Math.round(quranProgress.percentage)}%`, highlight: false, icon: 'fa-book-quran', theme: 'default' },
          { label: 'الزلات اليومية', value: log.mujahada.length + log.mujahadaNotes.length, highlight: false, icon: 'fa-triangle-exclamation', theme: 'danger' },
          { label: 'إجمالي الطاعات', value: log.prayers.length + log.azkar.length, highlight: false, icon: 'fa-pray', theme: 'default' },
          { label: 'أعمال البر', value: log.goodDeeds.length + log.notes.length, highlight: false, icon: 'fa-heart', theme: 'default' },
        ].map((stat, idx) => (
          <div key={idx} className={`bg-white dark:bg-[#151515] p-5 rounded-3xl border border-gray-100 dark:border-gray-800 flex flex-col items-center justify-center shadow-lg hover:shadow-yellow-500/10 hover:-translate-y-1 transition-all duration-300 ${stat.theme === 'danger' ? 'border-red-100 dark:border-red-900/20' : ''}`}>
            <i className={`fas ${stat.icon} text-[10px] mb-2 ${stat.theme === 'danger' ? 'text-red-500/60' : stat.theme === 'gold' ? 'text-yellow-600/60' : 'text-gray-400/60'}`}></i>
            <span className="text-gray-400 dark:text-gray-500 text-[9px] mb-1 font-black tracking-widest uppercase text-center">{stat.label}</span>
            <span className={`text-3xl font-black ${stat.theme === 'gold' ? 'gold-gradient' : stat.theme === 'danger' ? 'text-red-600' : 'text-slate-800 dark:text-gray-100'}`}>
              {stat.value}
            </span>
          </div>
        ))}
      </div>

      <div className="grid md:grid-cols-2 gap-6">
        <SectionCard title="ورد القرآن الكريم" icon="fa-book-open-reader" infoItems={getDailyInfo('QURAN')} defaultOpen={false}>
          <div className="space-y-6">
            <div className="bg-yellow-50/50 dark:bg-yellow-900/10 p-4 rounded-2xl border border-yellow-100 dark:border-yellow-900/20 mb-4">
               <div className="flex items-center justify-between">
                  <span className="text-xs font-black text-yellow-800 dark:text-yellow-400">الورد اليومي المستهدف (بالصفحات)</span>
                  <div className="flex items-center gap-2">
                    <button onClick={() => setDailyGoal(Math.max(1, dailyGoal - 1))} className="w-8 h-8 rounded-lg bg-white dark:bg-[#222] border border-gray-200 dark:border-gray-800 text-yellow-600">-</button>
                    <input 
                      type="number"
                      value={dailyGoal}
                      onChange={(e) => setDailyGoal(Math.max(1, parseInt(e.target.value) || 1))}
                      className="w-14 bg-white dark:bg-[#222] border border-gray-200 dark:border-gray-800 rounded-lg p-1 text-center font-black text-yellow-600 outline-none"
                    />
                    <button onClick={() => setDailyGoal(dailyGoal + 1)} className="w-8 h-8 rounded-lg bg-white dark:bg-[#222] border border-gray-200 dark:border-gray-800 text-yellow-600">+</button>
                  </div>
               </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] text-gray-500 block font-black uppercase pr-2">من صفحة</label>
                <input 
                  type="number" 
                  value={log.quranStart || ""}
                  onChange={(e) => handleQuranChange('quranStart', e.target.value)}
                  className="w-full bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-xl p-4 text-center text-yellow-600 font-black focus:ring-2 focus:ring-yellow-500/20"
                  placeholder="0"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] text-gray-500 block font-black uppercase pr-2">إلى صفحة</label>
                <input 
                  type="number" 
                  value={log.quranEnd || ""}
                  onChange={(e) => handleQuranChange('quranEnd', e.target.value)}
                  className="w-full bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-xl p-4 text-center text-yellow-600 font-black focus:ring-2 focus:ring-yellow-500/20"
                  placeholder="0"
                />
              </div>
            </div>

            {dailyGoal > 0 && (
              <div className="bg-gradient-to-r from-yellow-600 to-yellow-700 p-5 rounded-2xl text-white shadow-lg relative overflow-hidden">
                <div className="absolute top-0 right-0 opacity-10 -mr-4 -mt-4">
                   <i className="fas fa-calendar-check text-7xl"></i>
                </div>
                <div className="relative z-10 flex flex-col items-center">
                  <span className="text-[10px] font-black uppercase tracking-widest opacity-80 mb-1">الموعد المتوقع للختمة</span>
                  <p className="text-xl font-black">{quranProgress.formattedCompletion}</p>
                  <div className="mt-3 text-[11px] bg-white/20 px-4 py-1 rounded-full font-bold">
                    متبقي {quranProgress.daysLeft} يوماً بمعدل وردك الحالي
                  </div>
                </div>
              </div>
            )}
            <div className="space-y-2 pt-2">
              <div className="flex justify-between text-[10px] text-gray-500 font-black uppercase px-1">
                <span>التقدم في المصحف</span>
                <span>{Math.round(quranProgress.percentage)}%</span>
              </div>
              <div className="w-full h-4 bg-gray-100 dark:bg-black/30 rounded-full overflow-hidden p-0.5 border border-gray-200 dark:border-gray-800">
                <div 
                  className="h-full bg-gradient-to-r from-yellow-600 via-yellow-400 to-yellow-600 rounded-full transition-all duration-1000 ease-out shadow-[0_0_15px_rgba(212,175,55,0.5)]"
                  style={{ width: `${quranProgress.percentage}%` }}
                ></div>
              </div>
            </div>
          </div>
        </SectionCard>

        <SectionCard title="قسم الصلاة" icon="fa-mosque" infoItems={getDailyInfo('PRAYER')} defaultOpen={false}>
          <div className="grid grid-cols-2 gap-3">
            {PRAYER_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-4 rounded-2xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-yellow-50 dark:hover:bg-[#222] transition-all border border-transparent hover:border-yellow-200 dark:hover:border-gray-800">
                <input 
                  type="checkbox" 
                  checked={log.prayers.includes(task.id)}
                  onChange={() => toggleTask('prayers', task.id)}
                  className="w-5 h-5 rounded-lg border-gray-300 dark:border-gray-700 text-yellow-600 focus:ring-yellow-500"
                />
                <span className={`text-sm font-bold ${log.prayers.includes(task.id) ? 'text-yellow-600 line-through opacity-60' : 'text-slate-700 dark:text-gray-200'}`}>
                  {task.label}
                </span>
              </label>
            ))}
          </div>
        </SectionCard>

        <SectionCard title="قسم الأذكار" icon="fa-hands-praying" infoItems={getDailyInfo('AZKAR')} defaultOpen={false}>
          <div className="grid grid-cols-2 gap-3">
            {AZKAR_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-4 rounded-2xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-purple-50 dark:hover:bg-[#222] transition-all border border-transparent hover:border-purple-200 dark:hover:border-gray-800">
                <input 
                  type="checkbox" 
                  checked={log.azkar.includes(task.id)}
                  onChange={() => toggleTask('azkar', task.id)}
                  className="w-5 h-5 rounded-lg border-gray-300 dark:border-gray-700 text-purple-600 focus:ring-purple-500"
                />
                <span className={`text-sm font-bold ${log.azkar.includes(task.id) ? 'text-purple-600 line-through opacity-60' : 'text-slate-700 dark:text-gray-200'}`}>
                  {task.label}
                </span>
              </label>
            ))}
          </div>
        </SectionCard>

        <SectionCard title="أعمال البر والخير" icon="fa-heart-pulse" infoItems={getDailyInfo('GOOD_DEEDS')} defaultOpen={false}>
           <div className="space-y-4">
              <div className="grid gap-2">
                {GOOD_DEED_TASKS.slice(0, 8).map(task => (
                  <label key={task.id} className="flex items-start gap-4 p-4 rounded-2xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-emerald-50 dark:hover:bg-[#222] transition-all border border-transparent hover:border-emerald-200 dark:hover:border-gray-800">
                    <input 
                      type="checkbox" 
                      checked={log.goodDeeds.includes(task.id)}
                      onChange={() => toggleTask('goodDeeds', task.id)}
                      className="w-6 h-6 mt-0.5 rounded-lg border-gray-300 dark:border-gray-700 text-emerald-600"
                    />
                    <div className="flex flex-col">
                      <span className={`text-sm font-bold ${log.goodDeeds.includes(task.id) ? 'text-emerald-600' : 'text-slate-700 dark:text-gray-200'}`}>
                        {task.label}
                      </span>
                      <span className="text-[10px] text-gray-500 leading-tight mt-1">{task.description}</span>
                    </div>
                  </label>
                ))}
              </div>
              <div className="pt-4 border-t border-gray-100 dark:border-gray-800">
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    value={newNote}
                    onChange={(e) => setNewNote(e.target.value)}
                    placeholder="أضف عمل خير آخر قمت به..."
                    className="flex-grow bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-2xl px-5 py-3 text-sm focus:ring-2 focus:ring-yellow-500/20 outline-none"
                  />
                  <button onClick={addNote} className="bg-yellow-600 hover:bg-yellow-700 text-white w-12 h-12 rounded-2xl shadow-lg transition-all flex items-center justify-center">
                    <i className="fas fa-plus"></i>
                  </button>
                </div>
              </div>
           </div>
        </SectionCard>

        <SectionCard title="مجاهدة النفس" icon="fa-shield-halved" infoItems={getDailyInfo('MUJAHADA')} defaultOpen={false}>
          <div className="space-y-4">
            <p className="text-[10px] text-red-600 text-center font-black bg-red-50 dark:bg-red-900/10 py-3 rounded-2xl border border-red-100 dark:border-red-900/20 uppercase">تسجيل الزلات يساعدك على الانتباه لها وتجنبها غداً</p>
            <div className="grid gap-2">
              {MUJAHADA_TASKS.slice(0, 6).map(task => (
                <label key={task.id} className="flex items-start gap-4 p-4 rounded-2xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-red-50 dark:hover:bg-red-900/5 transition-all border border-transparent hover:border-red-200 dark:hover:border-red-900/30">
                  <input 
                    type="checkbox" 
                    checked={log.mujahada.includes(task.id)}
                    onChange={() => toggleTask('mujahada', task.id)}
                    className="w-6 h-6 mt-0.5 rounded-lg border-gray-300 dark:border-gray-700 text-red-600"
                  />
                  <div className="flex flex-col">
                    <span className={`text-sm font-bold ${log.mujahada.includes(task.id) ? 'text-red-600' : 'text-slate-700 dark:text-gray-200'}`}>
                      {task.label}
                    </span>
                    <span className="text-[10px] text-gray-400 leading-tight mt-1">{task.description}</span>
                  </div>
                </label>
              ))}
            </div>
            <div className="pt-4 border-t border-gray-100 dark:border-gray-800">
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    value={newMujahadaNote}
                    onChange={(e) => setNewMujahadaNote(e.target.value)}
                    placeholder="سجل ملاحظة للمجاهدة..."
                    className="flex-grow bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-2xl px-5 py-3 text-sm focus:ring-2 focus:ring-red-500/20 outline-none"
                  />
                  <button onClick={addMujahadaNote} className="bg-red-600 hover:bg-red-700 text-white w-12 h-12 rounded-2xl shadow-lg transition-all flex items-center justify-center">
                    <i className="fas fa-plus"></i>
                  </button>
                </div>
              </div>
          </div>
        </SectionCard>
      </div>

      <div className="mt-12 text-center p-8 bg-gradient-to-b from-transparent to-yellow-600/5 dark:to-yellow-900/10 rounded-t-[3rem] border-t border-yellow-200/20 dark:border-yellow-900/20">
         <i className="fas fa-mosque text-yellow-600/20 text-5xl mb-4 block"></i>
         <p className="text-gray-500 dark:text-gray-400 font-bold tracking-widest text-xs uppercase italic">"وَمَن يُعَظِّمْ شَعَائِرَ اللَّهِ فَإِنَّهَا مِن تَقْوَى الْقُلُوبِ"</p>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useMemo, useState } from 'react';
import { getLogs } from '../services/storageService';
import { DailyLog } from '../types';
import { PRAYER_TASKS, AZKAR_TASKS, GOOD_DEED_TASKS, MUJAHADA_TASKS } from '../constants';

interface BreakdownItem {
  label: string;
  points: number;
  type: 'pos' | 'neg';
  isFard?: boolean;
}

const History: React.FC = () => {
  const [startDate, setStartDate] = useState(() => {
    const d = new Date();
    d.setDate(d.getDate() - 7);
    return d.toISOString().split('T')[0];
  });
  const [endDate, setEndDate] = useState(() => new Date().toISOString().split('T')[0]);
  const [isHijriMode, setIsHijriMode] = useState(true);

  const [visibleDetails, setVisibleDetails] = useState<Record<string, boolean>>({});
  const [activeBreakdownDate, setActiveBreakdownDate] = useState<string | null>(null);

  const toggleDetails = (key: string) => {
    setVisibleDetails(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const logs = useMemo(() => getLogs(), []);

  const filteredDates = useMemo(() => {
    return Object.keys(logs)
      .filter(date => date >= startDate && date <= endDate)
      .sort((a, b) => b.localeCompare(a));
  }, [logs, startDate, endDate]);

  const calculateScore = (log: DailyLog) => {
    let currentScore = 0;
    const fardIds = ['fajr', 'dhuhr', 'asr', 'maghrib', 'isha'];

    // الفروض
    fardIds.forEach(id => {
      currentScore += log.prayers.includes(id) ? 10 : -10;
    });

    // النوافل والأذكار والخير
    const othersCount = log.prayers.filter(id => !fardIds.includes(id)).length 
                      + log.azkar.length 
                      + log.goodDeeds.length 
                      + log.notes.length;
    currentScore += othersCount * 10;

    // الزلات
    currentScore -= (log.mujahada.length + log.mujahadaNotes.length) * 10;

    return currentScore;
  };

  const getDayBreakdown = (date: string): BreakdownItem[] => {
    const log = logs[date];
    if (!log) return [];

    const items: BreakdownItem[] = [];
    const fardIds = ['fajr', 'dhuhr', 'asr', 'maghrib', 'isha'];

    // فحص الفروض
    fardIds.forEach(id => {
      const task = PRAYER_TASKS.find(t => t.id === id);
      const done = log.prayers.includes(id);
      items.push({
        label: task?.label || id,
        points: done ? 10 : -10,
        type: done ? 'pos' : 'neg',
        isFard: true
      });
    });

    // بقية الصلوات
    log.prayers.filter(id => !fardIds.includes(id)).forEach(id => {
      const task = PRAYER_TASKS.find(t => t.id === id);
      items.push({ label: task?.label || id, points: 10, type: 'pos' });
    });

    // الأذكار
    log.azkar.forEach(id => {
      const task = AZKAR_TASKS.find(t => t.id === id);
      items.push({ label: task?.label || id, points: 10, type: 'pos' });
    });

    // أعمال البر
    log.goodDeeds.forEach(id => {
      const task = GOOD_DEED_TASKS.find(t => t.id === id);
      items.push({ label: task?.label || id, points: 10, type: 'pos' });
    });
    log.notes.forEach(note => {
      items.push({ label: note, points: 10, type: 'pos' });
    });

    // الزلات
    log.mujahada.forEach(id => {
      const task = MUJAHADA_TASKS.find(t => t.id === id);
      items.push({ label: task?.label || id, points: -10, type: 'neg' });
    });
    log.mujahadaNotes.forEach(note => {
      items.push({ label: note, points: -10, type: 'neg' });
    });

    return items;
  };

  const totalPoints = useMemo(() => {
    return filteredDates.reduce((acc: number, date: string) => acc + calculateScore(logs[date]), 0);
  }, [logs, filteredDates]);

  const formatArabicDate = (dateStr: string, forceHijri?: boolean) => {
    try {
      const date = new Date(dateStr);
      const calendar = (forceHijri ?? isHijriMode) ? 'islamic-uma' : 'gregory';
      return new Intl.DateTimeFormat(`ar-SA-u-ca-${calendar}-nu-latn`, {
        day: 'numeric',
        month: 'long',
        year: 'numeric'
      }).format(date);
    } catch (e) {
      return dateStr;
    }
  };

  const getTaskLabel = (id: string, type: 'prayer' | 'azkar' | 'deed' | 'mujahada') => {
    let source = [];
    switch(type) {
        case 'prayer': source = PRAYER_TASKS; break;
        case 'azkar': source = AZKAR_TASKS; break;
        case 'deed': source = GOOD_DEED_TASKS; break;
        case 'mujahada': source = MUJAHADA_TASKS; break;
    }
    const task = source.find(t => t.id === id);
    if (!task) return id;
    return task.label.replace('صلاة ', '').replace('أذكار ', '');
  };

  const getDeedsEvaluation = (count: number) => {
    if (count === 0) return { text: 'لم يسجل', color: 'text-gray-400' };
    if (count <= 2) return { text: 'بداية طيبة', color: 'text-emerald-500' };
    if (count <= 5) return { text: 'سعي مشكور', color: 'text-emerald-600' };
    return { text: 'سابق بالخيرات', color: 'text-emerald-700 font-black' };
  };

  const getMujahadaEvaluation = (count: number) => {
    if (count === 0) return { text: 'نفس لوامة زكية', color: 'text-emerald-600 font-bold' };
    if (count <= 1) return { text: 'هفوة عابرة', color: 'text-yellow-600' };
    if (count <= 3) return { text: 'جاهد نفسك', color: 'text-orange-600' };
    return { text: 'انتبه لقلبك', color: 'text-red-600 font-black' };
  };

  return (
    <div className="animate-fade-in space-y-6 pb-12">
      {/* Breakdown Modal */}
      {activeBreakdownDate && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in" onClick={() => setActiveBreakdownDate(null)}>
          <div className="bg-white dark:bg-[#1a1a1a] w-full max-w-lg rounded-[2.5rem] shadow-2xl overflow-hidden border border-gray-200 dark:border-gray-800" onClick={e => e.stopPropagation()}>
            <div className="p-6 bg-gradient-to-r from-yellow-600 to-yellow-700 text-white flex items-center justify-between">
              <div className="flex flex-col">
                <h2 className="text-xl font-black">تفاصيل تقييم اليوم</h2>
                <span className="text-xs opacity-80">{formatArabicDate(activeBreakdownDate)}</span>
              </div>
              <button onClick={() => setActiveBreakdownDate(null)} className="w-10 h-10 rounded-full bg-white/20 flex items-center justify-center hover:bg-white/40 transition-colors">
                <i className="fas fa-times"></i>
              </button>
            </div>

            <div className="p-6 max-h-[60vh] overflow-y-auto space-y-3 custom-scrollbar">
              {getDayBreakdown(activeBreakdownDate).map((item, idx) => (
                <div key={idx} className={`flex items-center justify-between p-4 rounded-2xl border ${item.type === 'pos' ? 'bg-emerald-50 dark:bg-emerald-900/10 border-emerald-100 dark:border-emerald-900/20' : 'bg-red-50 dark:bg-red-900/10 border-red-100 dark:border-red-900/20'}`}>
                  <div className="flex items-center gap-3">
                    <i className={`fas ${item.type === 'pos' ? 'fa-circle-check text-emerald-500' : 'fa-circle-xmark text-red-500'}`}></i>
                    <div className="flex flex-col">
                      <span className="text-sm font-bold text-slate-800 dark:text-gray-100">{item.label}</span>
                      {item.isFard && <span className="text-[9px] font-black uppercase tracking-widest text-gray-500">{item.type === 'neg' ? 'فائتة (فرض)' : 'فرض'}</span>}
                    </div>
                  </div>
                  <span className={`text-sm font-black ${item.type === 'pos' ? 'text-emerald-600' : 'text-red-600'}`}>
                    {item.points > 0 ? `+${item.points}` : item.points}
                  </span>
                </div>
              ))}
            </div>

            <div className="p-6 bg-gray-50 dark:bg-[#111] border-t border-gray-100 dark:border-gray-800 flex items-center justify-between">
              <span className="text-sm font-black text-gray-500">إجمالي النتيجة</span>
              <span className={`text-2xl font-black ${calculateScore(logs[activeBreakdownDate]) >= 0 ? 'text-emerald-600' : 'text-red-600'}`}>
                {calculateScore(logs[activeBreakdownDate])}
              </span>
            </div>
          </div>
        </div>
      )}

      {/* Summary Header */}
      <div className="bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-3xl p-8 text-center shadow-xl relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-yellow-500 to-transparent opacity-40"></div>
        <h2 className="text-gray-500 dark:text-gray-400 text-[10px] mb-2 font-black tracking-widest uppercase">رصيد النقاط للفترة المختارة</h2>
        <div className="text-6xl font-black gold-gradient drop-shadow-sm mb-2">{totalPoints}</div>
        <div className="flex items-center justify-center gap-2 text-[11px] text-yellow-700 dark:text-yellow-600 font-bold bg-yellow-50 dark:bg-yellow-900/10 px-4 py-1.5 rounded-full inline-flex mx-auto border border-yellow-100 dark:border-yellow-900/20">
          <i className="fas fa-calendar-alt"></i>
          <span>من {formatArabicDate(startDate)} إلى {formatArabicDate(endDate)}</span>
        </div>
      </div>

      {/* Advanced Filter with Toggle */}
      <div className="bg-white dark:bg-[#151515] border border-gray-200 dark:border-gray-800 rounded-2xl p-4 shadow-md">
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="grid grid-cols-2 gap-3 flex-grow w-full">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-gray-400 uppercase pr-2">من</label>
              <input 
                type="date" 
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="w-full bg-gray-50 dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-xl p-3 text-xs font-bold focus:ring-2 focus:ring-yellow-500/20 outline-none dark:text-gray-200"
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-gray-400 uppercase pr-2">إلى</label>
              <input 
                type="date" 
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                className="w-full bg-gray-50 dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-xl p-3 text-xs font-bold focus:ring-2 focus:ring-yellow-500/20 outline-none dark:text-gray-200"
              />
            </div>
          </div>

          <button 
            onClick={() => setIsHijriMode(!isHijriMode)}
            className="flex items-center gap-2 px-6 py-3 bg-slate-800 dark:bg-yellow-600 text-white rounded-xl shadow-lg hover:opacity-90 transition-all font-bold text-sm w-full md:w-auto mt-2 md:mt-4 group"
          >
            <i className={`fas ${isHijriMode ? 'fa-moon' : 'fa-calendar-day'} group-hover:rotate-12 transition-transform`}></i>
            <span>التقويم {isHijriMode ? 'الهجري' : 'الميلادي'}</span>
          </button>
        </div>
      </div>

      {/* Detailed Table */}
      <div className="bg-white dark:bg-[#151515] border border-gray-200 dark:border-gray-800 rounded-2xl overflow-hidden shadow-lg">
        <div className="p-5 border-b border-gray-100 dark:border-gray-800 bg-gray-50 dark:bg-[#1a1a1a] flex items-center justify-between">
          <h3 className="font-black text-slate-800 dark:text-gray-100 flex items-center gap-2">
            <i className="fas fa-list-check text-yellow-600"></i>
            سجل المتابعة التفصيلي
          </h3>
          <span className="text-[10px] font-black text-gray-500 bg-white dark:bg-gray-800 px-3 py-1 rounded border border-gray-200 dark:border-gray-700">
            {filteredDates.length} أيام
          </span>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-right min-w-[1100px]">
            <thead>
              <tr className="bg-gray-50 dark:bg-[#1a1a1a] text-[10px] text-gray-500 uppercase font-black border-b border-gray-100 dark:border-gray-800">
                <th className="px-5 py-4 w-44">اليوم والتاريخ</th>
                <th className="px-5 py-4">الصلوات</th>
                <th className="px-5 py-4">الأذكار</th>
                <th className="px-5 py-4">القرآن</th>
                <th className="px-5 py-4">أعمال البر</th>
                <th className="px-5 py-4">المجاهدة</th>
                <th className="px-5 py-4 text-center">النتيجة</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
              {filteredDates.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-5 py-20 text-center text-gray-400 font-bold italic">لا توجد بيانات مسجلة في هذه الفترة</td>
                </tr>
              ) : (
                filteredDates.map(date => {
                  const log = logs[date];
                  const score = calculateScore(log);
                  const deedsCount = (log.goodDeeds?.length || 0) + (log.notes?.length || 0);
                  const mujahadaCount = (log.mujahada?.length || 0) + (log.mujahadaNotes?.length || 0);

                  const deedsEval = getDeedsEvaluation(deedsCount);
                  const mujahadaEval = getMujahadaEvaluation(mujahadaCount);

                  return (
                    <tr key={date} className="hover:bg-gray-50/50 dark:hover:bg-[#1a1a1a] transition-colors group">
                      <td className="px-5 py-5">
                        <div className="flex flex-col">
                          <span className="text-xs font-black text-slate-800 dark:text-gray-200">
                            {formatArabicDate(date)}
                          </span>
                          <span className="text-[9px] text-gray-400 font-bold mt-1">
                            {formatArabicDate(date, !isHijriMode)}
                          </span>
                        </div>
                      </td>

                      <td className="px-5 py-5">
                        <div className="flex flex-wrap gap-1 max-w-[160px]">
                          {log.prayers.length > 0 ? log.prayers.map(p => (
                            <span key={p} className="text-[9px] px-2 py-0.5 rounded bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 font-black border border-blue-100 dark:border-blue-900/30">
                              {getTaskLabel(p, 'prayer')}
                            </span>
                          )) : <i className="fas fa-minus text-gray-200 dark:text-gray-800"></i>}
                        </div>
                      </td>

                      <td className="px-5 py-5">
                        <div className="flex flex-wrap gap-1 max-w-[160px]">
                          {log.azkar.length > 0 ? log.azkar.map(a => (
                            <span key={a} className="text-[9px] px-2 py-0.5 rounded bg-purple-50 dark:bg-purple-900/20 text-purple-600 dark:text-purple-400 font-black border border-purple-100 dark:border-purple-900/30">
                              {getTaskLabel(a, 'azkar')}
                            </span>
                          )) : <i className="fas fa-minus text-gray-200 dark:text-gray-800"></i>}
                        </div>
                      </td>

                      <td className="px-5 py-5">
                        <div className="flex flex-col items-center bg-gray-50 dark:bg-[#222] px-3 py-1.5 rounded-xl border border-gray-100 dark:border-gray-800 w-fit">
                          <span className="text-xs font-black text-yellow-700 dark:text-yellow-500">
                             {log.quranEnd > 0 ? `${log.quranStart} ↩ ${log.quranEnd}` : 'لم يبدأ'}
                          </span>
                          {log.quranEnd > 0 && <span className="text-[8px] text-gray-400 font-bold uppercase">صفحة</span>}
                        </div>
                      </td>

                      <td className="px-5 py-5">
                        <div className="flex flex-col gap-2">
                          <div className="flex items-center justify-between gap-3">
                            <span className={`text-[11px] font-bold ${deedsEval.color}`}>
                              {deedsEval.text}
                            </span>
                            <button 
                              onClick={() => toggleDetails(`${date}-deed`)}
                              className={`w-7 h-7 rounded-full flex items-center justify-center transition-all ${visibleDetails[`${date}-deed`] ? 'bg-emerald-600 text-white shadow-lg' : 'bg-gray-100 dark:bg-gray-800 text-gray-400 hover:text-emerald-600'}`}
                            >
                              <i className={`fas ${visibleDetails[`${date}-deed`] ? 'fa-eye-slash' : 'fa-eye'} text-[10px]`}></i>
                            </button>
                          </div>

                          {visibleDetails[`${date}-deed`] && (
                            <div className="flex flex-wrap gap-1 max-w-[220px] mt-1 animate-fade-in">
                                {log.goodDeeds.map(d => (
                                  <span key={d} className="text-[9px] px-2 py-0.5 rounded bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 font-black border border-emerald-100 dark:border-emerald-900/30">
                                    {getTaskLabel(d, 'deed')}
                                  </span>
                                ))}
                                {log.notes.map((n, i) => (
                                  <span key={i} className="text-[9px] px-2 py-0.5 rounded bg-emerald-100/50 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-300 font-bold border border-emerald-200 dark:border-emerald-800">
                                    {n}
                                  </span>
                                ))}
                            </div>
                          )}
                        </div>
                      </td>

                      <td className="px-5 py-5">
                        <div className="flex flex-col gap-2">
                           <div className="flex items-center justify-between gap-3">
                            <span className={`text-[11px] font-bold ${mujahadaEval.color}`}>
                              {mujahadaEval.text}
                            </span>
                            <button 
                              onClick={() => toggleDetails(`${date}-mujahada`)}
                              className={`w-7 h-7 rounded-full flex items-center justify-center transition-all ${visibleDetails[`${date}-mujahada`] ? 'bg-red-600 text-white shadow-lg' : 'bg-gray-100 dark:bg-gray-800 text-gray-400 hover:text-red-600'}`}
                            >
                              <i className={`fas ${visibleDetails[`${date}-mujahada`] ? 'fa-eye-slash' : 'fa-eye'} text-[10px]`}></i>
                            </button>
                          </div>

                          {visibleDetails[`${date}-mujahada`] && (
                            <div className="flex flex-wrap gap-1 max-w-[220px] mt-1 animate-fade-in">
                                {log.mujahada.map(m => (
                                  <span key={m} className="text-[9px] px-2 py-0.5 rounded bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 font-black border border-red-100 dark:border-red-900/30">
                                    {getTaskLabel(m, 'mujahada')}
                                  </span>
                                ))}
                                {log.mujahadaNotes.map((mn, i) => (
                                  <span key={i} className="text-[9px] px-2 py-0.5 rounded bg-red-100/50 dark:bg-red-900/40 text-red-700 dark:text-red-300 font-bold border border-red-200 dark:border-red-800">
                                    {mn}
                                  </span>
                                ))}
                            </div>
                          )}
                        </div>
                      </td>

                      <td className="px-5 py-5 text-center">
                        <button 
                          onClick={() => setActiveBreakdownDate(date)}
                          className={`inline-block px-4 py-2 rounded-xl text-xs font-black shadow-sm border transition-all hover:scale-110 active:scale-95 cursor-pointer ${score >= 0 ? 'bg-emerald-500 text-white border-emerald-400' : 'bg-red-500 text-white border-red-400'}`}
                        >
                          {score > 0 ? `+${score}` : score}
                          <i className="fas fa-info-circle mr-2 opacity-60"></i>
                        </button>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="bg-yellow-600/5 dark:bg-yellow-900/5 p-6 text-center text-gray-500 dark:text-gray-400 text-xs font-bold rounded-2xl border border-dashed border-yellow-200 dark:border-yellow-900/30">
