import React, { useState, useEffect, useMemo } from 'react';
import { 
  PRAYER_TASKS, 
  AZKAR_TASKS, 
  GOOD_DEED_CATEGORIES, 
  MUJAHADA_CATEGORIES, 
  MOTIVATIONAL_QUOTES,
  SECTION_INFO
} from '../constants';
import { getLogForDate, saveLog, formatDate } from '../services/storageService';
import SectionCard from '../components/SectionCard';
import { DailyLog } from '../types';

const Dashboard: React.FC = () => {
  const [currentDate] = useState(formatDate(new Date()));
  const [log, setLog] = useState<DailyLog>(getLogForDate(currentDate));

  // حالات الأكورديون الداخلية
  const [openDeedCategory, setOpenDeedCategory] = useState<number | null>(null);
  const [openMujahadaCategory, setOpenMujahadaCategory] = useState<number | null>(null);

  // حالات الإدخال اليدوي
  const [manualInputs, setManualInputs] = useState<Record<string, string>>({});

  const dailyGoal = useMemo(() => parseInt(localStorage.getItem('quran_daily_goal') || "20"), []);
  const dailyRotationIndex = useMemo(() => new Date().getDate(), []);
  const quote = useMemo(() => MOTIVATIONAL_QUOTES[dailyRotationIndex % MOTIVATIONAL_QUOTES.length], [dailyRotationIndex]);

  const getDailyInfo = (section: keyof typeof SECTION_INFO) => [SECTION_INFO[section][dailyRotationIndex % SECTION_INFO[section].length]];

  useEffect(() => { saveLog(log); }, [log]);

  const toggleTask = (section: keyof DailyLog, id: string) => {
    setLog(prev => {
      const currentList = prev[section] as string[];
      const newList = currentList.includes(id) ? currentList.filter(item => item !== id) : [...currentList, id];
      return { ...prev, [section]: newList };
    });
  };

  const addManualEntry = (type: 'notes' | 'mujahadaNotes', categoryIndex: number) => {
    const key = `${type}-${categoryIndex}`;
    const value = manualInputs[key];
    if (!value || !value.trim()) return;

    setLog(prev => ({ ...prev, [type]: [...prev[type], value.trim()] }));
    setManualInputs(prev => ({ ...prev, [key]: '' }));
  };

  const score = useMemo(() => {
    let currentScore = 0;
    const fardIds = ['fajr', 'dhuhr', 'asr', 'maghrib', 'isha'];
    fardIds.forEach(id => currentScore += log.prayers.includes(id) ? 10 : -10);
    currentScore += (log.prayers.filter(id => !fardIds.includes(id)).length + log.azkar.length + log.goodDeeds.length + log.notes.length) * 10;
    currentScore -= (log.mujahada.length + log.mujahadaNotes.length) * 10;
    return currentScore;
  }, [log]);

  const quranProgress = useMemo(() => {
    const percentage = (log.quranEnd / 604) * 100;
    const totalRemaining = 604 - log.quranEnd;
    const daysLeft = dailyGoal > 0 ? Math.ceil(totalRemaining / dailyGoal) : 0;
    const completionDate = new Date();
    completionDate.setDate(completionDate.getDate() + daysLeft);
    let formattedCompletion = "غير محدد";
    try {
      formattedCompletion = new Intl.DateTimeFormat('ar-SA-u-ca-islamic-uma-nu-latn', { day: 'numeric', month: 'long', year: 'numeric' }).format(completionDate);
    } catch (e) { formattedCompletion = completionDate.toLocaleDateString('ar-EG'); }
    return { percentage, daysLeft, formattedCompletion };
  }, [log.quranEnd, dailyGoal]);

  return (
    <div className="space-y-6 pb-12 animate-fade-in relative">
      {/* Header Banner */}
      <div className="bg-white dark:bg-[#1a1a1a] border border-yellow-600/30 dark:border-yellow-900/40 p-10 rounded-[2.5rem] relative overflow-hidden group shadow-2xl">
        <div className="absolute top-0 right-0 w-64 h-64 bg-yellow-500/10 rounded-full -mr-32 -mt-32 blur-[100px]"></div>
        <div className="relative z-10 text-center">
          <i className="fas fa-quote-right text-[#d4af37] text-4xl mb-6 opacity-30"></i>
          <p className="text-2xl md:text-4xl font-bold text-slate-800 dark:text-gray-100 leading-relaxed quran-font">{quote.text}</p>
          <div className="mt-8 flex items-center justify-center gap-4">
            <span className="text-sm text-yellow-700 dark:text-yellow-500 font-black uppercase tracking-widest">{quote.source}</span>
          </div>
        </div>
      </div>

