import React, { useMemo, useState } from 'react';
import { getLogs } from '../services/storageService';
import { DailyLog } from '../types';
import { PRAYER_TASKS, AZKAR_TASKS, GOOD_DEED_CATEGORIES, MUJAHADA_CATEGORIES } from '../constants';

interface BreakdownItem {
  label: string;
  points: number;
  type: 'pos' | 'neg';
  isFard?: boolean;
}

const History: React.FC = () => {
  const [startDate, setStartDate] = useState(() => {
    const d = new Date(); d.setDate(d.getDate() - 7);
    return d.toISOString().split('T')[0];
  });
  const [endDate, setEndDate] = useState(() => new Date().toISOString().split('T')[0]);
  const [isHijriMode, setIsHijriMode] = useState(true);
  const [activeBreakdownDate, setActiveBreakdownDate] = useState<string | null>(null);

  const logs = useMemo(() => getLogs(), []);
  const filteredDates = useMemo(() => Object.keys(logs).filter(date => date >= startDate && date <= endDate).sort((a, b) => b.localeCompare(a)), [logs, startDate, endDate]);

  const calculateScore = (log: DailyLog) => {
    let currentScore = 0;
    const fardIds = ['fajr', 'dhuhr', 'asr', 'maghrib', 'isha'];
    fardIds.forEach(id => currentScore += log.prayers.includes(id) ? 10 : -10);
    currentScore += (log.prayers.filter(id => !fardIds.includes(id)).length + log.azkar.length + log.goodDeeds.length + log.notes.length) * 10;
    currentScore -= (log.mujahada.length + log.mujahadaNotes.length) * 10;
    return currentScore;
  };

  const getDayBreakdown = (date: string): BreakdownItem[] => {
    const log = logs[date];
    if (!log) return [];
    const items: BreakdownItem[] = [];
    const fardIds = ['fajr', 'dhuhr', 'asr', 'maghrib', 'isha'];

    fardIds.forEach(id => items.push({ label: PRAYER_TASKS.find(t => t.id === id)?.label || id, points: log.prayers.includes(id) ? 10 : -10, type: log.prayers.includes(id) ? 'pos' : 'neg', isFard: true }));
    log.prayers.filter(id => !fardIds.includes(id)).forEach(id => items.push({ label: PRAYER_TASKS.find(t => t.id === id)?.label || id, points: 10, type: 'pos' }));
    log.azkar.forEach(id => items.push({ label: AZKAR_TASKS.find(t => t.id === id)?.label || id, points: 10, type: 'pos' }));

    // فحص أعمال البر من الفئات
    log.goodDeeds.forEach(id => {
      let task = null;
      for (const cat of GOOD_DEED_CATEGORIES) { task = cat.tasks.find(t => t.id === id); if (task) break; }
      items.push({ label: task?.label || id, points: 10, type: 'pos' });
    });
    log.notes.forEach(note => items.push({ label: note, points: 10, type: 'pos' }));

    // فحص المجاهدة من الفئات
    log.mujahada.forEach(id => {
      let task = null;
      for (const cat of MUJAHADA_CATEGORIES) { task = cat.tasks.find(t => t.id === id); if (task) break; }
      items.push({ label: task?.label || id, points: -10, type: 'neg' });
    });
    log.mujahadaNotes.forEach(note => items.push({ label: note, points: -10, type: 'neg' }));

    return items;
  };

  const formatArabicDate = (dateStr: string, forceHijri?: boolean) => {
    try {
      const date = new Date(dateStr);
      const calendar = (forceHijri ?? isHijriMode) ? 'islamic-uma' : 'gregory';
      return new Intl.DateTimeFormat(`ar-SA-u-ca-${calendar}-nu-latn`, { day: 'numeric', month: 'long', year: 'numeric' }).format(date);
    } catch (e) { return dateStr; }
  };

  return (
    <div className="animate-fade-in space-y-6 pb-12">
      {/* Modal Breakdown */}
      {activeBreakdownDate && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm" onClick={() => setActiveBreakdownDate(null)}>
          <div className="bg-white dark:bg-[#1a1a1a] w-full max-w-lg rounded-[2.5rem] shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
            <div className="p-6 bg-yellow-600 text-white flex items-center justify-between">
              <div><h2 className="text-xl font-black">تفاصيل اليوم</h2><span className="text-xs opacity-80">{formatArabicDate(activeBreakdownDate)}</span></div>
              <button onClick={() => setActiveBreakdownDate(null)} className="w-8 h-8 rounded-full bg-white/20"><i className="fas fa-times"></i></button>
            </div>
            <div className="p-6 max-h-[60vh] overflow-y-auto space-y-2">
              {getDayBreakdown(activeBreakdownDate).map((item, idx) => (
                <div key={idx} className={`flex items-center justify-between p-3 rounded-xl border ${item.type === 'pos' ? 'bg-emerald-50 border-emerald-100' : 'bg-red-50 border-red-100'}`}>
                  <span className="text-sm font-bold text-slate-800">{item.label} {item.isFard && <small className="text-gray-400 block text-[8px] uppercase">فرض</small>}</span>
                  <span className={`text-sm font-black ${item.type === 'pos' ? 'text-emerald-600' : 'text-red-600'}`}>{item.points > 0 ? `+${item.points}` : item.points}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Stats Header */}
      <div className="bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-3xl p-8 text-center shadow-xl">
        <h2 className="text-gray-500 text-[10px] mb-2 font-black tracking-widest uppercase">رصيد النقاط الكلي</h2>
        <div className="text-6xl font-black gold-gradient mb-2">{filteredDates.reduce((acc, date) => acc + calculateScore(logs[date]), 0)}</div>
        <div className="text-[11px] text-yellow-700 bg-yellow-50 px-4 py-1.5 rounded-full inline-flex mx-auto border border-yellow-100">
          <i className="fas fa-calendar-alt mr-2"></i> من {formatArabicDate(startDate)} إلى {formatArabicDate(endDate)}
        </div>
      </div>

      {/* Date Filter */}
      <div className="flex flex-col md:flex-row gap-4 items-center bg-white dark:bg-[#151515] p-4 rounded-2xl border border-gray-100 dark:border-gray-800">
        <div className="grid grid-cols-2 gap-3 w-full">
          <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="bg-gray-50 dark:bg-[#1a1a1a] p-3 rounded-xl text-xs font-bold" />
          <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="bg-gray-50 dark:bg-[#1a1a1a] p-3 rounded-xl text-xs font-bold" />
        </div>
        <button onClick={() => setIsHijriMode(!isHijriMode)} className="px-6 py-3 bg-slate-800 text-white rounded-xl shadow-lg font-bold text-sm w-full md:w-auto">التقويم {isHijriMode ? 'الهجري' : 'الميلادي'}</button>
      </div>

      {/* Compact Log Table */}
      <div className="bg-white dark:bg-[#151515] rounded-2xl overflow-x-auto shadow-lg border border-gray-100 dark:border-gray-800">
        <table className="w-full text-right min-w-[600px]">
          <thead>
            <tr className="bg-gray-50 dark:bg-[#1a1a1a] text-[10px] text-gray-500 uppercase font-black">
              <th className="p-5">التاريخ</th>
              <th className="p-5">القرآن</th>
              <th className="p-5">الطاعات</th>
              <th className="p-5">الزلات</th>
              <th className="p-5 text-center">النتيجة</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
            {filteredDates.map(date => {
              const log = logs[date];
              const score = calculateScore(log);
              return (
                <tr key={date} className="hover:bg-gray-50 transition-colors">
                  <td className="p-5"><div className="text-xs font-black">{formatArabicDate(date)}</div></td>
                  <td className="p-5 text-xs text-yellow-600 font-bold">{log.quranEnd > 0 ? `ص ${log.quranEnd}` : '-'}</td>
                  <td className="p-5 text-xs text-emerald-600 font-bold">{(log.prayers.length + log.azkar.length + log.goodDeeds.length + log.notes.length)}</td>
                  <td className="p-5 text-xs text-red-600 font-bold">{(log.mujahada.length + log.mujahadaNotes.length)}</td>
                  <td className="p-5 text-center">
                    <button onClick={() => setActiveBreakdownDate(date)} className={`px-4 py-2 rounded-xl text-xs font-black shadow-sm ${score >= 0 ? 'bg-emerald-500' : 'bg-red-500'} text-white`}>
                      {score > 0 ? `+${score}` : score} <i className="fas fa-info-circle ml-1 opacity-60"></i>
                    </button>
                  </td>
                </tr>
              )
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

