import React, { useState, useEffect, useMemo } from 'react';
import { 
  PRAYER_TASKS, 
  AZKAR_CATEGORIES, 
  GOOD_DEED_CATEGORIES, 
  MUJAHADA_CATEGORIES, 
  MOTIVATIONAL_QUOTES,
  SECTION_INFO
} from '../constants';
import { getLogForDate, saveLog, formatDate } from '../services/storageService';
import SectionCard from '../components/SectionCard';
import { DailyLog } from '../types';

const Dashboard: React.FC = () => {
  const [currentDate] = useState(formatDate(new Date()));
  const [log, setLog] = useState<DailyLog>(getLogForDate(currentDate));

  // حالات الأكورديون الداخلية
  const [openAzkarCategory, setOpenAzkarCategory] = useState<number | null>(null);
  const [openDeedCategory, setOpenDeedCategory] = useState<number | null>(null);
  const [openMujahadaCategory, setOpenMujahadaCategory] = useState<number | null>(null);

  // حالات الإدخال اليدوي
  const [manualInputs, setManualInputs] = useState<Record<string, string>>({});

  const dailyGoal = useMemo(() => parseInt(localStorage.getItem('quran_daily_goal') || "20"), []);
  const dailyRotationIndex = useMemo(() => new Date().getDate(), []);
  const quote = useMemo(() => MOTIVATIONAL_QUOTES[dailyRotationIndex % MOTIVATIONAL_QUOTES.length], [dailyRotationIndex]);

  const getDailyInfo = (section: keyof typeof SECTION_INFO) => [SECTION_INFO[section][dailyRotationIndex % SECTION_INFO[section].length]];

  useEffect(() => { saveLog(log); }, [log]);

  const toggleTask = (section: keyof DailyLog, id: string) => {
    setLog(prev => {
      const currentList = prev[section] as string[];
      const newList = currentList.includes(id) ? currentList.filter(item => item !== id) : [...currentList, id];
      return { ...prev, [section]: newList };
    });
  };

  const addManualEntry = (type: 'notes' | 'mujahadaNotes', categoryIndex: number) => {
    const key = `${type}-${categoryIndex}`;
    const value = manualInputs[key];
    if (!value || !value.trim()) return;

    setLog(prev => ({ ...prev, [type]: [...prev[type], value.trim()] }));
    setManualInputs(prev => ({ ...prev, [key]: '' }));
  };

  const score = useMemo(() => {
    let currentScore = 0;
    const fardIds = ['fajr', 'dhuhr', 'asr', 'maghrib', 'isha'];
    fardIds.forEach(id => currentScore += log.prayers.includes(id) ? 10 : -10);
    currentScore += (log.prayers.filter(id => !fardIds.includes(id)).length + log.azkar.length + log.goodDeeds.length + log.notes.length) * 10;
    currentScore -= (log.mujahada.length + log.mujahadaNotes.length) * 10;
    return currentScore;
  }, [log]);

  const quranProgress = useMemo(() => {
    const percentage = (log.quranEnd / 604) * 100;
    const totalRemaining = 604 - log.quranEnd;
    const daysLeft = dailyGoal > 0 ? Math.ceil(totalRemaining / dailyGoal) : 0;
    const completionDate = new Date();
    completionDate.setDate(completionDate.getDate() + daysLeft);
    let formattedCompletion = "غير محدد";
    try {
      formattedCompletion = new Intl.DateTimeFormat('ar-SA-u-ca-islamic-uma-nu-latn', { day: 'numeric', month: 'long', year: 'numeric' }).format(completionDate);
    } catch (e) { formattedCompletion = completionDate.toLocaleDateString('ar-EG'); }
    return { percentage, daysLeft, formattedCompletion };
  }, [log.quranEnd, dailyGoal]);

  return (
    <div className="space-y-6 pb-12 animate-fade-in relative">
      {/* Header Banner */}
      <div className="bg-white dark:bg-[#1a1a1a] border border-yellow-600/30 dark:border-yellow-900/40 p-10 rounded-[2.5rem] relative overflow-hidden group shadow-2xl">
        <div className="absolute top-0 right-0 w-64 h-64 bg-yellow-500/10 rounded-full -mr-32 -mt-32 blur-[100px]"></div>
        <div className="relative z-10 text-center">
          <i className="fas fa-quote-right text-[#d4af37] text-4xl mb-6 opacity-30"></i>
          <p className="text-2xl md:text-4xl font-bold text-slate-800 dark:text-gray-100 leading-relaxed quran-font">{quote.text}</p>
          <div className="mt-8 flex items-center justify-center gap-4">
            <span className="text-sm text-yellow-700 dark:text-yellow-500 font-black uppercase tracking-widest">{quote.source}</span>
          </div>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
        {[
          { label: 'نقاط اليوم', value: score, highlight: true, icon: 'fa-star', theme: 'gold' },
          { label: 'تقدم الختمة', value: `${Math.round(quranProgress.percentage)}%`, highlight: false, icon: 'fa-book-quran', theme: 'default' },
          { label: 'الزلات', value: log.mujahada.length + log.mujahadaNotes.length, highlight: false, icon: 'fa-triangle-exclamation', theme: 'danger' },
          { label: 'إجمالي الطاعات', value: log.prayers.length + log.azkar.length, highlight: false, icon: 'fa-pray', theme: 'default' },
          { label: 'أعمال البر', value: log.goodDeeds.length + log.notes.length, highlight: false, icon: 'fa-heart', theme: 'default' },
        ].map((stat, idx) => (
          <div key={idx} className="bg-white dark:bg-[#151515] p-5 rounded-3xl border border-gray-100 dark:border-gray-800 flex flex-col items-center justify-center shadow-lg transition-all hover:-translate-y-1">
            <i className={`fas ${stat.icon} text-[10px] mb-2 ${stat.theme === 'danger' ? 'text-red-500/60' : 'text-yellow-600/60'}`}></i>
            <span className="text-gray-400 dark:text-gray-500 text-[9px] mb-1 font-black uppercase text-center">{stat.label}</span>
            <span className={`text-3xl font-black ${stat.theme === 'gold' ? 'gold-gradient' : stat.theme === 'danger' ? 'text-red-600' : 'text-slate-800 dark:text-gray-100'}`}>{stat.value}</span>
          </div>
        ))}
      </div>

      {/* Main Sections */}
      <div className="grid md:grid-cols-2 gap-6">
        {/* Quran Section */}
        <SectionCard title="ورد القرآن الكريم" icon="fa-book-open-reader" infoItems={getDailyInfo('QURAN')}>
          <div className="space-y-4">
             <div className="grid grid-cols-2 gap-4">
              <input type="number" value={log.quranStart || ""} onChange={(e) => setLog(prev => ({...prev, quranStart: parseInt(e.target.value) || 0}))} className="bg-gray-50 dark:bg-[#1a1a1a] p-4 rounded-xl text-center font-black text-yellow-600" placeholder="من صفحة" />
              <input type="number" value={log.quranEnd || ""} onChange={(e) => setLog(prev => ({...prev, quranEnd: parseInt(e.target.value) || 0}))} className="bg-gray-50 dark:bg-[#1a1a1a] p-4 rounded-xl text-center font-black text-yellow-600" placeholder="إلى صفحة" />
             </div>
             <div className="bg-yellow-600 p-4 rounded-2xl text-white text-center">
                <span className="text-[10px] font-black uppercase opacity-80">الموعد المتوقع للختمة</span>
                <p className="text-lg font-black">{quranProgress.formattedCompletion}</p>
             </div>
          </div>
        </SectionCard>

        {/* Prayer Section */}
        <SectionCard title="قسم الصلاة" icon="fa-mosque" infoItems={getDailyInfo('PRAYER')}>
          <div className="grid grid-cols-2 gap-2">
            {PRAYER_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-3 rounded-xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-yellow-50 transition-all">
                <input type="checkbox" checked={log.prayers.includes(task.id)} onChange={() => toggleTask('prayers', task.id)} className="w-4 h-4 text-yellow-600" />
                <span className="text-xs font-bold text-slate-700 dark:text-gray-200">{task.label}</span>
              </label>
            ))}
          </div>
        </SectionCard>

        {/* Azkar Section - WITH ACCORDION */}
        <SectionCard title="قسم الأذكار" icon="fa-hands-praying" infoItems={getDailyInfo('AZKAR')}>
          <div className="space-y-3">
            {AZKAR_CATEGORIES.map((cat, idx) => (
              <div key={idx} className="border border-gray-100 dark:border-gray-800 rounded-2xl overflow-hidden shadow-sm">
                <button 
                  onClick={() => setOpenAzkarCategory(openAzkarCategory === idx ? null : idx)}
                  className="w-full flex items-center justify-between p-4 bg-purple-50/30 dark:bg-[#1a1a1a] hover:bg-purple-50 transition-colors"
                >
                  <span className="text-sm font-black text-purple-700 dark:text-purple-500">{cat.category}</span>
                  <i className={`fas fa-chevron-down text-xs transition-transform ${openAzkarCategory === idx ? 'rotate-180' : ''}`}></i>
                </button>
                {openAzkarCategory === idx && (
                  <div className="p-4 bg-white dark:bg-[#151515] space-y-2 animate-fade-in">
                    {cat.tasks.map(task => (
