export default History;

import React, { useMemo, useState } from 'react';
import { getLogs } from '../services/storageService';
import { DailyLog } from '../types';
import { PRAYER_TASKS, AZKAR_CATEGORIES, GOOD_DEED_CATEGORIES, MUJAHADA_CATEGORIES } from '../constants';

interface BreakdownItem {
  label: string;
  points: number;
  type: 'pos' | 'neg';
  category: string;
}

const History: React.FC = () => {
  const [startDate, setStartDate] = useState(() => {
    const d = new Date(); d.setDate(d.getDate() - 7);
    return d.toISOString().split('T')[0];
  });
  const [endDate, setEndDate] = useState(() => new Date().toISOString().split('T')[0]);
  const [isHijriMode, setIsHijriMode] = useState(true);
  const [activeBreakdownDate, setActiveBreakdownDate] = useState<string | null>(null);

  const logs = useMemo(() => getLogs(), []);
  const filteredDates = useMemo(() => Object.keys(logs).filter(date => date >= startDate && date <= endDate).sort((a, b) => b.localeCompare(a)), [logs, startDate, endDate]);

  const getDayDetails = (log: DailyLog) => {
    const posItems: BreakdownItem[] = [];
    const negItems: BreakdownItem[] = [];
    const fardIds = ['fajr', 'dhuhr', 'asr', 'maghrib', 'isha'];

    // الصلاة
    fardIds.forEach(id => {
      const task = PRAYER_TASKS.find(t => t.id === id);
      if (log.prayers.includes(id)) {
        posItems.push({ label: task?.label || id, points: 10, type: 'pos', category: 'الصلاة' });
      } else {
        negItems.push({ label: `فوات ${task?.label || id}`, points: -10, type: 'neg', category: 'الصلاة' });
      }
    });
    log.prayers.filter(id => !fardIds.includes(id)).forEach(id => {
      const task = PRAYER_TASKS.find(t => t.id === id);
      posItems.push({ label: task?.label || id, points: 10, type: 'pos', category: 'السنن والنوافل' });
    });

    // الأذكار
    log.azkar.forEach(id => {
      let task = null;
      for (const cat of AZKAR_CATEGORIES) { task = cat.tasks.find(t => t.id === id); if (task) break; }
      posItems.push({ label: task?.label || id, points: 10, type: 'pos', category: 'الأذكار' });
    });

    // أعمال البر
    log.goodDeeds.forEach(id => {
      let task = null;
      for (const cat of GOOD_DEED_CATEGORIES) { task = cat.tasks.find(t => t.id === id); if (task) break; }
      posItems.push({ label: task?.label || id, points: 10, type: 'pos', category: 'أعمال البر' });
    });
    log.notes.forEach(note => posItems.push({ label: note, points: 10, type: 'pos', category: 'أعمال بر يدوية' }));

    // القرآن
    if (log.quranEnd > log.quranStart) posItems.push({ label: `قراءة القرآن (${log.quranEnd - log.quranStart} ص)`, points: 10, type: 'pos', category: 'القرآن' });
    if (log.quranTadabburNote) posItems.push({ label: 'خاطرة تدبر', points: 10, type: 'pos', category: 'القرآن' });
    if (log.quranActionNote) posItems.push({ label: 'تطبيق عملي لآية', points: 10, type: 'pos', category: 'القرآن' });
    if (log.quranListening) posItems.push({ label: 'سماع القرآن', points: 10, type: 'pos', category: 'القرآن' });
    if (log.quranSujudCount > 0) posItems.push({ label: `سجدة تلاوة (${log.quranSujudCount})`, points: 10, type: 'pos', category: 'القرآن' });

    // المجاهدة
    log.mujahada.forEach(id => {
      let task = null;
      for (const cat of MUJAHADA_CATEGORIES) { task = cat.tasks.find(t => t.id === id); if (task) break; }
      negItems.push({ label: task?.label || id, points: -10, type: 'neg', category: 'المجاهدة' });
    });
    log.mujahadaNotes.forEach(note => negItems.push({ label: note, points: -10, type: 'neg', category: 'مجاهدة يدوية' }));

    const posTotal = posItems.reduce((acc, item) => acc + item.points, 0);
    const negTotal = negItems.reduce((acc, item) => acc + item.points, 0);
    const netTotal = posTotal + negTotal;

    return { posItems, negItems, posTotal, negTotal, netTotal };
  };

  // وظيفة محسنة لتنسيق التاريخ تدعم تقويم أم القرى المتوافق مع 2026
  const formatArabicDate = (dateStr: string, forceHijri?: boolean) => {
    try {
      const date = new Date(dateStr);
      const useHijri = forceHijri ?? isHijriMode;
      const calendar = useHijri ? 'islamic-uma' : 'gregory';

      return new Intl.DateTimeFormat(`ar-SA-u-ca-${calendar}-nu-latn`, { 
        day: 'numeric', 
        month: 'long', 
        year: 'numeric',
        weekday: 'long'
      }).format(date);
    } catch (e) { return dateStr; }
  };

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="animate-fade-in space-y-6 pb-12 print:p-0">
      {/* Detailed Modal */}
      {activeBreakdownDate && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm" onClick={() => setActiveBreakdownDate(null)}>
          <div className="bg-white dark:bg-[#1a1a1a] w-full max-w-2xl rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh]" onClick={e => e.stopPropagation()}>
            <div className="p-6 bg-gradient-to-r from-yellow-700 to-yellow-600 text-white flex items-center justify-between">
              <div>
                <h2 className="text-xl font-black">تقرير الحصاد اليومي</h2>
                <div className="flex flex-col text-[10px] opacity-90 font-bold">
                   <span>{formatArabicDate(activeBreakdownDate, false)}</span>
                   <span>{formatArabicDate(activeBreakdownDate, true)}</span>
                </div>
              </div>
              <button onClick={() => setActiveBreakdownDate(null)} className="w-10 h-10 rounded-full bg-white/20 hover:bg-white/30 transition-colors flex items-center justify-center">
                <i className="fas fa-times"></i>
              </button>
            </div>

            <div className="flex-grow overflow-y-auto p-6 space-y-6">
              {/* Score Summary */}
              <div className="grid grid-cols-3 gap-3">
                <div className="bg-emerald-50 dark:bg-emerald-900/10 p-4 rounded-2xl text-center border border-emerald-100 dark:border-emerald-900/20">
                  <span className="text-[10px] font-black text-emerald-600 block mb-1">الإيجابي</span>
                  <span className="text-2xl font-black text-emerald-600">+{getDayDetails(logs[activeBreakdownDate]).posTotal}</span>
                </div>
                <div className="bg-red-50 dark:bg-red-900/10 p-4 rounded-2xl text-center border border-red-100 dark:border-red-900/20">
                  <span className="text-[10px] font-black text-red-600 block mb-1">السلبي</span>
                  <span className="text-2xl font-black text-red-600">{getDayDetails(logs[activeBreakdownDate]).negTotal}</span>
                </div>
                <div className="bg-yellow-50 dark:bg-yellow-900/10 p-4 rounded-2xl text-center border border-yellow-100 dark:border-yellow-900/20">
                  <span className="text-[10px] font-black text-yellow-600 block mb-1">الصافي</span>
                  <span className="text-2xl font-black text-yellow-600">{getDayDetails(logs[activeBreakdownDate]).netTotal}</span>
                </div>
              </div>

              {/* Items List */}
              <div className="space-y-4">
                <div className="space-y-2">
                  <h3 className="text-xs font-black text-emerald-600 uppercase border-r-4 border-emerald-500 pr-2">الحسنات والطاعات</h3>
                  {getDayDetails(logs[activeBreakdownDate]).posItems.length > 0 ? getDayDetails(logs[activeBreakdownDate]).posItems.map((item, idx) => (
                    <div key={idx} className="flex justify-between items-center bg-gray-50 dark:bg-gray-800/50 p-3 rounded-xl">
                      <div>
                        <span className="text-xs font-bold block">{item.label}</span>
                        <span className="text-[9px] text-gray-400">{item.category}</span>
                      </div>
                      <span className="text-emerald-600 font-black text-sm">+{item.points}</span>
                    </div>
                  )) : <div className="text-center py-4 text-gray-400 text-xs">لا توجد أعمال مسجلة</div>}
                </div>

                <div className="space-y-2">
                  <h3 className="text-xs font-black text-red-600 uppercase border-r-4 border-red-500 pr-2">الزلات والمجاهدة</h3>
                  {getDayDetails(logs[activeBreakdownDate]).negItems.length > 0 ? getDayDetails(logs[activeBreakdownDate]).negItems.map((item, idx) => (
                    <div key={idx} className="flex justify-between items-center bg-gray-50 dark:bg-gray-800/50 p-3 rounded-xl">
                      <div>
                        <span className="text-xs font-bold block">{item.label}</span>
                        <span className="text-[9px] text-gray-400">{item.category}</span>
                      </div>
                      <span className="text-red-600 font-black text-sm">{item.points}</span>
                    </div>
                  )) : <div className="text-center py-4 text-gray-400 text-xs">الحمد لله، لا توجد زلات مسجلة</div>}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Stats Header */}
      <div className="bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-3xl p-8 text-center shadow-xl print:shadow-none relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-yellow-500/5 rounded-full -mr-16 -mt-16 blur-3xl"></div>
        <h2 className="text-gray-500 text-[10px] mb-2 font-black tracking-widest uppercase">رصيد النقاط الكلي</h2>
        <div className="text-6xl font-black gold-gradient mb-2">{filteredDates.reduce((acc, date) => acc + getDayDetails(logs[date]).netTotal, 0)}</div>
        <div className="flex flex-col sm:flex-row items-center justify-center gap-3 relative z-10">
          <div className="text-[11px] text-yellow-700 bg-yellow-50 dark:bg-yellow-900/10 px-4 py-1.5 rounded-full border border-yellow-100 dark:border-yellow-900/20 font-bold">
            <i className="fas fa-calendar-alt mr-2"></i> {formatArabicDate(startDate)} - {formatArabicDate(endDate)}
          </div>
          <button onClick={handlePrint} className="text-[11px] bg-slate-800 text-white px-5 py-2 rounded-full hover:bg-slate-700 transition-all flex items-center gap-2 print:hidden shadow-lg shadow-slate-900/10">
            <i className="fas fa-file-pdf"></i> مشاركة التقرير
          </button>
        </div>
      </div>

      {/* Date Filter */}
      <div className="flex flex-col md:flex-row gap-4 items-center bg-white dark:bg-[#151515] p-5 rounded-2xl border border-gray-100 dark:border-gray-800 print:hidden shadow-sm">
        <div className="grid grid-cols-2 gap-4 w-full">
          <div className="flex flex-col group">
            <label className="text-[9px] font-black text-gray-400 uppercase mb-1.5 pr-1 flex items-center gap-2">
               <i className="fas fa-calendar-day text-yellow-600"></i> من تاريخ
            </label>
            <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="bg-gray-50 dark:bg-[#1a1a1a] p-3 rounded-xl text-xs font-bold outline-none border border-transparent focus:border-yellow-500/50 transition-all" />
            <span className="text-[9px] text-yellow-700 dark:text-yellow-500 font-bold mt-2 pr-1 bg-yellow-50 dark:bg-yellow-900/20 py-1 px-2 rounded-lg self-start">
              {formatArabicDate(startDate)}
            </span>
          </div>
          <div className="flex flex-col group">
            <label className="text-[9px] font-black text-gray-400 uppercase mb-1.5 pr-1 flex items-center gap-2">
               <i className="fas fa-calendar-check text-yellow-600"></i> إلى تاريخ
            </label>
            <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="bg-gray-50 dark:bg-[#1a1a1a] p-3 rounded-xl text-xs font-bold outline-none border border-transparent focus:border-yellow-500/50 transition-all" />
            <span className="text-[9px] text-yellow-700 dark:text-yellow-500 font-bold mt-2 pr-1 bg-yellow-50 dark:bg-yellow-900/20 py-1 px-2 rounded-lg self-start">
              {formatArabicDate(endDate)}
            </span>
          </div>
        </div>
        <button 
          onClick={() => setIsHijriMode(!isHijriMode)} 
          className="px-8 py-4 bg-yellow-600 text-white rounded-2xl shadow-xl shadow-yellow-600/10 font-black text-sm w-full md:w-auto hover:bg-yellow-700 hover:-translate-y-0.5 transition-all whitespace-nowrap active:scale-95"
        >
          {isHijriMode ? 'عرض بالميلادي' : 'عرض بالهجري'}
        </button>
      </div>

      {/* Main History Table */}
      <div className="bg-white dark:bg-[#151515] rounded-3xl overflow-hidden shadow-xl border border-gray-100 dark:border-gray-800">
        <div className="overflow-x-auto">
          <table className="w-full text-right min-w-[950px] border-collapse">
            <thead>
              <tr className="bg-gray-50 dark:bg-[#1a1a1a] text-[10px] text-gray-500 uppercase font-black">
                <th className="p-6 border-l border-gray-100 dark:border-gray-800">التاريخ ({isHijriMode ? 'هجري' : 'ميلادي'})</th>
                <th className="p-6">القرآن</th>
                <th className="p-6">الصلوات</th>
                <th className="p-6">الأذكار</th>
                <th className="p-6">أعمال البر</th>
                <th className="p-6">المجاهدة</th>
                <th className="p-6 text-center">الصافي</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
              {filteredDates.map(date => {
                const log = logs[date];
                const { netTotal } = getDayDetails(log);
                return (
                  <tr key={date} onClick={() => setActiveBreakdownDate(date)} className="hover:bg-yellow-50/30 dark:hover:bg-yellow-900/5 transition-all cursor-pointer group">
                    <td className="p-6 border-l border-gray-100 dark:border-gray-800">
                      <div className="flex flex-col">
                        <span className="text-xs font-black text-slate-800 dark:text-gray-100 leading-tight">
                           {formatArabicDate(date)}
                        </span>
                        {!isHijriMode && <span className="text-[8px] text-gray-400 mt-0.5">{formatArabicDate(date, true)}</span>}
                        {isHijriMode && <span className="text-[8px] text-gray-400 mt-0.5">{formatArabicDate(date, false)}</span>}
                      </div>
                    </td>
                    <td className="p-6">
                      <div className="text-[10px] font-bold text-yellow-600 leading-tight">
                        {log.quranEnd > log.quranStart ? (
                          <div className="flex items-center gap-1.5 bg-yellow-50 dark:bg-yellow-900/20 py-1 px-2 rounded-lg w-fit">
                            <i className="fas fa-book-quran opacity-70"></i>
                            ص {log.quranStart}-{log.quranEnd}
                          </div>
                        ) : <span className="text-gray-300">-</span>}
                      </div>
                    </td>
                    <td className="p-6">
                      <div className="flex items-center gap-1.5 max-w-[150px]">
                        {['fajr', 'dhuhr', 'asr', 'maghrib', 'isha'].map(f => (
                          <div 
                            key={f} 
                            title={PRAYER_TASKS.find(t=>t.id===f)?.label} 
                            className={`w-3 h-3 rounded-full border-2 ${log.prayers.includes(f) ? 'bg-emerald-500 border-emerald-200' : 'bg-red-500/20 border-red-500/40'}`}
                          ></div>
                        ))}
                        {log.prayers.length > 5 && (
                          <span className="text-[9px] font-black bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 px-1.5 py-0.5 rounded-md">
                            +{log.prayers.length - 5} نوافل
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="p-6">
                      <span className="text-[10px] font-black bg-purple-50 dark:bg-purple-900/20 text-purple-600 px-3 py-1.5 rounded-xl border border-purple-100 dark:border-purple-900/30">
                        {log.azkar.length} ذِكراً
                      </span>
                    </td>
                    <td className="p-6">
                      <div className="flex items-center gap-4">
                        <span className="text-[10px] font-black bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 px-3 py-1.5 rounded-xl border border-emerald-100 dark:border-emerald-900/30 min-w-[60px] text-center">
                          {log.goodDeeds.length + log.notes.length} عملاً
                        </span>
                        <button 
                          onClick={(e) => { e.stopPropagation(); setActiveBreakdownDate(date); }}
                          className="w-8 h-8 rounded-full bg-emerald-500 text-white flex items-center justify-center hover:bg-emerald-600 hover:scale-110 transition-all shadow-md shadow-emerald-600/20"
                          title="تفاصيل أعمال البر"
                        >
                           <i className="fas fa-eye text-xs"></i>
                        </button>
                      </div>
                    </td>
                    <td className="p-6">
                      <div className="flex items-center gap-4">
                        <span className={`text-[10px] font-black px-3 py-1.5 rounded-xl border min-w-[60px] text-center ${log.mujahada.length + log.mujahadaNotes.length > 0 ? 'bg-red-50 dark:bg-red-900/20 text-red-600 border-red-100 dark:border-red-900/30' : 'text-gray-300 border-gray-100 dark:border-gray-800'}`}>
                          {log.mujahada.length + log.mujahadaNotes.length} زلات
                        </span>
                        {log.mujahada.length + log.mujahadaNotes.length > 0 && (
                          <button 
                            onClick={(e) => { e.stopPropagation(); setActiveBreakdownDate(date); }}
                            className="w-8 h-8 rounded-full bg-red-500 text-white flex items-center justify-center hover:bg-red-600 hover:scale-110 transition-all shadow-md shadow-red-600/20"
                            title="تفاصيل الزلات"
                          >
                            <i className="fas fa-eye text-xs"></i>
                          </button>
                        )}
                      </div>
                    </td>
                    <td className="p-6 text-center">
                      <span className={`inline-block px-4 py-2 rounded-2xl text-xs font-black shadow-lg ${netTotal >= 0 ? 'bg-gradient-to-br from-emerald-500 to-emerald-600' : 'bg-gradient-to-br from-red-500 to-red-600'} text-white min-w-[65px]`}>
                        {netTotal > 0 ? `+${netTotal}` : netTotal}
                      </span>
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>
      </div>

      <style>{`
        @media print {
          nav, header, .print\\:hidden { display: none !important; }
          body { background: white !important; padding: 20px !important; color: black !important; }
          .bg-white, .bg-gray-50 { background: white !important; border-color: #eee !important; }
          .gold-gradient { -webkit-text-fill-color: #000 !important; color: #000 !important; font-weight: 900 !important; }
          .rounded-3xl, .rounded-2xl { border-radius: 8px !important; border: 1px solid #eee !important; }
          table { width: 100% !important; border-collapse: collapse !important; }
          th, td { border: 1px solid #eee !important; padding: 12px !important; text-align: right !important; }
          .quran-font { font-family: 'Amiri', serif !important; }
        }
      `}</style>
    </div>
  );
};

export default History;

import React, { useMemo, useState } from 'react';
import { getLogs } from '../services/storageService';
import { DailyLog } from '../types';
import { PRAYER_TASKS, AZKAR_CATEGORIES, GOOD_DEED_CATEGORIES, MUJAHADA_CATEGORIES } from '../constants';

interface BreakdownItem {
  label: string;
  points: number;
  type: 'pos' | 'neg';
  category: string;
}

const History: React.FC = () => {
  // تخزين التواريخ بصيغة ISO (ميلادي) لضمان استقرار البيانات في الذاكرة
  const [startDate, setStartDate] = useState(() => {
    const d = new Date(); d.setDate(d.getDate() - 7);
    return d.toISOString().split('T')[0];
  });
  const [endDate, setEndDate] = useState(() => new Date().toISOString().split('T')[0]);
  const [isHijriMode, setIsHijriMode] = useState(true);
  const [activeBreakdownDate, setActiveBreakdownDate] = useState<string | null>(null);

  const logs = useMemo(() => getLogs(), []);

  // فلترة التواريخ بناءً على النطاق الميلادي المختار
  const filteredDates = useMemo(() => {
    return Object.keys(logs)
      .filter(date => date >= startDate && date <= endDate)
      .sort((a, b) => b.localeCompare(a));
  }, [logs, startDate, endDate]);

  // دالة تحويل وعرض التاريخ (هجري/ميلادي) بدقة عالية
  const formatArabicDate = (dateStr: string, forceHijri?: boolean) => {
    try {
      const date = new Date(dateStr);
      const useHijri = forceHijri ?? isHijriMode;
      // استخدام تقويم أم القرى لضمان توافق عام 2026 (رمضان 19 فبراير)
      const calendar = useHijri ? 'islamic-umalqura' : 'gregory';

      return new Intl.DateTimeFormat(`ar-SA-u-ca-${calendar}-nu-latn`, { 
        day: 'numeric', 
        month: 'long', 
        year: 'numeric',
        weekday: 'long'
      }).format(date);
    } catch (e) { return dateStr; }
  };

  const getDayDetails = (log: DailyLog) => {
    const posItems: BreakdownItem[] = [];
    const negItems: BreakdownItem[] = [];
    const fardIds = ['fajr', 'dhuhr', 'asr', 'maghrib', 'isha'];

    // 1. حساب الصلوات والخصم عند الترك
    fardIds.forEach(id => {
      const task = PRAYER_TASKS.find(t => t.id === id);
      if (log.prayers.includes(id)) {
        posItems.push({ label: task?.label || id, points: 10, type: 'pos', category: 'الصلاة المفروضة' });
      } else {
        negItems.push({ label: `ترك ${task?.label || id}`, points: -10, type: 'neg', category: 'الصلوات الفائتة' });
      }
    });

    // 2. النوافل والسنن
    log.prayers.filter(id => !fardIds.includes(id)).forEach(id => {
      const task = PRAYER_TASKS.find(t => t.id === id);
      posItems.push({ label: task?.label || id, points: 10, type: 'pos', category: 'السنن والنوافل' });
    });

    // 3. الأذكار
    log.azkar.forEach(id => {
      let task = null;
      for (const cat of AZKAR_CATEGORIES) { task = cat.tasks.find(t => t.id === id); if (task) break; }
      posItems.push({ label: task?.label || id, points: 10, type: 'pos', category: 'الأذكار' });
    });

    // 4. أعمال البر
    log.goodDeeds.forEach(id => {
      let task = null;
      for (const cat of GOOD_DEED_CATEGORIES) { task = cat.tasks.find(t => t.id === id); if (task) break; }
      posItems.push({ label: task?.label || id, points: 10, type: 'pos', category: 'أعمال البر' });
    });
    log.notes.forEach(note => posItems.push({ label: note, points: 10, type: 'pos', category: 'مبادرات إضافية' }));

    // 5. القرآن
    if (log.quranEnd > log.quranStart) posItems.push({ label: `قراءة القرآن (${log.quranEnd - log.quranStart} ص)`, points: 10, type: 'pos', category: 'القرآن' });
    if (log.quranTadabburNote) posItems.push({ label: 'خاطرة تدبر', points: 10, type: 'pos', category: 'القرآن' });
    if (log.quranActionNote) posItems.push({ label: 'تطبيق عملي لآية', points: 10, type: 'pos', category: 'القرآن' });
    if (log.quranListening) posItems.push({ label: 'سماع القرآن', points: 10, type: 'pos', category: 'القرآن' });
    if (log.quranSujudCount > 0) posItems.push({ label: `سجدة تلاوة (${log.quranSujudCount})`, points: 10, type: 'pos', category: 'القرآن' });

    // 6. المجاهدة والزلات
    log.mujahada.forEach(id => {
      let task = null;
      for (const cat of MUJAHADA_CATEGORIES) { task = cat.tasks.find(t => t.id === id); if (task) break; }
      negItems.push({ label: task?.label || id, points: -10, type: 'neg', category: 'مجاهدة النفس' });
    });
    log.mujahadaNotes.forEach(note => negItems.push({ label: note, points: -10, type: 'neg', category: 'زلات يدوية' }));

    const posTotal = posItems.reduce((acc, item) => acc + item.points, 0);
    const negTotal = negItems.reduce((acc, item) => acc + item.points, 0);
    const netTotal = posTotal + negTotal;

    return { posItems, negItems, posTotal, negTotal, netTotal };
  };

  const handlePrint = () => window.print();

  return (
    <div className="animate-fade-in space-y-6 pb-12 print:p-0">
      {/* النافذة المنبثقة للتفاصيل العميقة */}
      {activeBreakdownDate && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/70 backdrop-blur-md" onClick={() => setActiveBreakdownDate(null)}>
          <div className="bg-white dark:bg-[#1a1a1a] w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden flex flex-col max-h-[85vh] border border-yellow-600/20" onClick={e => e.stopPropagation()}>
            <div className="p-8 bg-gradient-to-r from-yellow-700 via-yellow-600 to-yellow-700 text-white relative">
              <div className="absolute top-0 right-0 w-32 h-full islamic-pattern opacity-10"></div>
              <div className="flex justify-between items-start relative z-10">
                <div>
                  <h2 className="text-2xl font-black mb-1">كشف حساب الطاعات</h2>
                  <div className="flex flex-col text-[10px] font-bold text-yellow-100/80">
                    <span>{formatArabicDate(activeBreakdownDate, false)}</span>
                    <span className="text-yellow-200">{formatArabicDate(activeBreakdownDate, true)}</span>
                  </div>
                </div>
                <button onClick={() => setActiveBreakdownDate(null)} className="w-12 h-12 rounded-2xl bg-white/20 hover:bg-white/40 flex items-center justify-center transition-all">
                  <i className="fas fa-times text-xl"></i>
                </button>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto p-8 space-y-8">
              <div className="grid grid-cols-3 gap-4">
                <div className="bg-emerald-50 dark:bg-emerald-900/10 p-5 rounded-3xl text-center border-2 border-emerald-100 dark:border-emerald-900/20">
                  <span className="text-[10px] font-black text-emerald-600 block mb-1 uppercase">إيجابي</span>
                  <span className="text-3xl font-black text-emerald-600">+{getDayDetails(logs[activeBreakdownDate]).posTotal}</span>
                </div>
                <div className="bg-red-50 dark:bg-red-900/10 p-5 rounded-3xl text-center border-2 border-red-100 dark:border-red-900/20">
                  <span className="text-[10px] font-black text-red-600 block mb-1 uppercase">سلبي</span>
                  <span className="text-3xl font-black text-red-600">{getDayDetails(logs[activeBreakdownDate]).negTotal}</span>
                </div>
                <div className="bg-yellow-50 dark:bg-yellow-900/10 p-5 rounded-3xl text-center border-2 border-yellow-100 dark:border-yellow-900/20 shadow-lg shadow-yellow-600/5">
                  <span className="text-[10px] font-black text-yellow-600 block mb-1 uppercase">الصافي</span>
                  <span className="text-3xl font-black text-yellow-600">{getDayDetails(logs[activeBreakdownDate]).netTotal}</span>
                </div>
              </div>

              <div className="space-y-6">
                <div className="space-y-3">
                  <h3 className="text-sm font-black text-emerald-700 flex items-center gap-2">
                    <i className="fas fa-plus-circle"></i> الحسنات والمنجزات
                  </h3>
                  {getDayDetails(logs[activeBreakdownDate]).posItems.length > 0 ? getDayDetails(logs[activeBreakdownDate]).posItems.map((item, idx) => (
                    <div key={idx} className="flex justify-between items-center bg-emerald-50/30 dark:bg-emerald-900/5 p-4 rounded-2xl border border-emerald-100/50">
                      <div>
                        <span className="text-xs font-bold block dark:text-gray-100">{item.label}</span>
                        <span className="text-[9px] text-gray-400 font-bold">{item.category}</span>
                      </div>
                      <span className="text-emerald-600 font-black text-base">+{item.points}</span>
                    </div>
                  )) : <div className="text-center py-6 text-gray-400 text-xs italic">لا توجد أعمال مسجلة لهذا اليوم</div>}
                </div>

                <div className="space-y-3">
                  <h3 className="text-sm font-black text-red-700 flex items-center gap-2">
                    <i className="fas fa-minus-circle"></i> الزلات والمقصرات
                  </h3>
                  {getDayDetails(logs[activeBreakdownDate]).negItems.length > 0 ? getDayDetails(logs[activeBreakdownDate]).negItems.map((item, idx) => (
                    <div key={idx} className="flex justify-between items-center bg-red-50/30 dark:bg-red-900/5 p-4 rounded-2xl border border-red-100/50">
                      <div>
                        <span className="text-xs font-bold block dark:text-gray-100">{item.label}</span>
                        <span className="text-[9px] text-gray-400 font-bold">{item.category}</span>
                      </div>
                      <span className="text-red-600 font-black text-base">{item.points}</span>
                    </div>
                  )) : <div className="text-center py-6 text-gray-400 text-xs italic">الحمد لله، خلوت من الزلات اليوم</div>}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* الرأس: الملخص الكلي */}
      <div className="bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-[2.5rem] p-10 text-center shadow-2xl print:shadow-none relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-yellow-600 via-yellow-400 to-yellow-600"></div>
        <h2 className="text-gray-400 text-[10px] mb-3 font-black tracking-[0.3em] uppercase">رصيد النقاط التراكمي</h2>
        <div className="text-7xl font-black gold-gradient mb-4 drop-shadow-sm">{filteredDates.reduce((acc, date) => acc + getDayDetails(logs[date]).netTotal, 0)}</div>
        <div className="flex flex-col sm:flex-row items-center justify-center gap-4 relative z-10">
          <div className="text-[11px] text-yellow-800 bg-yellow-50 dark:bg-yellow-900/20 px-6 py-2 rounded-full border border-yellow-200 font-black shadow-inner">
            <i className="fas fa-calendar-alt ml-2"></i> {formatArabicDate(startDate)} إلى {formatArabicDate(endDate)}
          </div>
          <button onClick={handlePrint} className="text-[11px] bg-slate-800 text-white px-6 py-2 rounded-full hover:bg-slate-700 transition-all flex items-center gap-2 print:hidden shadow-lg shadow-slate-900/20 active:scale-95">
            <i className="fas fa-file-pdf"></i> تصدير التقرير
          </button>
        </div>
      </div>

      {/* الفلتر الهجري/الميلادي */}
      <div className="bg-white dark:bg-[#151515] p-6 rounded-3xl border border-gray-100 dark:border-gray-800 print:hidden shadow-sm flex flex-col md:flex-row gap-6 items-end">
        <div className="grid grid-cols-2 gap-6 w-full">
          <div className="flex flex-col">
            <label className="text-[10px] font-black text-gray-400 uppercase mb-2 pr-1 flex items-center gap-2">
               <i className="fas fa-hourglass-start text-yellow-600"></i> من تاريخ
            </label>
            <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)} className="bg-gray-50 dark:bg-[#1a1a1a] p-4 rounded-2xl text-xs font-bold outline-none border-2 border-transparent focus:border-yellow-500/30 transition-all" />
            <div className="text-[10px] text-yellow-600 font-black mt-2 pr-2 leading-tight bg-yellow-50 dark:bg-yellow-900/10 p-2 rounded-xl">
               {formatArabicDate(startDate)}
            </div>
          </div>
          <div className="flex flex-col">
            <label className="text-[10px] font-black text-gray-400 uppercase mb-2 pr-1 flex items-center gap-2">
               <i className="fas fa-hourglass-end text-yellow-600"></i> إلى تاريخ
            </label>
            <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)} className="bg-gray-50 dark:bg-[#1a1a1a] p-4 rounded-2xl text-xs font-bold outline-none border-2 border-transparent focus:border-yellow-500/30 transition-all" />
            <div className="text-[10px] text-yellow-600 font-black mt-2 pr-2 leading-tight bg-yellow-50 dark:bg-yellow-900/10 p-2 rounded-xl">
               {formatArabicDate(endDate)}
            </div>
          </div>
        </div>
        <button 
          onClick={() => setIsHijriMode(!isHijriMode)} 
          className="px-10 py-4 bg-yellow-600 text-white rounded-2xl shadow-xl shadow-yellow-600/20 font-black text-sm w-full md:w-auto hover:bg-yellow-700 transition-all whitespace-nowrap group active:scale-95"
        >
          <i className={`fas ${isHijriMode ? 'fa-calendar-day' : 'fa-kaaba'} ml-2 transition-transform group-hover:rotate-12`}></i>
          {isHijriMode ? 'التحويل للميلادي' : 'التحويل للهجري'}
        </button>
      </div>

      {/* الجدول الرئيسي */}
      <div className="bg-white dark:bg-[#151515] rounded-[2.5rem] overflow-hidden shadow-2xl border border-gray-100 dark:border-gray-800">
        <div className="overflow-x-auto">
          <table className="w-full text-right min-w-[1000px] border-collapse">
            <thead>
              <tr className="bg-gray-50 dark:bg-[#1a1a1a] text-[10px] text-gray-500 uppercase font-black tracking-widest">
                <th className="p-6 border-l border-gray-100 dark:border-gray-800">التاريخ ({isHijriMode ? 'الهجري' : 'الميلادي'})</th>
                <th className="p-6">القرآن</th>
                <th className="p-6">الصلوات</th>
                <th className="p-6">الأذكار</th>
                <th className="p-6">أعمال البر</th>
                <th className="p-6">المجاهدة</th>
                <th className="p-6 text-center">صافي النقاط</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
              {filteredDates.map(date => {
                const log = logs[date];
                const { netTotal } = getDayDetails(log);
                return (
                  <tr key={date} className="hover:bg-yellow-50/40 dark:hover:bg-yellow-900/5 transition-all group relative">
                    <td onClick={() => setActiveBreakdownDate(date)} className="p-6 border-l border-gray-100 dark:border-gray-800 cursor-pointer">
                      <div className="flex flex-col">
                        <span className="text-xs font-black text-slate-800 dark:text-gray-100 group-hover:text-yellow-700 transition-colors">
                           {formatArabicDate(date)}
                        </span>
                        <span className="text-[8px] text-gray-400 mt-1 font-bold">
                          {isHijriMode ? formatArabicDate(date, false) : formatArabicDate(date, true)}
                        </span>
                      </div>
                    </td>
                    <td className="p-6">
                      <div className="text-[10px] font-bold text-yellow-600">
                        {log.quranEnd > log.quranStart ? (
                          <div className="inline-flex items-center gap-2 bg-yellow-50 dark:bg-yellow-900/20 py-1.5 px-3 rounded-full border border-yellow-100 dark:border-yellow-900/30">
                            <i className="fas fa-book-quran opacity-60"></i>
                            ص {log.quranStart}-{log.quranEnd}
                          </div>
                        ) : <span className="text-gray-200">-</span>}
                      </div>
                    </td>
                    <td className="p-6">
                      <div className="flex items-center gap-1.5">
                        {['fajr', 'dhuhr', 'asr', 'maghrib', 'isha'].map(f => (
                          <div 
                            key={f} 
                            title={PRAYER_TASKS.find(t=>t.id===f)?.label} 
                            className={`w-3.5 h-3.5 rounded-full border-2 ${log.prayers.includes(f) ? 'bg-emerald-500 border-emerald-100 shadow-sm' : 'bg-red-500/20 border-red-500/40'}`}
                          ></div>
                        ))}
                        {log.prayers.length > 5 && (
                          <span className="text-[8px] font-black bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 px-2 py-1 rounded-lg">
                            +{log.prayers.length - 5} نوافل
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="p-6">
                      <span className="text-[10px] font-black bg-purple-50 dark:bg-purple-900/20 text-purple-600 px-3 py-1.5 rounded-2xl border border-purple-100">
                        {log.azkar.length} ذِكر
                      </span>
                    </td>
                    <td className="p-6">
                      <div className="flex items-center gap-3">
