            <i className={`fas ${isHijriMode ? 'fa-kaaba' : 'fa-calendar-day'}`}></i>
            {isHijriMode ? 'عرض بالميلادي' : 'عرض بالهجري'}
          </button>
        </div>
      </div>

      {/* جدول التقييم الرئيسي */}
