            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
              {filteredDates.map(date => {
                const log = logs[date];
                const { netTotal } = getDayDetails(log);
                return (
                  <tr key={date} className="hover:bg-yellow-50/20 transition-all group relative">
                    <td onClick={() => handleOpenModal(date, 'full')} className="p-8 border-l border-gray-100 dark:border-gray-800 cursor-pointer">
                      <div className="flex flex-col">
                        <span className="text-sm font-black text-slate-800 dark:text-gray-100 group-hover:text-yellow-700 transition-colors">
                           {formatArabicDate(date)}
                        </span>
                        <span className="text-[9px] text-gray-400 mt-1 font-bold">
                          {isHijriMode ? formatArabicDate(date, false) : formatArabicDate(date, true)}
                        </span>
                      </div>
                    </td>
                    <td className="p-8">
                      {log.quranEnd > log.quranStart ? (
                        <div className="flex items-center gap-2 bg-yellow-50 dark:bg-yellow-900/20 py-1.5 px-3 rounded-full border border-yellow-200 w-fit">
                          <i className="fas fa-book-quran text-yellow-600"></i>
