                        <span className={`text-[10px] font-black px-3 py-1.5 rounded-2xl border min-w-[55px] text-center ${log.mujahada.length + log.mujahadaNotes.length > 0 ? 'bg-red-50 dark:bg-red-900/20 text-red-600 border-red-100' : 'text-gray-200 border-gray-50'}`}>
                          {log.mujahada.length + log.mujahadaNotes.length} زلة
