                        <button 
                          onClick={(e) => { e.stopPropagation(); handleOpenModal(date, 'mujahada'); }}
                          className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all shadow-xl ${log.mujahada.length + log.mujahadaNotes.length > 0 ? 'bg-red-600 text-white shadow-red-600/30 hover:bg-red-700 hover:scale-110' : 'bg-red-100 text-red-300 opacity-40 hover:opacity-100 cursor-pointer'}`}
