export default History;

export interface DailyLog {
  date: string;
  prayers: string[];
  azkar: string[];
  goodDeeds: string[];
  mujahada: string[];
  quranStart: number;
  quranEnd: number;
  quranTadabburNote: string;
  quranActionNote: string;
  quranListening: boolean;
  quranSujudCount: number;
  quranGoal: 1 | 2 | 3 | 4; // عدد الختمات المستهدفة في الشهر
  notes: string[];
  mujahadaNotes: string[];
}

export interface Quote {
  text: string;
  source: string;
}

export interface TaskItem {
  id: string;
  label: string;
  description?: string;
  verse?: string;
  hadith?: string;
}

export enum SectionType {
  PRAYER = 'PRAYER',
  AZKAR = 'AZKAR',
  QURAN = 'QURAN',
  GOOD_DEEDS = 'GOOD_DEEDS',
  MUJAHADA = 'MUJAHADA'
}

import { DailyLog } from '../types';

const STORAGE_KEY = 'zad_almuslim_logs';

export const getLogs = (): Record<string, DailyLog> => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : {};
};

export const saveLog = (log: DailyLog) => {
  const logs = getLogs();
  logs[log.date] = log;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(logs));
};

export const getLogForDate = (date: string): DailyLog => {
  const logs = getLogs();
  if (logs[date]) {
    const log = logs[date];
    // Migration/Defaults for new fields
    return {
      ...log,
      mujahadaNotes: log.mujahadaNotes || [],
      quranTadabburNote: log.quranTadabburNote || "",
      quranActionNote: log.quranActionNote || "",
      quranListening: log.quranListening || false,
      quranSujudCount: log.quranSujudCount || 0,
      quranGoal: log.quranGoal || 1
    };
  }

  // إذا كان اليوم جديداً، نبحث عن آخر صفحة وصل إليها في السجلات السابقة
  const allDates = Object.keys(logs).sort();
  const previousDates = allDates.filter(d => d < date);
  const lastQuranEnd = previousDates.length > 0 ? logs[previousDates[previousDates.length - 1]].quranEnd : 0;

  return {
    date,
    prayers: [],
    azkar: [],
    goodDeeds: [],
    mujahada: [],
    quranStart: lastQuranEnd, // جلب صفحة النهاية من آخر سجل متاح
    quranEnd: lastQuranEnd,
    quranTadabburNote: "",
    quranActionNote: "",
    quranListening: false,
    quranSujudCount: 0,
    quranGoal: 1,
    notes: [],
    mujahadaNotes: []
  };
};

export const formatDate = (date: Date): string => {
  return date.toISOString().split('T')[0];
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  PRAYER_TASKS, 
  AZKAR_CATEGORIES, 
  GOOD_DEED_CATEGORIES, 
  MUJAHADA_CATEGORIES, 
  MOTIVATIONAL_QUOTES,
  SECTION_INFO,
  TADABBUR_QUESTIONS
} from '../constants';
import { getLogForDate, saveLog, formatDate } from '../services/storageService';
import SectionCard from '../components/SectionCard';
import { DailyLog } from '../types';

// متغير الإزاحة اليدوية (HIJRI_OFFSET): 
// يستخدم لتصحيح رؤية الهلال يدوياً. -1 يعني إنقاص يوم من الحساب الفلكي.
const HIJRI_OFFSET = -1; 

const Dashboard: React.FC = () => {
  const [currentDate] = useState(formatDate(new Date()));
  const [log, setLog] = useState<DailyLog>(getLogForDate(currentDate));

  const [openAzkarCategory, setOpenAzkarCategory] = useState<number | null>(null);
  const [openDeedCategory, setOpenDeedCategory] = useState<number | null>(null);
  const [openMujahadaCategory, setOpenMujahadaCategory] = useState<number | null>(null);
  const [openQuranSub, setOpenQuranSub] = useState<string | null>(null);

  const [manualInputs, setManualInputs] = useState<Record<string, string>>({});

  // تدوير المحتوى بناءً على اليوم الهجري المصحح
  const dailyRotationIndex = useMemo(() => {
    const d = new Date();
    return d.getDate() + HIJRI_OFFSET;
  }, []);

  const quote = useMemo(() => MOTIVATIONAL_QUOTES[Math.abs(dailyRotationIndex) % MOTIVATIONAL_QUOTES.length], [dailyRotationIndex]);
  const tadabburQuestion = useMemo(() => TADABBUR_QUESTIONS[Math.abs(dailyRotationIndex) % TADABBUR_QUESTIONS.length], [dailyRotationIndex]);

  const getDailyInfo = (section: keyof typeof SECTION_INFO) => [SECTION_INFO[section][Math.abs(dailyRotationIndex) % SECTION_INFO[section].length]];

  useEffect(() => { saveLog(log); }, [log]);

  const toggleTask = (section: keyof DailyLog, id: string) => {
    setLog(prev => {
      const currentList = prev[section] as string[];
      const newList = currentList.includes(id) ? currentList.filter(item => item !== id) : [...currentList, id];
      return { ...prev, [section]: newList };
    });
  };

  const addManualEntry = (type: 'notes' | 'mujahadaNotes', categoryIndex: number) => {
    const key = `${type}-${categoryIndex}`;
    const value = manualInputs[key];
    if (!value || !value.trim()) return;
    setLog(prev => ({ ...prev, [type]: [...prev[type], value.trim()] }));
    setManualInputs(prev => ({ ...prev, [key]: '' }));
  };

  const quranCalculations = useMemo(() => {
    const readToday = Math.max(0, log.quranEnd - log.quranStart);
    const totalRead = log.quranEnd;
    const remaining = 604 - totalRead;
    const juz = Math.min(30, Math.ceil(totalRead / 20.2) || 1);
    const percentage = (totalRead / 604) * 100;

    const dailyTarget = log.quranGoal * 20; // تقريباً 20 صفحة للختمة الواحدة يومياً
    const isGoalMet = readToday >= dailyTarget;

    const daysLeft = Math.ceil(remaining / (readToday || dailyTarget));
    const completionDate = new Date();
    completionDate.setDate(completionDate.getDate() + daysLeft);

    // تطبيق الإزاحة الهجرية عند عرض تاريخ الختمة المتوقع
    const completionWithOffset = new Date(completionDate);
    completionWithOffset.setDate(completionWithOffset.getDate() + HIJRI_OFFSET);

    const formattedCompletion = new Intl.DateTimeFormat('ar-SA-u-ca-islamic-umalqura-nu-latn', { day: 'numeric', month: 'long' }).format(completionWithOffset);

    return { readToday, remaining, juz, percentage, isGoalMet, dailyTarget, formattedCompletion };
  }, [log.quranStart, log.quranEnd, log.quranGoal]);

  const score = useMemo(() => {
    let currentScore = 0;
    const fardIds = ['fajr', 'dhuhr', 'asr', 'maghrib', 'isha'];
    fardIds.forEach(id => currentScore += log.prayers.includes(id) ? 10 : -10);

    currentScore += (log.prayers.filter(id => !fardIds.includes(id)).length + log.azkar.length + log.goodDeeds.length + log.notes.length) * 10;
    currentScore -= (log.mujahada.length + log.mujahadaNotes.length) * 10;

    if (quranCalculations.readToday > 0) currentScore += 10;
    if (log.quranTadabburNote) currentScore += 10;
    if (log.quranActionNote) currentScore += 10;
    if (log.quranListening) currentScore += 10;
    if (log.quranSujudCount > 0) currentScore += 10;

    return currentScore;
  }, [log, quranCalculations]);

  return (
    <div className="space-y-6 pb-12 animate-fade-in relative">
      {/* Header Banner */}
      <div className="bg-white dark:bg-[#1a1a1a] border border-yellow-600/30 dark:border-yellow-900/40 p-10 rounded-[2.5rem] relative overflow-hidden group shadow-2xl">
        <div className="absolute top-0 right-0 w-64 h-64 bg-yellow-500/10 rounded-full -mr-32 -mt-32 blur-[100px]"></div>
        <div className="relative z-10 text-center">
          <i className="fas fa-quote-right text-[#d4af37] text-4xl mb-6 opacity-30"></i>
          <p className="text-2xl md:text-4xl font-bold text-slate-800 dark:text-gray-100 leading-relaxed quran-font">{quote.text}</p>
          <div className="mt-8 flex items-center justify-center gap-4">
            <span className="text-sm text-yellow-700 dark:text-yellow-500 font-black uppercase tracking-widest">{quote.source}</span>
          </div>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
        {[
          { label: 'نقاط اليوم', value: score, highlight: true, icon: 'fa-star', theme: 'gold' },
          { label: 'تقدم الختمة', value: `${Math.round(quranCalculations.percentage)}%`, highlight: false, icon: 'fa-book-quran', theme: 'default' },
          { label: 'الزلات', value: log.mujahada.length + log.mujahadaNotes.length, highlight: false, icon: 'fa-triangle-exclamation', theme: 'danger' },
          { label: 'إجمالي الطاعات', value: log.prayers.length + log.azkar.length, highlight: false, icon: 'fa-pray', theme: 'default' },
          { label: 'أعمال البر', value: log.goodDeeds.length + log.notes.length, highlight: false, icon: 'fa-heart', theme: 'default' },
        ].map((stat, idx) => (
          <div key={idx} className="bg-white dark:bg-[#151515] p-5 rounded-3xl border border-gray-100 dark:border-gray-800 flex flex-col items-center justify-center shadow-lg transition-all hover:-translate-y-1">
            <i className={`fas ${stat.icon} text-[10px] mb-2 ${stat.theme === 'danger' ? 'text-red-500/60' : 'text-yellow-600/60'}`}></i>
            <span className="text-gray-400 dark:text-gray-500 text-[9px] mb-1 font-black uppercase text-center">{stat.label}</span>
            <span className={`text-3xl font-black ${stat.theme === 'gold' ? 'gold-gradient' : stat.theme === 'danger' ? 'text-red-600' : 'text-slate-800 dark:text-gray-100'}`}>{stat.value}</span>
          </div>
        ))}
      </div>

      {/* Main Sections */}
      <div className="grid md:grid-cols-2 gap-6">
        <SectionCard title="ورد القرآن الكريم" icon="fa-book-open-reader" infoItems={getDailyInfo('QURAN')} defaultOpen={true}>
          <div className="space-y-4">
            <div className="bg-yellow-50/50 dark:bg-[#1a1a1a] p-4 rounded-2xl border border-yellow-100 dark:border-gray-800 space-y-3">
               <div className="flex items-center justify-between">
                 <span className="text-[10px] font-black uppercase text-yellow-800 dark:text-yellow-600">هدف الختمات</span>
                 <div className="flex gap-2">
                   {[1, 2, 3, 4].map(g => (
                     <button 
                      key={g} 
                      onClick={() => setLog(p => ({...p, quranGoal: g as 1|2|3|4}))}
                      className={`px-3 py-1 rounded-lg text-xs font-black transition-all ${log.quranGoal === g ? 'bg-yellow-600 text-white shadow-md' : 'bg-white dark:bg-gray-800 text-gray-400'}`}
                     >
                       {g === 1 ? '١' : g === 2 ? '٢' : g === 3 ? '٣' : '٤'}
                     </button>
                   ))}
                 </div>
               </div>
               <p className="text-[11px] text-yellow-700 dark:text-yellow-500 font-bold text-center border-t border-yellow-200/50 dark:border-gray-700 pt-2 italic">
                {log.quranGoal === 1 && "لختم القرآن مرة واحدة، عليك قراءة ٢٠ صفحة يومياً."}
                {log.quranGoal === 2 && "لختم القرآن مرتين، عليك قراءة ٤٠ صفحة يومياً."}
                {log.quranGoal === 3 && "لختم القرآن ٣ مرات، عليك قراءة ٦٠ صفحة يومياً."}
                {log.quranGoal === 4 && "لختم القرآن ٤ مرات، عليك قراءة ٨٠ صفحة يومياً."}
               </p>
            </div>

            <div className="border border-gray-100 dark:border-gray-800 rounded-2xl overflow-hidden shadow-sm">
              <button onClick={() => setOpenQuranSub(openQuranSub === 'track' ? null : 'track')} className="w-full flex items-center justify-between p-4 bg-emerald-50/30 dark:bg-[#1a1a1a]">
