                <div className="p-4 bg-white dark:bg-[#151515] space-y-4 animate-fade-in">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-blue-600 uppercase pr-1">سؤال التدبر اليومي</label>
                    <div className="bg-blue-50 dark:bg-blue-900/10 p-3 rounded-xl border-r-4 border-blue-500 text-blue-800 dark:text-blue-300 text-xs font-bold leading-relaxed">
                      {tadabburQuestion}
                    </div>
                  </div>
                  <div className="space-y-3">
                    <div className="space-y-1">
                      <label className="text-[9px] font-black text-gray-400 uppercase">آية استوقفتني</label>
                      <textarea 
                        value={log.quranTadabburNote}
                        onChange={(e) => setLog(p => ({...p, quranTadabburNote: e.target.value}))}
                        className="w-full bg-gray-50 dark:bg-[#1a1a1a] p-3 rounded-xl text-xs font-bold outline-none border border-transparent focus:border-blue-500/30 min-h-[60px]"
                        placeholder="اكتب هنا الآية التي شعرت أنها تخاطبك..."
                      ></textarea>
                    </div>
                    <div className="space-y-1">
                      <label className="text-[9px] font-black text-gray-400 uppercase">العمل بالآية</label>
                      <textarea 
                        value={log.quranActionNote}
                        onChange={(e) => setLog(p => ({...p, quranActionNote: e.target.value}))}
                        className="w-full bg-gray-50 dark:bg-[#1a1a1a] p-3 rounded-xl text-xs font-bold outline-none border border-transparent focus:border-emerald-500/30 min-h-[60px]"
                        placeholder="سأطبق هذه الآية اليوم من خلال..."
                      ></textarea>
                    </div>
                  </div>
                </div>
              )}
            </div>

            <div className="border border-gray-100 dark:border-gray-800 rounded-2xl overflow-hidden shadow-sm">
              <button onClick={() => setOpenQuranSub(openQuranSub === 'other' ? null : 'other')} className="w-full flex items-center justify-between p-4 bg-purple-50/30 dark:bg-[#1a1a1a]">
                <span className="text-sm font-black text-purple-700 dark:text-purple-500">3. السماع والوجل</span>
                <i className={`fas fa-chevron-down text-xs transition-transform ${openQuranSub === 'other' ? 'rotate-180' : ''}`}></i>
              </button>
              {openQuranSub === 'other' && (
                <div className="p-4 bg-white dark:bg-[#151515] space-y-4 animate-fade-in">
                   <label className="flex items-center justify-between p-4 rounded-xl bg-gray-50 dark:bg-gray-800 cursor-pointer">
                      <div className="flex items-center gap-3">
                        <i className="fas fa-headphones text-purple-600"></i>
                        <span className="text-xs font-bold">ورد السماع</span>
                      </div>
                      <input type="checkbox" checked={log.quranListening} onChange={(e) => setLog(p => ({...p, quranListening: e.target.checked}))} className="w-5 h-5 rounded text-purple-600" />
                   </label>
                   <div className="flex items-center justify-between p-4 rounded-xl bg-gray-50 dark:bg-gray-800">
                      <div className="flex items-center gap-3">
                        <i className="fas fa-person-praying text-purple-600"></i>
                        <span className="text-xs font-bold">سجدات التلاوة</span>
                      </div>
                      <div className="flex items-center gap-2">
                        <button onClick={() => setLog(p => ({...p, quranSujudCount: Math.max(0, p.quranSujudCount - 1)}))} className="w-8 h-8 rounded-lg bg-white dark:bg-gray-700 text-purple-600">-</button>
                        <span className="w-8 text-center font-black">{log.quranSujudCount}</span>
                        <button onClick={() => setLog(p => ({...p, quranSujudCount: p.quranSujudCount + 1}))} className="w-8 h-8 rounded-lg bg-white dark:bg-gray-700 text-purple-600">+</button>
                      </div>
                   </div>
                </div>
              )}
            </div>
          </div>
        </SectionCard>

        <SectionCard title="قسم الصلاة" icon="fa-mosque" infoItems={getDailyInfo('PRAYER')}>
          <div className="grid grid-cols-2 gap-2">
            {PRAYER_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-3 rounded-xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-yellow-50 transition-all">
                <input type="checkbox" checked={log.prayers.includes(task.id)} onChange={() => toggleTask('prayers', task.id)} className="w-4 h-4 text-yellow-600" />
                <span className="text-xs font-bold text-slate-700 dark:text-gray-200">{task.label}</span>
              </label>
            ))}
          </div>
        </SectionCard>

        <SectionCard title="قسم الأذكار" icon="fa-hands-praying" infoItems={getDailyInfo('AZKAR')}>
          <div className="space-y-3">
            {AZKAR_CATEGORIES.map((cat, idx) => (
              <div key={idx} className="border border-gray-100 dark:border-gray-800 rounded-2xl overflow-hidden shadow-sm">
                <button onClick={() => setOpenAzkarCategory(openAzkarCategory === idx ? null : idx)} className="w-full flex items-center justify-between p-4 bg-purple-50/30 dark:bg-[#1a1a1a]">
                  <span className="text-sm font-black text-purple-700 dark:text-purple-500">{cat.category}</span>
                  <i className={`fas fa-chevron-down text-xs transition-transform ${openAzkarCategory === idx ? 'rotate-180' : ''}`}></i>
                </button>
                {openAzkarCategory === idx && (
                  <div className="p-4 bg-white dark:bg-[#151515] space-y-2 animate-fade-in">
                    {cat.tasks.map(task => (
                      <label key={task.id} className="flex items-start gap-3 p-3 rounded-xl hover:bg-purple-50/30 transition-all cursor-pointer">
                        <input type="checkbox" checked={log.azkar.includes(task.id)} onChange={() => toggleTask('azkar', task.id)} className="mt-1 w-4 h-4 text-purple-600" />
                        <div className="flex flex-col">
                          <span className="text-xs font-bold">{task.label}</span>
                          <span className="text-[9px] text-gray-500">{task.description}</span>
                        </div>
                      </label>
                    ))}
                  </div>
                )}
              </div>
            ))}
          </div>
        </SectionCard>

        <SectionCard title="أعمال البر والطاعات" icon="fa-heart-pulse" infoItems={getDailyInfo('GOOD_DEEDS')}>
          <div className="space-y-3">
            {GOOD_DEED_CATEGORIES.map((cat, idx) => (
              <div key={idx} className="border border-gray-100 dark:border-gray-800 rounded-2xl overflow-hidden shadow-sm">
                <button onClick={() => setOpenDeedCategory(openDeedCategory === idx ? null : idx)} className="w-full flex items-center justify-between p-4 bg-emerald-50/30 dark:bg-[#1a1a1a]">
                  <span className="text-sm font-black text-emerald-700 dark:text-emerald-500">{cat.category}</span>
                  <i className={`fas fa-chevron-down text-xs transition-transform ${openDeedCategory === idx ? 'rotate-180' : ''}`}></i>
                </button>
                {openDeedCategory === idx && (
                  <div className="p-4 bg-white dark:bg-[#151515] space-y-2 animate-fade-in">
                    {cat.tasks.map(task => (
                      <label key={task.id} className="flex items-start gap-3 p-3 rounded-xl hover:bg-emerald-50/30 transition-all cursor-pointer">
                        <input type="checkbox" checked={log.goodDeeds.includes(task.id)} onChange={() => toggleTask('goodDeeds', task.id)} className="mt-1 w-4 h-4 text-emerald-600" />
                        <div className="flex flex-col">
                          <span className="text-xs font-bold">{task.label}</span>
                          <span className="text-[9px] text-gray-500">{task.description}</span>
                        </div>
                      </label>
                    ))}
                    <div className="flex gap-2 mt-4 pt-2 border-t border-gray-50">
                       <input type="text" placeholder="غير ذلك..." value={manualInputs[`notes-${idx}`] || ''} onChange={(e) => setManualInputs(p => ({...p, [`notes-${idx}`]: e.target.value}))} className="flex-grow bg-gray-50 dark:bg-[#1a1a1a] text-xs p-3 rounded-xl outline-none" />
                       <button onClick={() => addManualEntry('notes', idx)} className="bg-emerald-600 text-white px-4 rounded-xl"><i className="fas fa-plus"></i></button>
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>
        </SectionCard>

        <SectionCard title="مجاهدة النفس" icon="fa-shield-halved" infoItems={getDailyInfo('MUJAHADA')}>
          <div className="space-y-3">
            {MUJAHADA_CATEGORIES.map((cat, idx) => (
              <div key={idx} className="border border-gray-100 dark:border-gray-800 rounded-2xl overflow-hidden shadow-sm">
                <button onClick={() => setOpenMujahadaCategory(openMujahadaCategory === idx ? null : idx)} className="w-full flex items-center justify-between p-4 bg-red-50/30 dark:bg-[#1a1a1a]">
                  <span className="text-sm font-black text-red-700 dark:text-red-500">{cat.category}</span>
                  <i className={`fas fa-chevron-down text-xs transition-transform ${openMujahadaCategory === idx ? 'rotate-180' : ''}`}></i>
                </button>
                {openMujahadaCategory === idx && (
                  <div className="p-4 bg-white dark:bg-[#151515] space-y-2 animate-fade-in">
                    {cat.tasks.map(task => (
                      <label key={task.id} className="flex items-start gap-3 p-3 rounded-xl hover:bg-red-50/30 transition-all cursor-pointer">
                        <input type="checkbox" checked={log.mujahada.includes(task.id)} onChange={() => toggleTask('mujahada', task.id)} className="mt-1 w-4 h-4 text-red-600" />
                        <div className="flex flex-col">
                          <span className="text-xs font-bold">{task.label}</span>
                          <span className="text-[9px] text-gray-500">{task.description}</span>
                        </div>
                      </label>
                    ))}
                    <div className="flex gap-2 mt-4 pt-2 border-t border-gray-50">
                       <input type="text" placeholder="غير ذلك..." value={manualInputs[`mujahadaNotes-${idx}`] || ''} onChange={(e) => setManualInputs(p => ({...p, [`mujahadaNotes-${idx}`]: e.target.value}))} className="flex-grow bg-gray-50 dark:bg-[#1a1a1a] text-xs p-3 rounded-xl outline-none" />
                       <button onClick={() => addManualEntry('mujahadaNotes', idx)} className="bg-red-600 text-white px-4 rounded-xl"><i className="fas fa-plus"></i></button>
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>
        </SectionCard>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  PRAYER_TASKS, 
  AZKAR_CATEGORIES, 
  GOOD_DEED_CATEGORIES, 
  MUJAHADA_CATEGORIES, 
  MOTIVATIONAL_QUOTES,
  SECTION_INFO,
  TADABBUR_QUESTIONS
} from '../constants';
import { getLogForDate, saveLog, formatDate } from '../services/storageService';
import SectionCard from '../components/SectionCard';
import { DailyLog } from '../types';

// متغير الإزاحة اليدوية (HIJRI_OFFSET): 
const HIJRI_OFFSET = -1; 

const Dashboard: React.FC = () => {
  const [currentDate] = useState(formatDate(new Date()));
  const [log, setLog] = useState<DailyLog>(getLogForDate(currentDate));

  const [openAzkarCategory, setOpenAzkarCategory] = useState<number | null>(null);
  const [openDeedCategory, setOpenDeedCategory] = useState<number | null>(null);
  const [openMujahadaCategory, setOpenMujahadaCategory] = useState<number | null>(null);
  const [openQuranSub, setOpenQuranSub] = useState<string | null>(null);

  const [manualInputs, setManualInputs] = useState<Record<string, string>>({});

  const dailyRotationIndex = useMemo(() => {
    const d = new Date();
    return d.getDate() + HIJRI_OFFSET;
  }, []);

  const quote = useMemo(() => MOTIVATIONAL_QUOTES[Math.abs(dailyRotationIndex) % MOTIVATIONAL_QUOTES.length], [dailyRotationIndex]);
  const tadabburQuestion = useMemo(() => TADABBUR_QUESTIONS[Math.abs(dailyRotationIndex) % TADABBUR_QUESTIONS.length], [dailyRotationIndex]);

  const getDailyInfo = (section: keyof typeof SECTION_INFO) => [SECTION_INFO[section][Math.abs(dailyRotationIndex) % SECTION_INFO[section].length]];

  useEffect(() => { saveLog(log); }, [log]);

  const toggleTask = (section: keyof DailyLog, id: string) => {
    setLog(prev => {
      const currentList = prev[section] as string[];
      const newList = currentList.includes(id) ? currentList.filter(item => item !== id) : [...currentList, id];
      return { ...prev, [section]: newList };
    });
  };

  const addManualEntry = (type: 'notes' | 'mujahadaNotes', categoryIndex: number) => {
    const key = `${type}-${categoryIndex}`;
    const value = manualInputs[key];
    if (!value || !value.trim()) return;
    setLog(prev => ({ ...prev, [type]: [...prev[type], value.trim()] }));
    setManualInputs(prev => ({ ...prev, [key]: '' }));
  };

  const quranCalculations = useMemo(() => {
    const readToday = Math.max(0, log.quranEnd - log.quranStart);
    const totalRead = log.quranEnd;
    const remaining = 604 - totalRead;
    const juz = Math.min(30, Math.ceil(totalRead / 20.2) || 1);
    const percentage = (totalRead / 604) * 100;

    const dailyTarget = log.quranGoal * 20; 
    const isGoalMet = readToday >= dailyTarget;

    const daysLeft = Math.ceil(remaining / (readToday || dailyTarget));
    const completionDate = new Date();
    completionDate.setDate(completionDate.getDate() + daysLeft);

    const completionWithOffset = new Date(completionDate);
    completionWithOffset.setDate(completionWithOffset.getDate() + HIJRI_OFFSET);

    const formattedCompletion = new Intl.DateTimeFormat('ar-SA-u-ca-islamic-umalqura-nu-latn', { day: 'numeric', month: 'long' }).format(completionWithOffset);

    return { readToday, remaining, juz, percentage, isGoalMet, dailyTarget, formattedCompletion };
  }, [log.quranStart, log.quranEnd, log.quranGoal]);

  const score = useMemo(() => {
    let currentScore = 0;
    const fardIds = ['fajr', 'dhuhr', 'asr', 'maghrib', 'isha'];
    fardIds.forEach(id => currentScore += log.prayers.includes(id) ? 10 : -10);

    currentScore += (log.prayers.filter(id => !fardIds.includes(id)).length + log.azkar.length + log.goodDeeds.length + log.notes.length) * 10;
    currentScore -= (log.mujahada.length + log.mujahadaNotes.length) * 10;

    if (quranCalculations.readToday > 0) currentScore += 10;
    if (log.quranTadabburNote) currentScore += 10;
    if (log.quranActionNote) currentScore += 10;
    if (log.quranListening) currentScore += 10;
    if (log.quranSujudCount > 0) currentScore += 10;

    return currentScore;
  }, [log, quranCalculations]);

  return (
    <div className="space-y-8 pb-12 animate-fade-in relative">
      {/* Prominent Daily Quote Banner */}
      <div className="bg-gradient-to-br from-[#1a1a1a] via-[#222] to-[#1a1a1a] dark:from-[#0a0a0a] dark:to-[#151515] border-y-4 md:border-4 border-yellow-600/40 p-12 rounded-none md:rounded-[3.5rem] relative overflow-hidden group shadow-[0_20px_50px_rgba(0,0,0,0.3)] dark:shadow-[0_20px_50px_rgba(0,0,0,0.6)]">
        <div className="absolute top-0 left-0 w-full h-full islamic-pattern opacity-10"></div>
        <div className="absolute -top-24 -right-24 w-64 h-64 bg-yellow-500/10 rounded-full blur-[80px] group-hover:bg-yellow-500/20 transition-all duration-700"></div>
        <div className="absolute -bottom-24 -left-24 w-64 h-64 bg-yellow-500/10 rounded-full blur-[80px] group-hover:bg-yellow-500/20 transition-all duration-700"></div>

        <div className="relative z-10 text-center space-y-6">
          <div className="flex items-center justify-center gap-4 mb-2">
            <div className="h-[1px] w-12 bg-yellow-600/50"></div>
            <span className="text-yellow-600 dark:text-yellow-500 text-[10px] font-black uppercase tracking-[0.3em]">حكمة اليوم</span>
            <div className="h-[1px] w-12 bg-yellow-600/50"></div>
          </div>

          <i className="fas fa-quote-right text-yellow-600/20 text-6xl block mb-2 transition-transform group-hover:scale-110"></i>

          <p className="text-3xl md:text-5xl font-black text-slate-100 dark:text-gray-100 leading-[1.3] quran-font drop-shadow-lg">
            {quote.text}
          </p>

          <div className="pt-6">
            <span className="inline-block px-8 py-2 bg-yellow-600/10 border border-yellow-600/30 rounded-full text-sm text-yellow-500 font-black tracking-widest uppercase">
              {quote.source}
            </span>
          </div>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
        {[
          { label: 'نقاط اليوم', value: score, highlight: true, icon: 'fa-star', theme: 'gold' },
          { label: 'تقدم الختمة', value: `${Math.round(quranCalculations.percentage)}%`, highlight: false, icon: 'fa-book-quran', theme: 'default' },
          { label: 'الزلات', value: log.mujahada.length + log.mujahadaNotes.length, highlight: false, icon: 'fa-triangle-exclamation', theme: 'danger' },
          { label: 'إجمالي الطاعات', value: log.prayers.length + log.azkar.length, highlight: false, icon: 'fa-pray', theme: 'default' },
          { label: 'أعمال البر', value: log.goodDeeds.length + log.notes.length, highlight: false, icon: 'fa-heart', theme: 'default' },
        ].map((stat, idx) => (
          <div key={idx} className="bg-white dark:bg-[#151515] p-5 rounded-3xl border border-gray-100 dark:border-gray-800 flex flex-col items-center justify-center shadow-lg transition-all hover:-translate-y-1">
            <i className={`fas ${stat.icon} text-[10px] mb-2 ${stat.theme === 'danger' ? 'text-red-500/60' : 'text-yellow-600/60'}`}></i>
            <span className="text-gray-400 dark:text-gray-500 text-[9px] mb-1 font-black uppercase text-center">{stat.label}</span>
            <span className={`text-3xl font-black ${stat.theme === 'gold' ? 'gold-gradient' : stat.theme === 'danger' ? 'text-red-600' : 'text-slate-800 dark:text-gray-100'}`}>{stat.value}</span>
          </div>
        ))}
      </div>

      {/* Main Sections */}
      <div className="grid md:grid-cols-2 gap-6">
        <SectionCard title="ورد القرآن الكريم" icon="fa-book-open-reader" infoItems={getDailyInfo('QURAN')} defaultOpen={true}>
          <div className="space-y-4">
            <div className="bg-yellow-50/50 dark:bg-[#1a1a1a] p-4 rounded-2xl border border-yellow-100 dark:border-gray-800 space-y-3">
               <div className="flex items-center justify-between">
                 <span className="text-[10px] font-black uppercase text-yellow-800 dark:text-yellow-600">هدف الختمات</span>
                 <div className="flex gap-2">
                   {[1, 2, 3, 4].map(g => (
                     <button 
                      key={g} 
                      onClick={() => setLog(p => ({...p, quranGoal: g as 1|2|3|4}))}
                      className={`px-3 py-1 rounded-lg text-xs font-black transition-all ${log.quranGoal === g ? 'bg-yellow-600 text-white shadow-md' : 'bg-white dark:bg-gray-800 text-gray-400'}`}
                     >
                       {g === 1 ? '١' : g === 2 ? '٢' : g === 3 ? '٣' : '٤'}
                     </button>
                   ))}
                 </div>
               </div>
               <p className="text-[11px] text-yellow-700 dark:text-yellow-500 font-bold text-center border-t border-yellow-200/50 dark:border-gray-700 pt-2 italic">
                {log.quranGoal === 1 && "لختم القرآن مرة واحدة، عليك قراءة ٢٠ صفحة يومياً."}
                {log.quranGoal === 2 && "لختم القرآن مرتين، عليك قراءة ٤٠ صفحة يومياً."}
                {log.quranGoal === 3 && "لختم القرآن ٣ مرات، عليك قراءة ٦٠ صفحة يومياً."}
                {log.quranGoal === 4 && "لختم القرآن ٤ مرات، عليك قراءة ٨٠ صفحة يومياً."}
               </p>
            </div>

            <div className="border border-gray-100 dark:border-gray-800 rounded-2xl overflow-hidden shadow-sm">
              <button onClick={() => setOpenQuranSub(openQuranSub === 'track' ? null : 'track')} className="w-full flex items-center justify-between p-4 bg-emerald-50/30 dark:bg-[#1a1a1a]">
                <span className="text-sm font-black text-emerald-700 dark:text-emerald-500">1. متابعة الورد (الكمّي)</span>
                <i className={`fas fa-chevron-down text-xs transition-transform ${openQuranSub === 'track' ? 'rotate-180' : ''}`}></i>
              </button>
              {openQuranSub === 'track' && (
                <div className="p-4 bg-white dark:bg-[#151515] space-y-4 animate-fade-in">
                   <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-[9px] font-black text-gray-400 uppercase pr-1">من صفحة</label>
                      <input type="number" value={log.quranStart || ""} onChange={(e) => setLog(prev => ({...prev, quranStart: parseInt(e.target.value) || 0}))} className="w-full bg-gray-50 dark:bg-[#1a1a1a] p-4 rounded-xl text-center font-black text-yellow-600 outline-none border border-transparent focus:border-yellow-500/30" placeholder="0" />
                    </div>
                    <div className="space-y-1">
                      <label className="text-[9px] font-black text-gray-400 uppercase pr-1">إلى صفحة</label>
                      <input type="number" value={log.quranEnd || ""} onChange={(e) => setLog(prev => ({...prev, quranEnd: parseInt(e.target.value) || 0}))} className="w-full bg-gray-50 dark:bg-[#1a1a1a] p-4 rounded-xl text-center font-black text-yellow-600 outline-none border border-transparent focus:border-yellow-500/30" placeholder="0" />
                    </div>
                   </div>

                   {quranCalculations.readToday > 0 ? (
                      <div className="bg-emerald-500 text-white p-3 rounded-xl text-center animate-bounce shadow-lg">
                        <i className="fas fa-check-circle mr-2"></i>
                        <span className="text-xs font-black">فتح الله عليك! قرأت {quranCalculations.readToday} صفحة</span>
                      </div>
                   ) : (
                      <div className="bg-orange-50 dark:bg-orange-900/10 text-orange-700 dark:text-orange-500 p-3 rounded-xl text-center border border-orange-100 dark:border-orange-900/20">
                        <i className="fas fa-heart mr-2"></i>
                        <span className="text-xs font-black">أما اشتقت لحديث ربك؟ ابدأ وردك الآن</span>
                      </div>
                   )}

                   <div className="grid grid-cols-3 gap-2">
                      <div className="bg-gray-50 dark:bg-gray-800 p-3 rounded-xl text-center">
                        <span className="text-[8px] text-gray-400 block font-black uppercase">الجزء</span>
                        <span className="text-sm font-black text-slate-700 dark:text-gray-200">{quranCalculations.juz}</span>
                      </div>
                      <div className="bg-gray-50 dark:bg-gray-800 p-3 rounded-xl text-center">
                        <span className="text-[8px] text-gray-400 block font-black uppercase">المتبقي</span>
                        <span className="text-sm font-black text-slate-700 dark:text-gray-200">{quranCalculations.remaining} ص</span>
                      </div>
                      <div className="bg-gray-50 dark:bg-gray-800 p-3 rounded-xl text-center">
                        <span className="text-[8px] text-gray-400 block font-black uppercase">الختمة</span>
                        <span className="text-[9px] font-black text-yellow-600 leading-tight">{quranCalculations.formattedCompletion}</span>
                      </div>
                   </div>

                   <div className="space-y-1">
                      <div className="flex justify-between text-[9px] font-black text-gray-400">
                        <span>خريطة المصحف</span>
                        <span>{Math.round(quranCalculations.percentage)}%</span>
                      </div>
                      <div className="h-3 bg-gray-100 dark:bg-gray-800 rounded-full overflow-hidden p-0.5">
                        <div className="h-full bg-gradient-to-r from-emerald-600 to-emerald-400 rounded-full transition-all duration-1000" style={{ width: `${quranCalculations.percentage}%` }}></div>
                      </div>
                   </div>
                </div>
              )}
            </div>

            <div className="border border-gray-100 dark:border-gray-800 rounded-2xl overflow-hidden shadow-sm">
              <button onClick={() => setOpenQuranSub(openQuranSub === 'tadabbur' ? null : 'tadabbur')} className="w-full flex items-center justify-between p-4 bg-blue-50/30 dark:bg-[#1a1a1a]">
                <span className="text-sm font-black text-blue-700 dark:text-blue-500">2. قسم التدبر (الكيفي)</span>
                <i className={`fas fa-chevron-down text-xs transition-transform ${openQuranSub === 'tadabbur' ? 'rotate-180' : ''}`}></i>
              </button>
              {openQuranSub === 'tadabbur' && (
                <div className="p-4 bg-white dark:bg-[#151515] space-y-4 animate-fade-in">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-blue-600 uppercase pr-1">سؤال التدبر اليومي</label>
                    <div className="bg-blue-50 dark:bg-blue-900/10 p-3 rounded-xl border-r-4 border-blue-500 text-blue-800 dark:text-blue-300 text-xs font-bold leading-relaxed">
                      {tadabburQuestion}
                    </div>
                  </div>
                  <div className="space-y-3">
                    <div className="space-y-1">
                      <label className="text-[9px] font-black text-gray-400 uppercase">آية استوقفتني</label>
                      <textarea 
                        value={log.quranTadabburNote}
                        onChange={(e) => setLog(p => ({...p, quranTadabburNote: e.target.value}))}
                        className="w-full bg-gray-50 dark:bg-[#1a1a1a] p-3 rounded-xl text-xs font-bold outline-none border border-transparent focus:border-blue-500/30 min-h-[60px]"
                        placeholder="اكتب هنا الآية التي شعرت أنها تخاطبك..."
                      ></textarea>
                    </div>
                    <div className="space-y-1">
                      <label className="text-[9px] font-black text-gray-400 uppercase">العمل بالآية</label>
                      <textarea 
                        value={log.quranActionNote}
                        onChange={(e) => setLog(p => ({...p, quranActionNote: e.target.value}))}
                        className="w-full bg-gray-50 dark:bg-[#1a1a1a] p-3 rounded-xl text-xs font-bold outline-none border border-transparent focus:border-emerald-500/30 min-h-[60px]"
                        placeholder="سأطبق هذه الآية اليوم من خلال..."
                      ></textarea>
                    </div>
                  </div>
                </div>
              )}
            </div>

            <div className="border border-gray-100 dark:border-gray-800 rounded-2xl overflow-hidden shadow-sm">
              <button onClick={() => setOpenQuranSub(openQuranSub === 'other' ? null : 'other')} className="w-full flex items-center justify-between p-4 bg-purple-50/30 dark:bg-[#1a1a1a]">
                <span className="text-sm font-black text-purple-700 dark:text-purple-500">3. السماع والوجل</span>
                <i className={`fas fa-chevron-down text-xs transition-transform ${openQuranSub === 'other' ? 'rotate-180' : ''}`}></i>
              </button>
              {openQuranSub === 'other' && (
                <div className="p-4 bg-white dark:bg-[#151515] space-y-4 animate-fade-in">
                   <label className="flex items-center justify-between p-4 rounded-xl bg-gray-50 dark:bg-gray-800 cursor-pointer">
                      <div className="flex items-center gap-3">
                        <i className="fas fa-headphones text-purple-600"></i>
                        <span className="text-xs font-bold">ورد السماع</span>
                      </div>
                      <input type="checkbox" checked={log.quranListening} onChange={(e) => setLog(p => ({...p, quranListening: e.target.checked}))} className="w-5 h-5 rounded text-purple-600" />
                   </label>
                   <div className="flex items-center justify-between p-4 rounded-xl bg-gray-50 dark:bg-gray-800">
                      <div className="flex items-center gap-3">
                        <i className="fas fa-person-praying text-purple-600"></i>
                        <span className="text-xs font-bold">سجدات التلاوة</span>
                      </div>
                      <div className="flex items-center gap-2">
                        <button onClick={() => setLog(p => ({...p, quranSujudCount: Math.max(0, p.quranSujudCount - 1)}))} className="w-8 h-8 rounded-lg bg-white dark:bg-gray-700 text-purple-600">-</button>
                        <span className="w-8 text-center font-black">{log.quranSujudCount}</span>
                        <button onClick={() => setLog(p => ({...p, quranSujudCount: p.quranSujudCount + 1}))} className="w-8 h-8 rounded-lg bg-white dark:bg-gray-700 text-purple-600">+</button>
                      </div>
                   </div>
                </div>
              )}
            </div>
          </div>
        </SectionCard>

        <SectionCard title="قسم الصلاة" icon="fa-mosque" infoItems={getDailyInfo('PRAYER')}>
          <div className="grid grid-cols-2 gap-2">
            {PRAYER_TASKS.map(task => (
              <label key={task.id} className="flex items-center gap-3 p-3 rounded-xl bg-gray-50 dark:bg-[#1a1a1a] cursor-pointer hover:bg-yellow-50 transition-all">
                <input type="checkbox" checked={log.prayers.includes(task.id)} onChange={() => toggleTask('prayers', task.id)} className="w-4 h-4 text-yellow-600" />
                <span className="text-xs font-bold text-slate-700 dark:text-gray-200">{task.label}</span>
              </label>
            ))}
          </div>
        </SectionCard>

        <SectionCard title="قسم الأذكار" icon="fa-hands-praying" infoItems={getDailyInfo('AZKAR')}>
          <div className="space-y-3">
            {AZKAR_CATEGORIES.map((cat, idx) => (
              <div key={idx} className="border border-gray-100 dark:border-gray-800 rounded-2xl overflow-hidden shadow-sm">
                <button onClick={() => setOpenAzkarCategory(openAzkarCategory === idx ? null : idx)} className="w-full flex items-center justify-between p-4 bg-purple-50/30 dark:bg-[#1a1a1a]">
                  <span className="text-sm font-black text-purple-700 dark:text-purple-500">{cat.category}</span>
                  <i className={`fas fa-chevron-down text-xs transition-transform ${openAzkarCategory === idx ? 'rotate-180' : ''}`}></i>
                </button>
                {openAzkarCategory === idx && (
                  <div className="p-4 bg-white dark:bg-[#151515] space-y-2 animate-fade-in">
                    {cat.tasks.map(task => (
                      <label key={task.id} className="flex items-start gap-3 p-3 rounded-xl hover:bg-purple-50/30 transition-all cursor-pointer">
                        <input type="checkbox" checked={log.azkar.includes(task.id)} onChange={() => toggleTask('azkar', task.id)} className="mt-1 w-4 h-4 text-purple-600" />
                        <div className="flex flex-col">
                          <span className="text-xs font-bold">{task.label}</span>
                          <span className="text-[9px] text-gray-500">{task.description}</span>
                        </div>
                      </label>
                    ))}
                  </div>
                )}
              </div>
            ))}
          </div>
        </SectionCard>

        <SectionCard title="أعمال البر والطاعات" icon="fa-heart-pulse" infoItems={getDailyInfo('GOOD_DEEDS')}>
          <div className="space-y-3">
            {GOOD_DEED_CATEGORIES.map((cat, idx) => (
              <div key={idx} className="border border-gray-100 dark:border-gray-800 rounded-2xl overflow-hidden shadow-sm">
                <button onClick={() => setOpenDeedCategory(openDeedCategory === idx ? null : idx)} className="w-full flex items-center justify-between p-4 bg-emerald-50/30 dark:bg-[#1a1a1a]">
                  <span className="text-sm font-black text-emerald-700 dark:text-emerald-500">{cat.category}</span>
                  <i className={`fas fa-chevron-down text-xs transition-transform ${openDeedCategory === idx ? 'rotate-180' : ''}`}></i>
                </button>
                {openDeedCategory === idx && (
                  <div className="p-4 bg-white dark:bg-[#151515] space-y-2 animate-fade-in">
                    {cat.tasks.map(task => (
                      <label key={task.id} className="flex items-start gap-3 p-3 rounded-xl hover:bg-emerald-50/30 transition-all cursor-pointer">
                        <input type="checkbox" checked={log.goodDeeds.includes(task.id)} onChange={() => toggleTask('goodDeeds', task.id)} className="mt-1 w-4 h-4 text-emerald-600" />
                        <div className="flex flex-col">
                          <span className="text-xs font-bold">{task.label}</span>
                          <span className="text-[9px] text-gray-500">{task.description}</span>
                        </div>
                      </label>
                    ))}
                    <div className="flex gap-2 mt-4 pt-2 border-t border-gray-50">
                       <input type="text" placeholder="غير ذلك..." value={manualInputs[`notes-${idx}`] || ''} onChange={(e) => setManualInputs(p => ({...p, [`notes-${idx}`]: e.target.value}))} className="flex-grow bg-gray-50 dark:bg-[#1a1a1a] text-xs p-3 rounded-xl outline-none" />
                       <button onClick={() => addManualEntry('notes', idx)} className="bg-emerald-600 text-white px-4 rounded-xl"><i className="fas fa-plus"></i></button>
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>
        </SectionCard>

        <SectionCard title="مجاهدة النفس" icon="fa-shield-halved" infoItems={getDailyInfo('MUJAHADA')}>
          <div className="space-y-3">
            {MUJAHADA_CATEGORIES.map((cat, idx) => (
              <div key={idx} className="border border-gray-100 dark:border-gray-800 rounded-2xl overflow-hidden shadow-sm">
                <button onClick={() => setOpenMujahadaCategory(openMujahadaCategory === idx ? null : idx)} className="w-full flex items-center justify-between p-4 bg-red-50/30 dark:bg-[#1a1a1a]">
                  <span className="text-sm font-black text-red-700 dark:text-red-500">{cat.category}</span>
                  <i className={`fas fa-chevron-down text-xs transition-transform ${openMujahadaCategory === idx ? 'rotate-180' : ''}`}></i>
                </button>
                {openMujahadaCategory === idx && (
                  <div className="p-4 bg-white dark:bg-[#151515] space-y-2 animate-fade-in">
                    {cat.tasks.map(task => (
                      <label key={task.id} className="flex items-start gap-3 p-3 rounded-xl hover:bg-red-50/30 transition-all cursor-pointer">
                        <input type="checkbox" checked={log.mujahada.includes(task.id)} onChange={() => toggleTask('mujahada', task.id)} className="mt-1 w-4 h-4 text-red-600" />
                        <div className="flex flex-col">
                          <span className="text-xs font-bold">{task.label}</span>
                          <span className="text-[9px] text-gray-500">{task.description}</span>
                        </div>
                      </label>
                    ))}
                    <div className="flex gap-2 mt-4 pt-2 border-t border-gray-50">
                       <input type="text" placeholder="غير ذلك..." value={manualInputs[`mujahadaNotes-${idx}`] || ''} onChange={(e) => setManualInputs(p => ({...p, [`mujahadaNotes-${idx}`]: e.target.value}))} className="flex-grow bg-gray-50 dark:bg-[#1a1a1a] text-xs p-3 rounded-xl outline-none" />
                       <button onClick={() => addManualEntry('mujahadaNotes', idx)} className="bg-red-600 text-white px-4 rounded-xl"><i className="fas fa-plus"></i></button>
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>
        </SectionCard>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useMemo, useState } from 'react';
import { getLogs } from '../services/storageService';
import { DailyLog } from '../types';
import { PRAYER_TASKS, AZKAR_CATEGORIES, GOOD_DEED_CATEGORIES, MUJAHADA_CATEGORIES } from '../constants';

interface BreakdownItem {
  label: string;
  points: number;
  type: 'pos' | 'neg';
  category: string;
}

type ModalType = 'full' | 'goodDeeds' | 'mujahada';

// متغير الإزاحة اليدوية (HIJRI_OFFSET): 
const HIJRI_OFFSET = -1; 

const HIJRI_MONTHS = [
  "محرم", "صفر", "ربيع الأول", "ربيع الآخر", "جمادى الأولى", "جمادى الآخرة",
  "رجب", "شعبان", "رمضان", "شوال", "ذو القعدة", "ذو الحجة"
];

const History: React.FC = () => {
  const [startDate, setStartDate] = useState(() => {
    const d = new Date('2026-02-19'); 
    return d.toISOString().split('T')[0];
  });
  const [endDate, setEndDate] = useState(() => {
    const d = new Date('2026-03-20'); 
    return d.toISOString().split('T')[0];
  });

  const [isHijriMode, setIsHijriMode] = useState(true);
  const [activeBreakdownDate, setActiveBreakdownDate] = useState<string | null>(null);
  const [modalType, setModalType] = useState<ModalType>('full');

  const logs = useMemo(() => getLogs(), []);

  const formatArabicDate = (dateStr: string, forceHijri?: boolean) => {
    try {
      const date = new Date(dateStr);
      const useHijri = forceHijri ?? isHijriMode;

      if (useHijri) {
        date.setDate(date.getDate() + HIJRI_OFFSET);
      }

      const calendar = useHijri ? 'islamic-umalqura' : 'gregory';

      return new Intl.DateTimeFormat(`ar-SA-u-ca-${calendar}-nu-latn`, { 
        day: 'numeric', 
        month: 'long', 
        year: 'numeric',
        weekday: 'long'
      }).format(date);
    } catch (e) { return dateStr; }
  };

  const filteredDates = useMemo(() => {
    return Object.keys(logs)
      .filter(date => date >= startDate && date <= endDate)
      .sort((a, b) => b.localeCompare(a));
  }, [logs, startDate, endDate]);

  const getDayDetails = (log: DailyLog) => {
    const posItems: BreakdownItem[] = [];
    const negItems: BreakdownItem[] = [];
    const fardIds = ['fajr', 'dhuhr', 'asr', 'maghrib', 'isha'];

    fardIds.forEach(id => {
      const task = PRAYER_TASKS.find(t => t.id === id);
      if (log.prayers.includes(id)) {
        posItems.push({ label: task?.label || id, points: 10, type: 'pos', category: 'الفرائض' });
      } else {
        negItems.push({ label: `فوات ${task?.label || id}`, points: -10, type: 'neg', category: 'التقصير' });
      }
    });

    log.prayers.filter(id => !fardIds.includes(id)).forEach(id => {
      const task = PRAYER_TASKS.find(t => t.id === id);
      posItems.push({ label: task?.label || id, points: 10, type: 'pos', category: 'النوافل' });
    });

    log.azkar.forEach(id => {
      let task = null;
      for (const cat of AZKAR_CATEGORIES) { task = cat.tasks.find(t => t.id === id); if (task) break; }
      posItems.push({ label: task?.label || id, points: 10, type: 'pos', category: 'الأذكار' });
    });

    log.goodDeeds.forEach(id => {
      let task = null;
      for (const cat of GOOD_DEED_CATEGORIES) { task = cat.tasks.find(t => t.id === id); if (task) break; }
      posItems.push({ label: task?.label || id, points: 10, type: 'pos', category: 'أعمال البر' });
    });
    log.notes.forEach(note => posItems.push({ label: note, points: 10, type: 'pos', category: 'أعمال إضافية' }));

    if (log.quranEnd > log.quranStart) posItems.push({ label: `قراءة القرآن (${log.quranEnd - log.quranStart} ص)`, points: 10, type: 'pos', category: 'القرآن' });
    if (log.quranTadabburNote) posItems.push({ label: 'تدبر آية', points: 10, type: 'pos', category: 'القرآن' });
    if (log.quranActionNote) posItems.push({ label: 'تطبيق عملي', points: 10, type: 'pos', category: 'القرآن' });

    log.mujahada.forEach(id => {
      let task = null;
      for (const cat of MUJAHADA_CATEGORIES) { task = cat.tasks.find(t => t.id === id); if (task) break; }
      negItems.push({ label: task?.label || id, points: -10, type: 'neg', category: 'المجاهدة' });
    });
    log.mujahadaNotes.forEach(note => negItems.push({ label: note, points: -10, type: 'neg', category: 'المجاهدة' }));

    const posTotal = posItems.reduce((acc, item) => acc + item.points, 0);
    const negTotal = negItems.reduce((acc, item) => acc + item.points, 0);
    return { posItems, negItems, posTotal, negTotal, netTotal: posTotal + negTotal };
  };

  const handleOpenModal = (date: string, type: ModalType) => {
    setActiveBreakdownDate(date);
    setModalType(type);
  };

  const handlePrint = () => window.print();

  return (
    <div className="animate-fade-in space-y-6 pb-12 print:p-0">
      {/* Dynamic Detail Modal */}
      {activeBreakdownDate && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-xl" onClick={() => setActiveBreakdownDate(null)}>
          <div className="bg-white dark:bg-[#1a1a1a] w-full max-w-2xl rounded-[3rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh] border-4 border-yellow-600/30" onClick={e => e.stopPropagation()}>
            <div className={`p-8 bg-gradient-to-br text-white relative ${
              modalType === 'goodDeeds' ? 'from-emerald-700 via-emerald-600 to-emerald-800' :
              modalType === 'mujahada' ? 'from-red-700 via-red-600 to-red-800' :
              'from-yellow-700 via-yellow-600 to-yellow-800'
            }`}>
              <div className="flex justify-between items-start">
                <div>
                  <h2 className="text-3xl font-black mb-1 quran-font">
                    {modalType === 'goodDeeds' ? 'تفاصيل أعمال البر' : 
                     modalType === 'mujahada' ? 'كشف الزلات والمجاهدة' : 
                     'التقرير الإيماني الشامل'}
                  </h2>
                  <p className="text-xs font-bold opacity-90">{formatArabicDate(activeBreakdownDate, false)}</p>
                  <p className="text-sm font-black text-white/70">{formatArabicDate(activeBreakdownDate, true)}</p>
                </div>
                <button onClick={() => setActiveBreakdownDate(null)} className="w-12 h-12 rounded-full bg-white/20 hover:bg-white/40 flex items-center justify-center transition-all">
                  <i className="fas fa-times text-xl"></i>
                </button>
              </div>
            </div>

            <div className="flex-grow overflow-y-auto p-8 space-y-8">
              {(modalType === 'full') && (
                <div className="grid grid-cols-3 gap-4">
                  <div className="bg-emerald-50 dark:bg-emerald-900/10 p-5 rounded-3xl text-center border-2 border-emerald-100">
                    <span className="text-[10px] font-black text-emerald-600 block mb-1">الإيجابي</span>
                    <span className="text-3xl font-black text-emerald-600">+{getDayDetails(logs[activeBreakdownDate]).posTotal}</span>
                  </div>
                  <div className="bg-red-50 dark:bg-red-900/10 p-5 rounded-3xl text-center border-2 border-red-100">
                    <span className="text-[10px] font-black text-red-600 block mb-1">السلبي</span>
                    <span className="text-3xl font-black text-red-600">{getDayDetails(logs[activeBreakdownDate]).negTotal}</span>
                  </div>
                  <div className="bg-yellow-50 dark:bg-yellow-900/10 p-5 rounded-3xl text-center border-4 border-yellow-500 shadow-xl">
                    <span className="text-[10px] font-black text-yellow-600 block mb-1">الصافي</span>
                    <span className="text-3xl font-black text-yellow-600">{getDayDetails(logs[activeBreakdownDate]).netTotal}</span>
                  </div>
                </div>
              )}

              <div className="space-y-6">
                {(modalType === 'full' || modalType === 'goodDeeds') && (
                  <div className="space-y-3">
                    <h3 className="text-sm font-black text-emerald-700 flex items-center gap-2"><i className="fas fa-star"></i> الطاعات وأعمال الخير</h3>
                    {getDayDetails(logs[activeBreakdownDate]).posItems.filter(i => modalType === 'full' || i.category.includes('البر') || i.category.includes('إضافية')).map((item, idx) => (
                      <div key={idx} className="flex justify-between items-center bg-emerald-50/30 dark:bg-emerald-800 p-4 rounded-2xl border border-emerald-100/50">
                        <div><span className="text-xs font-bold block">{item.label}</span><span className="text-[9px] text-gray-400">{item.category}</span></div>
                        <span className="text-emerald-600 font-black">+{item.points}</span>
                      </div>
                    ))}
                    {modalType === 'goodDeeds' && getDayDetails(logs[activeBreakdownDate]).posItems.filter(i => i.category.includes('البر') || i.category.includes('إضافية')).length === 0 && (
                      <div className="text-center py-10 text-gray-400 text-xs italic">لم يتم تسجيل أعمال بر لهذا اليوم</div>
                    )}
                  </div>
                )}

                {(modalType === 'full' || modalType === 'mujahada') && (
                  <div className="space-y-3">
                    <h3 className="text-sm font-black text-red-700 flex items-center gap-2"><i className="fas fa-exclamation-circle"></i> الزلات والمجاهدة</h3>
                    {getDayDetails(logs[activeBreakdownDate]).negItems.map((item, idx) => (
                      <div key={idx} className="flex justify-between items-center bg-red-50/30 dark:bg-red-800 p-4 rounded-2xl border border-red-100/50">
                        <div><span className="text-xs font-bold block">{item.label}</span><span className="text-[9px] text-gray-400">{item.category}</span></div>
                        <span className="text-red-600 font-black">{item.points}</span>
                      </div>
                    ))}
                    {modalType === 'mujahada' && getDayDetails(logs[activeBreakdownDate]).negItems.length === 0 && (
                      <div className="text-center py-10 text-emerald-600 text-xs font-black">الحمد لله، يومك خالٍ من الزلات المسجلة</div>
                    )}
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Stats Summary Card */}
      <div className="bg-white dark:bg-[#1a1a1a] border border-gray-200 dark:border-gray-800 rounded-[3rem] p-10 text-center shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-yellow-600"></div>
        <h2 className="text-gray-400 text-[10px] mb-2 font-black tracking-widest uppercase">رصيد الإيمان الكلي</h2>
        <div className="text-8xl font-black gold-gradient mb-6 drop-shadow-xl">{filteredDates.reduce((acc, date) => acc + getDayDetails(logs[date]).netTotal, 0)}</div>
        <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
          <div className="text-[11px] text-yellow-800 bg-yellow-50 px-6 py-2 rounded-full border border-yellow-200 font-black">
            <i className="fas fa-calendar-alt ml-2"></i> {formatArabicDate(startDate)} - {formatArabicDate(endDate)}
          </div>
          <button onClick={handlePrint} className="text-[11px] bg-slate-800 text-white px-6 py-2 rounded-full hover:bg-slate-700 transition-all flex items-center gap-2 print:hidden shadow-lg">
            <i className="fas fa-file-pdf"></i> مشاركة التقرير كـ PDF
          </button>
        </div>
      </div>

      {/* Filter Tools */}
      <div className="bg-white dark:bg-[#151515] p-6 rounded-[2.5rem] border border-gray-100 dark:border-gray-800 shadow-lg flex flex-col md:flex-row gap-6 items-center print:hidden">
        <div className="grid grid-cols-2 gap-4 w-full">
          <div className="flex flex-col">
            <label className="text-[10px] font-black text-gray-400 mb-1 pr-1">من تاريخ</label>
